INSERT INTO `dr_1_anlizhongxin` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `alxqydbzbzt`, `alxqydbsbmc`, `alxqydbfwxm`, `alxqydbkhhp`, `alxqydbskyhq`, `alxqyzbsgsp`, `alxqyzbsgspfm`, `alxqyzbsgxc`, `allbyzbxhybzt`, `allbyzbxhybfbt`, `baldycp`, `anlixianshi`, `sfszbxm`) VALUES
(274, 11, '湖北高速上线豫工除雪滚        ', '873', '除雪滚,豫工除雪滚', '冬季来临，湖北鄂州某标段市政高速公路因除雪需要，计划采购雪滚设备，经同一高速公路相邻标段负责人推荐，咨询豫工除雪滚刷。给客户推荐豫工雪滚的李总，跟客户承包同一高速公路的不同标段，2022年10月采购豫工马路吹扫机，根据工人反馈，设备风量大、吹扫效率高。因为设备性价比高，2022年12月李总又陆续批量采购豫工融雪撒布机、雪滚、雪铲设备，清雪除雪设备一站式配齐。去年高速公路大雪，李总承包的标段清雪除雪', 1, 1, '创始人', 9, '/show-274.html', 0, 0, '39.96.59.7-50280', 1709283689, 1714200477, 0, '1456', '除雪滚', '湖北鄂州某标段市政高速公路除雪项目', '这两台扫雪滚，让今年高速除雪工期缩短不少！', '3000', '1457', '1458', '', '1455', '除雪滚', '103', NULL, NULL),
(275, 11, '豫工除雪滚圆满交付新疆高速除雪项目', '1001', '除雪滚,除雪滚刷', '2023年10月中旬，客户咨询豫工除雪滚，因为采购数量大，客户同时咨询并现场考察了多个雪滚厂家。经过近1个月的综合对比，豫工雪滚以超高的性价比赢得客户信赖，并最终达成采购合同！客户此次共采购除雪设备14台，其中包括3米液压雪滚8台，3.5米自带动力除雪滚一台，3米自带动力除雪滚3台，3米轻型雪铲1台，10立方融雪剂撒布机1台。', 1, 1, '创始人', 9, '/show-275.html', 0, 0, '39.96.59.7-50288', 1709283690, 1769740990, 0, '1243', '豫工除雪滚刷', '新疆高速除雪', '售后专业负责，选择豫工很放心！', '3000', '1245', '1246', '', '1259', '除雪滚', '103', '2', '2'),
(276, 11, '15台除雪滚刷亮剑黑龙江高速除雪', '878', '除雪滚,除雪滚刷,豫工除雪滚', '为落实高速公路除雪保通工作部署，黑龙江高速计划采购一批除雪设备，2023年10月，负责人宋总咨询豫工除雪滚，客户同时咨询了多个厂家。11月6日，宋总与项目技术员来豫工工厂考察，在了解了工厂的生产规模、设备的性能指标，售后的技术支持后，与豫工机械签订采购合同！本次合作，客户共采购15台除雪设备，除了原定的10台3.5米除雪滚，又追加4台雪铲，1台液压融雪撒布机。', 1, 1, '创始人', 9, '/show-276.html', 0, 0, '39.96.59.7-50296', 1709283690, 1769741016, 0, '1398', '除雪滚', '黑龙江高速公路除雪保通', '该款设备可以根据路况进行匹配定制，不挑车型，保护路面，除雪效率高，彻底干净', '2000', '1399', '1400', '', '1401', '除雪滚', '103', '2', '2'),
(277, 17, '价值18万隧道物资圆满交付，豫工机械获中铁十二局点赞', '877', '小导管缩尖机,小导管冲孔机', '中铁十二局深江铁路项目计划采购一批隧道物资。9月27日，负责人谭总咨询豫工小导管缩尖、冲孔设备，对比设备性能指标，了解工厂生产实力，审核公司经营资质。客户同时咨询了另外三个厂家，经过半个月的综合对比，最终选择豫工机械作为其设备供应商。10月16日，客户谭总与豫工签订合同！在定购小导管缩尖机、小导管冲孔机的同时，加购数控弯箍机、自动滚丝机、压弯机设备！', 1, 1, '创始人', 9, '/show-277.html', 0, 0, '39.96.59.7-50304', 1709283690, 1769756065, 0, '1449', '隧道钢筋支护设备', '中铁十二局深江铁路项目', '设备劲大，效率高，完美地帮工人解放双手！', '3000', '1450', '1451', '', '1452', '小导管缩尖机', '133', '2', '2'),
(278, 11, '水电七局点赞豫工除雪滚        ', '876', '除雪滚,除雪滚刷', '冬季来临，中国水利水电第七工程局因工程需要，计划采购除雪滚刷，用于水电站地面冬季积雪清除。为了选到高品质的设备，项目方综合对比了多个厂家！经过1个月的综合对比，客户最终选择豫工作为供货方，是对产品经理专业服务和工厂生产实力的认可。为了提高清扫效率，客户选择豫工自带动力系列除雪滚刷，并选用工作宽度3米的机型，用以匹配项目工地的装载机。冬季来临，为应对冬季除雪设备的大量需求，豫工机械工厂未雨绸缪，提前', 1, 1, '创始人', 9, '/show-278.html', 0, 0, '39.96.59.7-50312', 1709283690, 1714200472, 0, '1453', '除雪滚刷', '水电站地面冬季积雪清除', '尼龙钢丝混合刷片，除雪效率高，清雪速度20km/h', '2000', '1454', '', '', '1455', '除雪滚', '103', NULL, NULL),
(279, 17, '34万隧道物资圆满交付，豫工机械获中铁六局点赞        ', '1349', '隧道物资,豫工钢筋设备', '四川客户承接中铁六局康新高速钢结构加工项目，按照甲方（中铁六局项目部）要求，批量采购一批隧道物资设备，共计六款7台。为了买到符合要求的设备，也为了节约成本，客户走访对比了多个生产厂家。产品经理结合客户钢筋加工尺寸、钢板切割厚度、工期进度，制定了合理的设备采购方案：300型数控型钢冷弯机、数控龙门等离子切割机、50型小导管缩尖机、50型数控小导管双头割孔机、220型全自动网片排焊接生产线等', 1, 1, '创始人', 9, '/show-279.html', 0, 0, '39.96.59.7-50320', 1709283691, 1769756177, 0, '1342', '50型数控小导管双头割孔机、220型全自动网片排焊接生产线', '中铁六局康新高速钢结构加工项目', '感谢豫工对我们的全力支持，下次定设备，还要找他们！', '3000', '1343', '1344', '[\"1345\",\"1346\",\"1347\"]', '1348', '钢筋网片排焊机', '131', '2', '2'),
(280, 18, '豫工混凝土输送泵助力一带一路建设               ', '1335', '液压湿喷机,工字钢弯拱机', '客户负责中泰高铁——超前支护工程项目。2021年9月，客户首次咨询豫工液压湿喷机，工字钢弯拱机等设备，同时咨询了河南、湖南至少5个生产厂家。2021年12月5日，客户到访公司总部——郑州运营中心，并考察了豫工机械隧道支护设备生产基地。客户看到豫工门类齐全的设备生产线，庞大的仓库备货，完全满足其隧道物资一站式采购的需求，非常满意，从而达成合作意向！', 1, 1, '创始人', 9, '/show-280.html', 0, 0, '39.96.59.7-50328', 1709283691, 1770365635, 0, '1336', '混凝土输送泵', '中泰高铁——超前支护工程项目', '检修之后，设备比之前更好用了！感谢豫工，免除了我的后顾之忧！', '3000', '1337', '3330', '[\"1339\",\"1338\",\"1340\"]', '1341', '混凝土输送泵', '128', '2', '2'),
(281, 17, '飞机售后，豫工湿喷机助力厦门地铁抢工期               ', '1247', '液压湿喷机,混凝土喷浆支护', '豫工故事客户谭总长期从事混凝土护坡支护项目，一直租赁混凝土湿喷机施工，却因为设备陈旧，遭遇上水慢、压力低、流量小......等问题的困扰。2023年2月，客户咨询豫工液压湿喷机，因为工程量小，最终还是选择租赁设备施工。然而，合作虽然未成，沟通从未间断！豫工产品经理的专业过硬，服务耐心，给客户留下深刻的印象，赢得客户的信任。', 1, 1, '创始人', 9, '/show-281.html', 0, 0, '39.96.59.7-50338', 1709283691, 1769755302, 0, '1248', '液压湿喷机', '液压湿喷机地铁支护', '售后专业 反应迅速！', '2000', '1249', '1250', '', '1260', '液压湿喷机', '134', '2', '2'),
(282, 11, '夏邑住建局点赞豫工永磁防汛泵车               ', '1355', '防汛泵车,永磁防汛泵车', '5月20日，河南夏邑住建局计划采购防汛泵车，根据客户对设备流量和性能的要求，产品经理推荐300方、500方、1000方永磁防汛泵车。作为政府采购项目，客户对质量、细节要求严格，咨询多个厂家后，选定包括豫工在内的三个厂家，提交设备方案，做最后对比。产品经理提交的方案中，充分体现了豫工人对细节的追求，不仅对永磁防汛泵的结构做客观展示，对核心部件如发电机组品牌、永磁泵国家级检测认证、关键配件配置也一 一', 1, 1, '创始人', 9, '/show-282.html', 0, 0, '39.96.59.7-50348', 1709283692, 1760665958, 0, '1356', '永磁防汛泵车', '河南夏邑住建局防汛泵车采购', '设备出水口水量足，流量大！操作也简单，真的是设备好，服务棒', '2000', '1358', '1359', '', '1361', '永磁防汛泵', '136', '2', '2'),
(284, 11, '豫工除雪滚大批量登录湖北高速               ', '995', '', '冬季来临，湖北鄂州某标段市政高速公路因除雪需要，计划采购雪滚设备，经同一高速公路相邻标段负责人推荐，咨询豫工除雪滚刷。给客户推荐豫工雪滚的李总，跟客户承包同一高速公路的不同标段，2022年10月采购豫工马路吹扫机，根据工人反馈，设备风量大、吹扫效率高。因为设备性价比高，2022年12月李总又陆续批量采购豫工融雪撒布机、雪滚、雪铲设备，清雪除雪设备一站式配齐。去年高速公路大雪，李总承包的标段清雪除雪', 1, 1, '创始人', 9, '/show-284.html', 0, 0, '39.96.59.7-50444', 1709283731, 1743385772, 0, '1362', '除雪滚', '湖北鄂州某标段市政高速公路除雪', '有了这两台扫雪滚，今年的高速道路除雪工期可以缩短不少！', '2000元', '1363', '1364', '', '1365', '除雪滚', '103', '2', '2'),
(285, 11, '水电七局点赞豫工除雪滚清扫效率高               ', '992', '除雪滚,冬季除雪滚刷', '冬季来临，中国水利水电第七工程局因工程需要，计划采购除雪滚刷，用于水电站地面冬季积雪清除。为了选到高品质的设备，项目方综合对比了多个厂家！经过1个月的综合对比，客户最终选择豫工作为供货方，是对产品经理专业服务和工厂生产实力的认可。为了提高清扫效率，客户选择豫工自带动力系列除雪滚刷，并选用工作宽度3米的机型，用以匹配项目工地的装载机。冬季来临，为应对冬季除雪设备的大量需求，豫工机械工厂未雨绸缪，提前', 1, 1, '创始人', 9, '/show-285.html', 0, 0, '39.96.59.7-50452', 1709283732, 1743385821, 0, '1370', '除雪滚', '水电站地面冬季积雪清除', '订购前，考察了多个厂家，综合对比后，还是觉得豫工的雪滚性价比更高', '2000', '1372', '1373', '[\"1374\",\"1376\"]', '1377', '除雪滚', '103', '2', '2'),
(286, 15, '豫工钢筋网片排焊机助力雄安新区建设               ', '993', '钢筋网片排焊机,半自动气动钢筋网片排焊机', '客户好评必须为豫工的专业服务点赞，提供的施工方案，实用性强，施工成本低，真是省心、省力、省钱！据现场工人反馈，此次购买的全气动钢筋网片焊机不仅焊点牢固，自动落料，焊接速度快，而且定位精准，网格尺寸标准。另外，设备在运行过程中没有出现任何故障，减少了维修时间和费用，这对提高生产效率，保证工期至关重要。案例现场', 1, 1, '创始人', 9, '/show-286.html', 0, 0, '39.96.59.7-50462', 1709283732, 1714202787, 0, '1303', '钢筋网片排焊机', '批量的建筑用钢筋网片焊接', '全气动钢筋网片焊机不仅焊点牢固，自动落料，焊接速度快，而且定位精准，网格尺寸标准。', '2000', '1304', '1305', '', '1263', '钢筋网片排焊机', '130', NULL, NULL),
(287, 14, '6万平边坡绿化，喷播机租还是买？               ', '994', '', '客户好评因为朋友三年前订购豫工的30型筛土机，设备一直运转良好，对豫工品牌比较认可！他一直在微信朋友圈关注豫工的发展动态，了解到近几年，豫工喷播机一直在出货。特意向我推荐，现在看来，施工效果确实不错，与产品经理介绍的效果差不多，完全满足施工需求，选择豫工，就是放心。施工现场', 1, 1, '创始人', 9, '/show-287.html', 0, 0, '39.96.59.7-50470', 1709283732, 1714202770, 0, '1306', '6方液力喷播机', '土质边坡绿化项目，施工面积6万平，绿化山坡高度30米', '施工效果确实不错，与产品经理介绍的效果差不多，完全满足施工需求，选择豫工，就是放心！', '2000', '1307', '1308', '', '1261', '液压喷播机', '150', NULL, NULL),
(288, 14, '一位豫工售后20天的工作日记               ', '991', '喷播机,泥沙分离器', '10月面对疫情压力，豫工人迎难而上，捷报频传，业绩一路飘红。  然而，成交只是开始，服务永无止境！10月10日，为解决因疫情售后人员出行不便的问题，公司特发起服务动员令，从无疫情地区的本部工厂一线，抽调8位技术工程师，组建应急技术服务小组，代替售后部门职能，赴各地客户工地，提供技术服务。  我们截取了一名工程师20天（10.10-11.1）的工作日志，来记录这次意义非凡的行动。下面跟随王工的脚步，', 1, 1, '创始人', 9, '/show-288.html', 0, 0, '39.96.59.7-50478', 1709283733, 1714200727, 0, '1378', '88kw液力喷播机', '国道边防工程绿化项目', '始终把售后服务与产品质量，置于战略性地位，为广大客户提供专业及时的售后服务', '2000', '1379', '1380', '[\"1381\",\"1382\",\"1383\"]', '1384', '客土喷播机', '150', NULL, NULL),
(289, 15, '浙江台州破桩机房建桩破除               ', '1385', '破桩机,液压破桩机', '客户好评客户为豫工破桩机的工作效率点赞，是人工的数十倍！客户对调整模块数量的工作专业度表示高度认可，感谢豫工售后服务团队的热情服务和耐心指导。图片展示', 1, 1, '创始人', 9, '/show-289.html', 0, 0, '39.96.59.7-50512', 1709283742, 1714202657, 0, '1386', '液压破桩机', '浙江台州市火车站房建工程项目', '破桩速度快，是人工的数十倍！', '3000', '1389', '1390', '[\"1396\",\"1395\",\"1397\"]', '1394', '液压破桩机', '122', NULL, NULL),
(290, 12, '雄安高铁站负一层环氧树脂涂装前打毛               ', '1264', '', '客户评价听朋友介绍，才开始了解豫工的抛丸机，工期紧，仓促下单，没想到效率、速度都这么棒！按照这个速度， 4天即可保质保量完工，不错！图片展示', 1, 1, '创始人', 9, '/show-290.html', 0, 0, '39.96.59.7-50520', 1709283743, 1714200423, 0, '1265', '路面抛丸机', '高铁站环氧树脂涂装前打毛', '工期紧，仓促下单，没想到效率、速度都这么棒！', '1000', '1266', '1276', '', '1267', '路面抛丸机打毛混凝土地面', '156', NULL, NULL),
(291, 15, '豫工破桩机 2.3米大桩高效破拆', '1402', '破桩机,液压破桩机', '客户好评破桩过程中，赶上中铁大桥局领导视察现场！在全程观看破桩机施工后，将苏工找到身边，交流破桩心得！领导表示：项目上，曾经使用过其他厂家的破桩机，因为速度、效率、破桩程度不太理想，目前已不再使用。现在这款设备破桩效果，与之前相比，效果不错。“在同一场地，同等地质条件下，豫工破桩机比之前那款相比，破桩速度更快，效率更高！”另一负责施工的领导介绍说。', 1, 1, '创始人', 9, '/show-291.html', 0, 0, '39.96.59.7-50528', 1709283743, 1769740715, 0, '1403', '液压破桩机', '中铁大桥局 黄河大桥建造工程', '在同一场地，同等地质条件下，豫工破桩机比之前那款相比，破桩速度更快，效率更高', '3000', '1404', '1405', '[\"1407\",\"1406\",\"1408\"]', '1394', '液压破桩机', '122', '2', '2'),
(292, 12, '豫工550型抛丸机设备3年0故障               ', '1270', '路面抛丸机,混凝土打毛抛丸机', '客户评价因为之前的合作，一直在朋友圈关注豫工的发展动态，了解到客户对于抛丸机使用反馈一直很好，此次工地需要该设备，就直接下单了，现在看来，施工效果果然不错，完全满足防水施工需求，选择豫工，就是放心。施工现场展示     河南豫工机械是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。', 1, 1, '创始人', 9, '/show-292.html', 0, 0, '39.96.59.7-50536', 1709283743, 1769741077, 0, '1275', '路面抛丸机', '车库顶板防水打毛', '施工效果果然不错，完全满足防水施工需求，选择豫工，就是放心。', '800', '1273', '1274', '', '1262', '路面抛丸机', '156', '2', '2'),
(293, 17, '豫工液压湿喷机助力中铁18局地铁站建设               ', '1417', '液压湿喷机,混凝土湿喷机', '客户好评客户盛赞豫工液压湿喷机湿喷效果杠杠滴，现场操作工人说：这设备陡起（徐州方言：太厉害的意思），很好！到目前为止，没有听到工人反馈任何故障问题，这也减少了维修时间和费用，提高了生产效率。', 1, 1, '创始人', 9, '/show-293.html', 0, 0, '39.96.59.7-50544', 1709283744, 1773890140, 0, '1418', '液压湿喷机', '徐州奥体中心地铁站项目', '这设备陡起（徐州方言：太厉害的意思），很好！', '2000', '1419', '1420', '[\"1421\",\"1422\",\"1423\"]', '1424', '液压湿喷机', '134', '1', '2'),
(294, 17, '豫工湿喷台车助力中铁隧道局开工大吉!               ', '1409', '湿喷台车,湿喷机械手', '2022年3月31日，在豫工机械生产车间，两台3017型湿喷台车完成最后的装配，成功下线，通过严格功能检测，即将发车！', 1, 1, '创始人', 9, '/show-294.html', 0, 0, '39.96.59.7-50556', 1709283744, 1714202580, 0, '1410', '液压湿喷台车', '宜兴铁路ZQ-3标隧道喷浆支护项目', '下次再上一台', '3000', '1411', '1412', '[\"1414\",\"1413\",\"1415\"]', '1416', '湿喷台车', '134', NULL, NULL),
(295, 17, '中建五局点赞豫工液压湿喷机               ', '990', '', '客户好评喷浆速度很快，操作很简单！这是设备给我最大的印象！感谢技术人员的辛勤付出，很专业也很有责任心，总是耐心指导工人操作步骤，听工人说他们现在可以熟练掌握设备的安装、拆卸、操作、保养步骤。选择豫工，我很放心。施工现场', 1, 1, '创始人', 9, '/show-295.html', 0, 0, '39.96.59.7-50566', 1709283744, 1714202705, 0, '1331', '90型单喷头液压湿喷机', '基坑支护，总施工面积100000平', '喷浆速度很快，操作很简单！', '3000', '1332', '1333', '', '1334', '液压湿喷机', '134', NULL, NULL),
(296, 12, '张家口中泰城车库顶板防水前打毛               ', '1288', '路面抛丸机,非固化喷涂机', '客户好评结束客户服务第5天，张工电话回访客户设备使用情况。客户表示：喷涂机效率挺高，溶胶速度也可以，工人用起来很顺手。因抛丸机退换货拉下的工期有望补回来，项目不出意外，可以如期完工，交付甲方。图片展示', 1, 1, '创始人', 9, '/show-296.html', 0, 0, '39.96.59.7-50574', 1709283745, 1714202827, 0, '1293', '路面抛丸机 非固化喷涂机', '张家口车库顶板防水工程', '喷涂机效率挺高，溶胶速度也可以，工人用起来很顺手。', '1200', '1294', '1295', '', '1296', '非固化喷涂机', '155', NULL, NULL),
(297, 12, '中国二冶中学建设项目防水施工               ', '1283', '非固化喷涂机,非固化防水喷涂机', '客户好评豫工非固化喷涂机太棒了！与租用的设备相比，综合施工效率提高了4-5倍，非常好！今年天已经冷了，明年开春再来，继续购买。图片展示', 1, 1, '创始人', 9, '/show-297.html', 0, 0, '39.96.59.7-50582', 1709283745, 1715333505, 0, '1284', '非固化喷涂机', '楼顶防水喷涂项目', '非固化喷涂机太棒了！与租用的设备相比，综合施工效率提高了4-5倍，非常好！', '800元', '1285', '1286', '', '1287', '非固化喷涂机', '155', NULL, NULL),
(298, 12, '驻马店某别墅车库顶板防水处理               ', '1282', '路面抛丸机,非固化喷涂机', '客户好评客户表示:总包对防水效果的认可，让我对豫工设备很放心。购买成套设备，售后很方便，听工人反馈设备很好用，操作简单、维护方便，让我很省心。天气炎热，工人室外作业很辛苦，设备高效作业，大大减轻工人的工作量，工作效率提高了，这对如期完工很重要！图片展示', 1, 1, '创始人', 9, '/show-298.html', 0, 0, '39.96.59.7-50590', 1709283745, 1714200337, 0, '1281', '路面抛丸机 非固化喷涂机', '地下车库顶板防水项目', '设备很好用，操作简单、维护方便，让我很省心。', '1000', '1277', '1279', '', '1280', '路面抛丸机', '156', NULL, NULL),
(299, 12, '西安兴平食品工业钢板除锈               ', '1433', '路面抛丸机,钢板除锈抛丸机', '客户评价钢板除锈施工，第一次用磨光机，有粉尘，环保局不通过，改用湿喷机，排出的污水污染下水道，村委会不让用，后选择豫工路面抛丸机，无尘环保，客户满意，甲方点赞图片展示', 1, 1, '创始人', 9, '/show-299.html', 0, 0, '39.96.59.7-50624', 1709283752, 1714202499, 0, '1434', '路面抛丸机', '路面抛丸机钢板除锈施工', '选择豫工路面抛丸机钢板除锈，无尘环保，客户满意。', '900', '1435', '1436', '', '1432', '路面抛丸机', '156', NULL, NULL),
(300, 12, '路面抛丸机助力空军某部队军用机场打毛项目', '1425', '路面抛丸机,550型路面抛丸机', '客户好评部队领导对豫工550型路面抛丸机施工效果很满意，并称赞豫工机械贴心的售后服务远超预期！', 1, 1, '创始人', 9, '/show-300.html', 0, 0, '39.96.59.7-50632', 1709283752, 1769741036, 0, '1426', '路面抛丸机', '军用机场道路施工', '效果很满意，售后服务远超预期！', '1000', '1430', '1431', '', '1432', '路面抛丸机', '156', '2', '2'),
(301, 12, '长春碧桂园地下车库顶板防水施工               ', '1297', '地下车库顶板防水施工,非固化喷涂机', '客户好评在结束服务第五天，乔工回访客户设备施工情况，对方表示：防水施工速度和防水施工效果，项目部都非常满意，已成功签订合同，明年5月份开工，完成9万平地下车库顶板防水施工。图片展示', 1, 1, '创始人', 9, '/show-301.html', 0, 0, '39.96.59.7-50640', 1709283752, 1714202807, 0, '1298', '非固化喷涂机', '地下车库顶板防水施工 ', '防水施工速度和防水施工效果，项目部都非常满意，已成功签订合同', '800', '1299', '1300', '', '1302', '非固化喷涂机', '155', NULL, NULL),
(302, 15, '山西重点建设项目祁离高速破桩               ', '1444', '破桩机,液压破桩机', '客户评价破桩之前，客户反复强调完好保留桥梁桩竖向钢筋。试机结果完美达成客户要求。豫工破桩机被客户称为“破除桥梁桩专用神器”。客户表示：豫工破桩机截桩不留芯，避免二次人工处理，大大减少破桩工程人工投入，为确保工期意义重大！图片展示', 1, 1, '创始人', 9, '/show-302.html', 0, 0, '39.96.59.7-50648', 1709283753, 1714202242, 0, '1444', '液压破桩机', '祁离高速建设项目', '破除桥梁桩专用神器，对工期意义重大！', '3000', '1445', '1447', '', '1394', '液压破桩机', '122', NULL, NULL),
(303, 12, '保定市政工程混凝土地面打毛               ', '1437', '路面抛丸机,混凝土路面抛丸机', '客户反馈客户刘先生高度称赞营销顾问的专业推荐，对调试路面抛丸机配发的切丸非常满意，效果明显，完全满足施工要求。非常认可豫工550型路面抛丸机，不仅工作效率满足要求，而且操作简便，在毛工的耐心指导下，工人虽年过六旬，但上手很快，完全不影响施工进度。图片展示', 1, 1, '创始人', 9, '/show-303.html', 0, 0, '39.96.59.7-50656', 1709283753, 1714202440, 0, '1440', '路面抛丸机', '市政水泥道路抛丸工程', '抛丸机配效果明显，完全满足施工要求', '900', '1441', '1442', '', '1432', '路面抛丸机', '156', NULL, NULL),
(309, 14, '客户点赞豫工390型客土喷播机', '1310', '客土喷播机,高速公路边坡绿化', '客户来自河北邯郸，8月承接到高速公路边坡绿化项目，工程面积50000平方，坡高60米，坡度大约45°，中级三级边坡。客户知道自己的工程需要大功率的客土喷播机，对设备性能要求高，为此，客户实地考察了多个喷播机厂家。2022年8月26日，客户与技术人员来我厂考察，现代化的生产车间、庞大的研发团队、种类齐全的系列设备，让客户对豫工的生产实力很放心！车间主任详细介绍了客土喷播机的性能特点和设备配置。客户综', 1, 2, '豫工机械', 9, '/show-309.html', 0, 0, '123.52.20.170-45553', 1712030618, 1782979406, 0, '1315', '390型客土喷播机', '高速公路边坡绿化项目，工程面积50000平方，坡高60米，坡度大约45°', '动力足，直喷高度轻松达到50-60米。', '3000元', '1316', '1317', '', '1318', '390型客土喷播机', '150', '2', '2'),
(310, 14, '砂石分离机助力焦平高速环保施工', '1319', '洗石机生产线,混凝土砂石分离', '河南省公路工程局，负责焦作至平顶山高速公路焦作至荥阳段项目建设，2023年2月，客户第一次咨询砂石分离机，用于处理水泥罐车清洗出来的混凝土。客户待处理的混凝土中含有0-5mm 和1-3mm的青石子,按照项目要求，设备需要达到每小时7到8方的处理量，为了选到质优价廉的设备，客户咨询多个厂家，并筛选出三个优质厂家，进行三方报价。经过半个月的综合对比，3月1日，客户到访豫工机械环保设备生产基地，强大的生', 1, 2, '豫工机械', 9, '/show-310.html', 0, 0, '123.52.20.170-55234', 1712039056, 1714202729, 0, '1325', '砂石分离机', '水泥罐车清洗出来的混凝土净化分离', '快速分离，操作简单，便于清理的特点，是搅拌站理想的环保节能产品。', '3000', '1328', '1329', '', '1330', '砂石分离机', '145', NULL, NULL),
