(317, 18, '豫工混凝土输送泵助力郑州医疗产业园建设', '1513', '混凝土输送泵,地泵', '郑州医疗产业园建设，豫工混凝土输送泵大显神威，专业售后团队现场调试试机，获得一片好评。', 1, 2, '豫工机械', 9, '/show-317.html', 0, 0, '123.52.21.159-17406', 1713428767, 1770365660, 0, '1512', '混凝土输送泵', '郑州医疗产业园建设混凝土输送', '输送骨料大，不堵管，连续性好 输送量大 运行平稳 故障率低。', '2000', '1531', '1512', '', '', '', '128', '2', '2'),
