INSERT INTO `dr_1_chanpinzhongxin` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `cpxqydblbtsp`, `cpxqydblbtspfm`, `cpxqydblbt`, `cpxqydbcs1`, `cpxqydbcs2`, `cpxqydbcs3`, `cpxqydbxjskq`, `cpxqyzbsyfw`, `cpxqyzbjgys`, `cpxqyzbsbcs`, `cpxqyzbbfyhxc`, `cplbycpzyslt`, `cpzxjhm`, `allbyzbyctmbjtp`, `syrmcpjhm`) VALUES
(103, 19, '除雪滚刷', '356', '除雪滚,除雪滚刷', '除雪滚刷转速高、扭矩大、清雪效果好，清扫洁净度高，可广泛应用于公路、城市道路、机场及高速公路的积雪、沙石等清扫工作。', 1, 1, '创始人', 9, '/show-103.html', 0, 0, '127.0.0.1-61877', 1706924380, 1773192161, 0, '195', '196', '[\"197\",\"198\",\"199\",\"201\"]', '除雪宽度：2米-3.5米', '左右调节：±30°', '最大速度：5-30km/h', '2000', '', '', '', '[\"202\",\"203\",\"205\",\"204\"]', '302', '2', '1466', '2'),
(111, 26, '工程用空压机', '1205', '户外大型基坑边坡支护空压机,混凝土喷浆空压机', '工地移动式工程用螺杆空压机，功率75千瓦，排气量13立方，大型喷锚空气压缩机，空压机本身自带缓冲罐，直接连接用气设备，两个出气口，用于建筑工地喷浆护坡喷锚、修路钻机凿岩凿孔等。', 1, 1, '创始人', 9, '/show-111.html', 0, 0, '127.0.0.1-62240', 1706924916, 1773192236, 0, '1198', '1199', '[\"1200\",\"1201\",\"1202\",\"1203\",\"1204\"]', '排气量 13立方', '功率 75kw', '气桶容量 300L', '500', '&lt;p&gt;&lt;span style=&quot;font-family: Arial, Helvetica, sans-serif; font-size: 16px; background-color: rgb(255, 255, 255);&quot;&gt;豫工机械为您提供多种型号基坑、边坡支护空压机，户外工地混凝土喷浆空压机我们建议使用75千瓦13立方螺杆空压机，如果是配套湿喷机，我们则建议使用大一些的16立方空压机，四轮移动式带牵引，另外还有固定式、柴油动力供您选择。&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255);&quot;&gt;（1）显示功能：具有汉字液晶显示屏、系统排气压力、排气温度、用汉字显示屏显示、非正常因素一旦出现，中文提示维护或检修。&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255);&quot;&gt;（2）报警功能：排气压力过高、排气温度过高、润滑油压力过低、自动报警。&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255);&quot;&gt;（3）保护功能：排气压力过高、排气温度过高、润滑油压力过低、主电机过载、风扇电机过载、自动报警停机、三相电源的任意一相或二相断开，自动切断电源、三相电源的相序有误时，不能启动。&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255);&quot;&gt;（4）控制功能：压缩机启动、停机、自动加载、卸载、手动加载、卸载、紧急停机、空久停机、由微电脑自动控制。&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255);&quot;&gt;（5）设置功能：启动时间、卸载压力值、排气压力过高、排气温度过高、润滑油压力过低、空久停机时间、可以自己设置。&lt;/p&gt;', '&lt;p&gt;&lt;span style=&quot;font-family: Arial, Helvetica, sans-serif; font-size: 16px; background-color: rgb(255, 255, 255);&quot;&gt;型号：QFY-75G，驱动方式：直联，电机功率：75千瓦，排气量：13立方每分钟，工作压力：8-13公斤，外形尺寸：2850*1460*1870，重量：1800公斤，四轮移动带牵引，内部自带缓冲罐，配套两个出气口，喷浆机配套边坡支护、喷浆喷锚杆用螺杆空压机。&lt;/span&gt;&lt;span style=&quot;font-family: Arial, Helvetica, sans-serif; font-size: 16px; background-color: rgb(255, 255, 255);&quot;&gt;&lt;/span&gt;&lt;/p&gt;', '[\"1193\",\"1194\",\"1195\",\"1196\"]', '1206', '1', '1600', '2'),
(112, 26, '护栏打桩机', '1207', '高速公路装载式波形护栏打桩机,小型液压打拨钻一体机', '', 1, 1, '创始人', 9, '/show-112.html', 0, 0, '127.0.0.1-62769', 1706925180, 1713518676, 0, '1189', '1190', '[\"1185\",\"1184\",\"1186\",\"1187\",\"1188\"]', '动力头功率 55KW', '打桩高度 2900mm/3100mm', '钻孔深度 2200mm', '2000', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/owfmodUaS93lre8o_JHoAhAE0HE.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/oNWoHI2Y8XJNzPHpTQngqBADRpo.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/RTYS5QDfES48k_cnzL8A5xAGskI.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/j_b2RRC8XYowhdC-C7REMhAGLRw.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/M63Pavsq8wdKi8Ox4An3vxACwFg.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/MBwes3UIP61hDg4AXpO_QhAB_PA.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/xEyiJ-rOMRJNye_8RrEh8xACHyw.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;', '[\"1180\",\"1181\",\"1182\",\"1183\"]', '1208', '2', '1605', '2'),
(113, 26, '光伏打桩机', '1209', '电动光伏打桩机,液压地基凿岩钻机', '', 1, 1, '创始人', 9, '/show-113.html', 0, 0, '127.0.0.1-62778', 1706925203, 1713518661, 0, '1175', '1162', '[\"1163\",\"1165\",\"1164\",\"1166\",\"1168\"]', '钻孔深度 6m', '一次推进行程 3-8米', '钻孔直径 0-300mm', '3000', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/4DOBwFcByoZ0CL0tkfN9lhASwCc.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/UV72N8LeUKNBXL8cfAPDuhADNOk.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/gJOqeBuQnWDca_EPxAERHBAceTQ.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/TbxVuMBtAK0i3ZRbBXk3YhAal18.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/C8jUNhjPSXnesOYidNsEIBAWiSg.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '[\"1170\",\"1171\",\"1173\",\"1174\"]', '1210', '2', '1604', '2'),
(114, 26, '非开挖定向钻', '1211', '微型定向钻机厂家,坑道式定向钻,非开挖钻机', '非开挖定向钻机是在不开挖地表面的条件下，铺设多种地下公用设施(管道、电缆等)的一种施工机械，它应用于供水、电力、电讯、天然气、煤气、石油等管线铺设施工中，它适用于沙土、粘土、卵石等地况，我国大部分非硬岩地区都可施工。工作环境温度为-15C~+45C。水平定向钻进技术是将石油工业的定向钻进技术和传统的管线施工结合在一起的一项施工新技术，它具有施工速度快、施工精度高、成本低等优点。', 1, 1, '创始人', 9, '/show-114.html', 0, 0, '127.0.0.1-62769', 1706925229, 1770600159, 0, '1146', '1153', '[\"1149\",\"1148\",\"1150\",\"1151\",\"1152\"]', '钻孔直径 600', '可配钻杆类型 2m', '规格 直径50mm', '3000', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://cbu01.alicdn.com/img/ibank/O1CN01zF9Bs02I8QsYBDjOS_!!2213362829241-0-cib.jpg?__r__=1683104554777&quot; width=&quot;750&quot; height=&quot;876&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;豫工非开挖定向钻机&quot; alt=&quot;豫工非开挖定向钻机&quot;/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工非开挖定向钻机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;非开挖定向钻机是一种采用非开挖方式的管道施工工艺，广泛应用于石油、天然气输送及市政管道建设等领域。 ‌&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;主要用途&lt;/strong&gt;‌：用于穿越公路、铁路、河流、湖泊、建筑物等障碍物铺设长距离的石油和通信线路管道。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;适用管径&lt;/strong&gt;‌：一般适用于管径为50mm至800mm的管线。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;管材类型&lt;/strong&gt;‌：可适应钢管、PE管等多种管材。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;地质条件&lt;/strong&gt;‌：适应一般岩石层、土层等复杂地质条件。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;施工优势&lt;/strong&gt;‌：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;不破坏地表结构，不会阻碍交通、破坏绿地植被或影响居民正常生活。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;施工精度高，易于调整敷设方向和埋深，可绕过地下障碍物。 ‌&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;施工速度快，占地少，工程成本低。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;施工不受季节限制，安全可靠。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械作为郑州机械厂家，其非开挖水平定向钻机具有操作力小、移动灵活简便等特点，适用于穿越工程等场景。 ‌&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://cbu01.alicdn.com/img/ibank/O1CN01i2Liow2I8Qsd9pSNB_!!2213362829241-0-cib.jpg?__r__=1683104554777&quot; width=&quot;750&quot; height=&quot;801&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;豫工非开挖定向钻机产品优势&quot; alt=&quot;豫工非开挖定向钻机产品优势&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://cbu01.alicdn.com/img/ibank/O1CN01J3RnSm2I8Qsd9sTUw_!!2213362829241-0-cib.jpg?__r__=1683104554777&quot; width=&quot;750&quot; height=&quot;657&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;豫工非开挖定向钻机产品细节展示&quot; alt=&quot;豫工非开挖定向钻机产品细节展示&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工非开挖定向钻机产品细节展示。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770599469724abf.jpg&quot; width=&quot;750&quot; height=&quot;911&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;非开挖钻机产品参数&quot; alt=&quot;非开挖钻机产品参数&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工非开挖定向钻机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;钻机重量&amp;nbsp; &amp;nbsp; 2.7吨，钻机长度&amp;nbsp; &amp;nbsp; 3.5米，入射角&amp;nbsp; &amp;nbsp; 10-22度，钻头直径&amp;nbsp; &amp;nbsp; 100-300MM，最大拉回功率&amp;nbsp; &amp;nbsp; 160KN，最大推动功率&amp;nbsp; &amp;nbsp; 160KN，钻机宽度&amp;nbsp; &amp;nbsp; 1.6米，爬坡能力&amp;nbsp; &amp;nbsp; 35度，离去角&amp;nbsp; &amp;nbsp; 20度，钻杆长度&amp;nbsp; &amp;nbsp; 2米，钻杆直径&amp;nbsp; &amp;nbsp; 50MM，地面驱动速度&amp;nbsp; &amp;nbsp; 2公里/小时。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;这是一款履带式非开挖水平定向钻机，适用于地下管道铺设工程。如需了解更多详情或其他型号参数，请联系厂家客服18937135091。&lt;/span&gt;&lt;/p&gt;', '[\"1155\",\"1156\",\"1157\",\"1158\"]', '1212', '2', '1603', '2'),
(115, 26, '高举锚固钻机', '1213', '边坡护坡高举锚固钻机,高举护坡锚固钻机', '豫工高举锚固钻机结构优势明显，动力头功率高达136KW，转速达到148RPM，配备有螺旋钻头，爬坡能力出色，能很好地满足高举升锚固需求。高举升锚固钻机主要用于斜坡等复杂地形的锚固打孔作业，广泛适用于建筑，水利，勘探，深基坑支护，边坡加固等工程。', 1, 1, '创始人', 9, '/show-115.html', 0, 0, '127.0.0.1-62778', 1706925248, 1770448642, 0, '1139', '1138', '[\"1130\",\"1129\",\"1131\",\"1135\",\"1137\"]', '深度m 0-70米', '油泵 40/40/32/齿轮泵', '钻孔直径mm 0-300mm', '3000', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/hzB0aNcPe55uyrT1KtzwPRAD3xE.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;a href=&quot;https://www.zzyugong.cn/show-115.html&quot; target=&quot;_self&quot; title=&quot;豫工高举锚固钻机&quot; style=&quot;font-size: 18px; text-decoration: underline;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工高举锚固钻机&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;应用范围广泛，适用于建筑，水利，勘探，深基坑支护，边坡加固等工程。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202403/1709796745a1137f.png&quot; title=&quot;image&quot; alt=&quot;image&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202403/1709796797cebb77.png&quot; title=&quot;image&quot; alt=&quot;image&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;a href=&quot;https://www.zzyugong.cn/show-115.html&quot; target=&quot;_self&quot; title=&quot;豫工高举锚固钻机&quot; style=&quot;font-size: 18px; text-decoration: underline;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工高举锚固钻机&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;结构优势明显，动力头功率高达136KW，转速达到148RPM，配备有螺旋钻头，爬坡能力出色，能很好地满足高举升锚固需求。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://t12.baidu.com/it/u=2328653216,1341367877&amp;fm=199&amp;app=68&amp;f=JPEG&amp;fmt=auto?w=750&amp;h=2136&amp;s=BFA8870B12817D4306CCC15E0300D073&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;a href=&quot;https://www.zzyugong.cn/show-115.html&quot; target=&quot;_self&quot; title=&quot;豫工高举锚固钻机&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;高举锚固钻机&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;各种参数均能满足您的需求。如有进一步定制或其他疑问，欢迎联系我们，24小时工厂热线：189-3713-5091&lt;/span&gt;&lt;/p&gt;', '[\"1125\",\"1124\",\"1126\",\"1127\"]', '1214', '2', '1602', '2'),
(116, 26, '锚固钻机', '1215', '液压锚固钻机,多功能护坡钻机', '豫工机械履带锚杆钻机高举升液压护坡自行走锚索钻孔打岩柴动锚固钻车', 1, 1, '创始人', 9, '/show-116.html', 0, 0, '127.0.0.1-62778', 1706925265, 1769160936, 0, '1103', '1105', '[\"1107\",\"1108\",\"1119\",\"1118\",\"1120\"]', '型号 YG-500', '钻探深度 2000mm', '机器行走速度 0-40 m/h', '2000', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/4_ic1XqqgtD8SRsxUWz_dhAHlxQ.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;产品特性：锚固钻机&amp;nbsp; &amp;nbsp; 品牌：豫工机械&lt;br/&gt;型号：YG-350/500&amp;nbsp; &amp;nbsp; 产品别名：锚固钻车&lt;br/&gt;豫工锚固钻机适用范围：电站、公路及铁路山体边坡治理锚索加固、隧道管棚超前支护、基坑斜拉桩锚索、抗浮锚杆、路基加固、水电工程大坝基础及坝身防渗处理、排水孔、矿山及采石场、微型桩孔等工程。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/_vRj8G6PnU3bwJ90n2x5QRAI4O8.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/q2stX80Wi-9Iiq6i14NrpxAIMgM.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot; width=&quot;750&quot; height=&quot;1083&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;豫工锚固钻机优势&quot; alt=&quot;豫工锚固钻机优势&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工锚固钻机配备履带装置、22kw电动回转动力头，结构简单、操作容易，学习成本低。经济投入少，无需空压机，连接电源即可进行钻孔。配备90-200mm的麻花钻杆，硬质合金钻头，推进速度快，升举高度高，拆卸钻杆方便。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://b2b-material.cdn.bcebos.com/JdRi387VD1_xpBRJHObXAxAFZCE.jpg?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot; width=&quot;750&quot; height=&quot;1123&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;边坡支护锚杆钻机履带式锚固钻机自行走液压锚杆钻机豫工机械厂家&quot; alt=&quot;边坡支护锚杆钻机履带式锚固钻机自行走液压锚杆钻机豫工机械厂家&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械边坡支护锚杆钻机履带式锚固钻机自行走液压锚杆钻机厂家，豫工履带式液压锚杆钻机专业进行地质土层作业的工程钻车，其主要用于护坡加固、边坡稳固绿化、土质工程钻凿疏通、山体斜坡的加固工程、巷道建设、水利沟渠钻孔喷浆、小区地基稳固、基坑支护等工程。如有采购需求可拨打24小时热线：18937135091。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '[\"1113\",\"1114\",\"1115\",\"1117\"]', '1216', '2', '1601', '2'),
(117, 25, '液压墙锯机', '1225', '液压墙锯机,桥梁隧道混凝土切割机', '液压墙锯机（Hydraulic Wall Saw），在行业内通常被称为液压绳锯机（当使用金刚石绳锯时）或液压墙锯（当使用金刚石排锯片时），是一种广泛应用于建筑拆除、改建和加固工程中的高端混凝土切割设备。', 1, 1, '创始人', 9, '/show-117.html', 0, 0, '127.0.0.1-62778', 1706925295, 1767075552, 0, '1096', '1097', '[\"1091\",\"1092\",\"1093\",\"1094\",\"1095\"]', '最大切深 600mm', '频率 50hz', '锯片直径 800-1800mm', '600', '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202403/1709718392c0fefa.png&quot; title=&quot;image&quot; alt=&quot;image&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;液压墙锯机在建筑施工中扮演着关键角色，主要用于：&lt;/span&gt;&lt;/p&gt;&lt;ul class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;混凝土拆除：&lt;/strong&gt; 楼板、墙体、桥梁、基础的局部或整体拆除。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;门窗洞口改造：&lt;/strong&gt; 在现有墙体上精准切割出新的大门口或落地窗洞口。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;结构改造与加固：&lt;/strong&gt; 切除部分混凝土结构以便进行碳纤维加固、粘钢加固等。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;紧急救援：&lt;/strong&gt; 在地震、火灾等灾害后的应急救援中，用于开辟救援通道（使用专业的便携式版本）。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;核电站与水利工程：&lt;/strong&gt; 由于其切割精度高且无振动，常用于对结构稳定性要求极高的设施维护。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://b2b-openapi-attachment.bj.bcebos.com//2UJnX7kYpohu3aKHxdQP7emM8Vr?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;相比传统的爆破、风镐破碎或电动切割工具，液压墙锯机具有显著的优势：&lt;/span&gt;&lt;/p&gt;&lt;ul class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;切割能力强：&lt;/strong&gt; 液压系统具有高扭矩、低转速的特性，能够轻松应对&lt;strong&gt;加厚、高标号的钢筋混凝土&lt;/strong&gt;。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;施工精度高：&lt;/strong&gt; 切割面平整、光滑，通常不需要后续处理，不会对保留结构产生微裂纹损伤（这对建筑加固非常重要）。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;低噪音、低振动：&lt;/strong&gt; 相比冲击破碎，墙锯机的振动极小，噪音也较小，适合在敏感区域（如医院、学校、居民区）施工。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;环保无尘：&lt;/strong&gt; 采用湿法切割，水流直接带走粉尘，避免了扬尘污染。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;切割深度大：&lt;/strong&gt; 特别是液压绳锯，切割深度理论上是无限的（取决于绳索长度），可以完成超大体积的混凝土分离。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;多功能性：&lt;/strong&gt; 同一台主机，更换锯头即可安装金刚石圆盘锯（用于浅深度切割）或金刚石绳锯（用于深孔或异形切割）。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;http://b2b-openapi-attachment.bj.bcebos.com//2UJnXJXqiXBun5FrFCbTvhN4G8R?x-bce-process=image%2Fformat%2Cf_auto%2Fquality%2Cq_90%2Fignore-error%2Ci_1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;一套完整的液压墙锯机系统通常包含以下几个部分：&lt;/span&gt;&lt;/p&gt;&lt;ol class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;液压动力站：&lt;/strong&gt; 设备的“心脏”，提供动力源。可以是电动（适合室内）、柴油（适合野外无电源场景）。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;切割主机：&lt;/strong&gt; 安装在导轨上，包含液压马达、锯轮或锯片安装盘、进给机构等。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;导轨系统：&lt;/strong&gt; 固定在墙体或作业面上，确保切割机沿直线运行，保证切割精度。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;切割刀具：&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;ul class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;金刚石排锯片：&lt;/strong&gt; 适合直线切割，深度一般在500mm-700mm以内。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;金刚石绳锯：&lt;/strong&gt; 适合大体积、深层切割，甚至异形切割（如弧形）。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;电气与水路系统：&lt;/strong&gt; 控制开关、水管接头等。&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ol&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '[\"1087\",\"1086\",\"1088\",\"1090\"]', '1226', '2', '1500', '2'),
(118, 25, '岩石劈裂机', '1219', '90岩石液压劈裂机,矿用开山静态分裂器', '岩石劈裂机是一种用于开采石材、混凝土等硬质材料的重要设备。它通过施加巨大的力量，使岩石沿着预定的裂缝方向分裂，从而实现材料的开采。', 1, 1, '创始人', 9, '/show-118.html', 0, 0, '127.0.0.1-62778', 1706925311, 1727322386, 6, '1079', '1080', '[\"1075\",\"1076\",\"1077\",\"1078\",\"1083\"]', '钻孔深度 1-50', '油箱容积 22-60L', '适用介质 柴油 电力', '500', '', '', '', '[\"1071\",\"1073\",\"1081\",\"1082\"]', '1220', '1', '1492', '2'),
(119, 25, '矿山绳锯机', '1221', '矿山绳锯机,开采矿山绳锯', '主机身切割主要部件，主电机提供金刚石链条切割时所需的转动动力(电机正反转)小电机提供切割收紧金刚石链条所需的动力(绳锯机前后移动)行走齿轮齿优选45号钢制齿轮轴运行平稳有劲自动定点启停,自动回旋轨道无需人工助力。绳锯大盘加厚铝制大盘内置500MM加厚耐磨橡胶圈运行平稳、不掉绳、切割效率高。橡胶行走轮采用耐磨橡胶，精选哈尔滨轴承，推拉轻便，方便一人施工锥形支腿，抓地力更牢,防止左右偏移导向轮改变切割', 1, 1, '创始人', 9, '/show-119.html', 0, 0, '127.0.0.1-62778', 1706925326, 1713429652, 0, '1058', '1060', '[\"1063\",\"1064\",\"1065\",\"1067\",\"1066\"]', '机器行走速度 0-100m/h', '绳锯线速度 0-40m/s', '主电机功率 37\\45\\55\\75kw', '800', '&lt;p&gt;适用于花岗岩、大理石、砂岩等石材的矿山荒料开采。采用定制变频器+永磁同步电机，全频段恒扭矩输出，节能环保。&lt;/p&gt;', '&lt;p&gt;1. 采用PLC及变频器控制输出；&lt;/p&gt;&lt;p&gt;2. 可根据切割面积大小自行调整张力大小，确保切割状态；&lt;/p&gt;&lt;p&gt;3. 操作中配备高性能文本显示器，实时显示主机电压，电流，转速等参数；&lt;/p&gt;&lt;p&gt;4. 在设备出现故障或超载时自动报警并显示故障内容；&lt;/p&gt;&lt;p&gt;5. 设备机头可左右移动360度旋转定位准确，操作方便；&lt;/p&gt;&lt;p&gt;6. 独立控制箱结构，防尘效果好，系统稳定。&lt;/p&gt;&lt;p&gt;&lt;br style=&quot;white-space: normal;&quot;/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://t11.baidu.com/it/u=1474239075,195839195&amp;fm=199&amp;app=68&amp;f=JPEG&amp;fmt=auto?w=750&amp;h=874&amp;s=98B5CB12424D66E87C8FD1D2020030A9&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '[\"1054\",\"1055\",\"1056\",\"1057\"]', '1222', '2', '1498', '2'),
(120, 25, '液压绳锯机', '1223', '液压绳锯机,金刚石串珠锯绳', '绳锯是一种针对厚混凝土、不规则的混凝土的切割拆除设备。例如：钢筋混凝土梁、柱的切断、桥梁、楼板及石材加工等建筑基础混凝土结构需要部分拆除的话只有采用绳锯切割，使用方法灵活，横切割，竖切割均可。', 1, 1, '创始人', 9, '/show-120.html', 0, 0, '127.0.0.1-62778', 1706925343, 1727060319, 8, '1049', '1050', '[\"1045\",\"1044\",\"1046\",\"1047\",\"1048\"]', '直径 1200', '厚度 5mm', '材质 金刚石', '500', '', '', '', '[\"1040\",\"1039\",\"1041\",\"1042\"]', '1224', '2', '1499', '2');
INSERT INTO `dr_1_chanpinzhongxin` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `cpxqydblbtsp`, `cpxqydblbtspfm`, `cpxqydblbt`, `cpxqydbcs1`, `cpxqydbcs2`, `cpxqydbcs3`, `cpxqydbxjskq`, `cpxqyzbsyfw`, `cpxqyzbjgys`, `cpxqyzbsbcs`, `cpxqyzbbfyhxc`, `cplbycpzyslt`, `cpzxjhm`, `allbyzbyctmbjtp`, `syrmcpjhm`) VALUES
