INSERT INTO `dr_1_chanpinzhongxin` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `cpxqydblbtsp`, `cpxqydblbtspfm`, `cpxqydblbt`, `cpxqydbcs1`, `cpxqydbcs2`, `cpxqydbcs3`, `cpxqydbxjskq`, `cpxqyzbsyfw`, `cpxqyzbjgys`, `cpxqyzbsbcs`, `cpxqyzbbfyhxc`, `cplbycpzyslt`, `cpzxjhm`, `allbyzbyctmbjtp`, `syrmcpjhm`) VALUES
(135, 19, '排水方舱', '660', '移动照明排水方舱,自动装卸排水方舱', '自动装卸排水方舱采用350m³/min的大流量水泵，20-25米的加厚加长水带，可快速进行排涝排污。排水方舱采用18KW大功率进口品牌发电机组，增加了电启动功能，性能稳定，操作简单；52L加大油箱，避免了频繁加油的麻烦，给长时间施工的提供了保障。', 1, 1, '创始人', 9, '/show-135.html', 0, 0, '127.0.0.1-50471', 1706925690, 1713428495, 0, '649', '650', '[\"652\",\"651\",\"653\",\"654\",\"655\"]', '流量 350m³/h', '扬程 30m', '压力 35Mpa', '2000', '&lt;p&gt;1&lt;span style=&quot;color: rgb(34, 34, 34); font-family: arial; font-size: 18px; background-color: rgb(255, 255, 255);&quot;&gt;. 暴雨、洪水等水灾场景：可以快速排除受灾区域的积水，降低灾害带来的影响。&lt;/span&gt;&lt;br style=&quot;display: block; max-width: 100%; color: rgb(34, 34, 34); font-family: arial; font-size: 18px; white-space: normal; background-color: rgb(255, 255, 255);&quot;/&gt;&lt;br style=&quot;display: block; max-width: 100%; color: rgb(34, 34, 34); font-family: arial; font-size: 18px; white-space: normal; background-color: rgb(255, 255, 255);&quot;/&gt;&lt;span style=&quot;color: rgb(34, 34, 34); font-family: arial; font-size: 18px; background-color: rgb(255, 255, 255);&quot;&gt;2. 紧急救援场景：可以为救援现场提供必要的电力支持、照明支持等。&lt;/span&gt;&lt;br style=&quot;display: block; max-width: 100%; color: rgb(34, 34, 34); font-family: arial; font-size: 18px; white-space: normal; background-color: rgb(255, 255, 255);&quot;/&gt;&lt;br style=&quot;display: block; max-width: 100%; color: rgb(34, 34, 34); font-family: arial; font-size: 18px; white-space: normal; background-color: rgb(255, 255, 255);&quot;/&gt;&lt;span style=&quot;color: rgb(34, 34, 34); font-family: arial; font-size: 18px; background-color: rgb(255, 255, 255);&quot;&gt;3. 临时工地场景：可以为临时工地提供必要的电力支持、照明支持、排水支持等。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;&lt;strong&gt;设备特点&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;全钢制钣金机箱：&lt;/strong&gt;高温烤漆 防雨防晒 耐腐蚀，高标准用料制作工艺，外壳持久如新&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;低噪音/静音箱体：&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;科学创新 物理降噪，阻隔式进排风设计 抗阻复合消声体 汽车减震垫 高密度波浪吸音棉&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;自卸式移动照明塔：&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;机动性强 360º多范围现场照明，一人可装卸 加配远程视频传输和喇叭播放功能&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;智能液晶控制屏：&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;一键操作 无需值守 自装卸系统，数字显示 运行检测 单人远程操控。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;&lt;strong&gt;性能优势&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;排水方舱灯头由2个60W进口LED光源组成，可满足设备周边施工作业的照明需要，也可将灯头在上下左右0-90°调节旋转，实现多角度，大范围照明&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;灯塔两侧的防护灯采用28W固态LED光源，给近距离施工和操作提供照明需求及安全提示&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;采用350m³/min的大流量水泵，20-25米的加厚加长水带，可快速进行排涝排污&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;排水方舱采用四个加强型支脚，并分别在顶部配备警示频闪灯，以提示过往车辆或施工人员安全, 支脚的展开和收纳采用电动控制，操作简单，方便快捷&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;可视电子油表，可随时了解油箱油量，以免过耗使用，减少发电机组寿命&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;配备4个高强度尼龙脚轮，向下翻转，即可推行移动；向上翻起，就可稳定落地，既方便了短距离移动照明，又保证了设备运行时的安全。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;排水方舱采用18KW大功率进口品牌发电机组，增加了电启动功能，性能稳定，操作简单；52L加大油箱，避免了频繁加油的麻烦，给长时间施工的提供了保障&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;整体采用各种优质金属材料制作，结构紧凑，性能稳定，确保在各种恶劣环境和气候条件下正常工作，防雨淋、喷水，抗风等级为8级。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;350立方应急排水方舱&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;照明参数&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;升降照明灯：2*60W（LED）&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;辅助照明灯：2*30W（LED）&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;升降方式：自动+遥控&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;发电机参数&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;额定功率： 18KW&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;备用功率： 20KW&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Mi