(146, 20, '圆盘过滤机', '465', '圆盘过滤机,陶瓷过滤机', '豫工盘式真空过滤机是利用真空作为过滤动力，使浆液进行固液分离的设备。', 1, 1, '创始人', 9, '/show-146.html', 0, 0, '127.0.0.1-55523', 1706945817, 1773192182, 0, '402', '403', '[\"397\",\"398\",\"399\",\"400\",\"401\"]', '型号 50-500', '有效过滤面积 50-500平', '适用对象性质 弱腐蚀性,低温物料', '3000', '&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;适用于矿山金属矿、非金属矿、环保污泥、水泥、建材等行业细颗粒物料的过滤脱水&lt;/span&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/17692179737cff3d.jpg&quot; title=&quot;豫工圆盘过滤机 &quot; alt=&quot;豫工圆盘过滤机 &quot; width=&quot;774&quot; height=&quot;581&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;省：与传统脱水设备相比用电量节省80%&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;高：可联系作业，自动卸料。工作效率可以提高30%&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;易：操作容易，维护更容易少：自控程度高，减少操作人员数量&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;快：具有故障自动报警屏幕显示功能、可快速精准定位、处理故障&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;固：结构牢固，经久耐用&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;低：本机采用微机优化设计，降低运输成本&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;清：滤液清澈，可反复利用，减少排放，符合当前清洁生产的环保大趋势&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;小:结构设计合理，占地面积小。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://cbu01.alicdn.com/img/ibank/O1CN010N0tZs2G56huKSJn4_!!2206736258963-0-cib.jpg?__r__=1657945179228&quot; width=&quot;774&quot; height=&quot;1461&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;豫工80平方圆盘真空陶瓷过滤机&quot; alt=&quot;豫工80平方圆盘真空陶瓷过滤机&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;豫工&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;80平方圆盘真空陶瓷过滤机自动化控制，处理能力强，如果有定制或者其他采购需求，可拨打24小时热线：18937135091&lt;/span&gt;&lt;/p&gt;', '[\"404\",\"406\",\"405\",\"407\"]', '466', '1', '1489', '1'),
(147, 20, '工业压滤机', '470', '工业压滤机,板框式污泥压滤机,厢式压滤机', '压滤机有厢式、板框式、带式，品类多样，型号齐全，主营系列有：200、320、450、630、800、1000、1250、1500、1600、φ800、φ1000型。板框式及厢式过滤面积0.5㎡-800㎡。板框材质有铸铁、增强聚丙稀、玻璃纤维聚丙稀（耐温120℃）及不锈钢板框等。压紧形式有手动压紧、机械压紧、千斤顶压紧、液压压紧、自动保压压紧及微机程控全自动控制等。', 1, 1, '创始人', 9, '/show-147.html', 0, 0, '127.0.0.1-55522', 1706945840, 1773192139, 0, '375', '376', '[\"377\",\"378\",\"380\",\"379\",\"381\"]', '厢式压滤机', '进料压力：0-0.6MPa', '过滤面积：30-1000㎡', '2000', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑; font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;厢式压滤机广泛应用冶金、化工、印染、陶瓷、食品、医药、矿山、洗煤等行业。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑; font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑; font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑; font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;豫工&lt;/span&gt;压滤机热卖爆款&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;厢式自动保压压滤机：适用于过滤面积较大的压滤机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;板块式自动保压压滤机：适用于物料浓度比较大，处理量大行业使用&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;自动保压隔膜厢式压滤机：适用于粘性、含水率要求较高的过滤&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;程控自动拉板厢式压滤机：在拉板运行中，自动纠偏滤板&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;您的需要，我们解决：为客户提供一站式的全程专业服务,支持设备定制、优先发货、维护保养等方面更省心。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1769216935256fdc.jpg&quot; title=&quot;板块式自动保压压滤机&quot; alt=&quot;板块式自动保压压滤机&quot; width=&quot;774&quot; height=&quot;436&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑; font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;&lt;/span&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1769217017d001a4.png&quot; title=&quot;自动保压隔膜厢式压滤机&quot; alt=&quot;自动保压隔膜厢式压滤机&quot;/&gt;&lt;/p&gt;', '&lt;p style=&quot;margin-top: 0px; margin-bottom: 0px; white-space: normal; padding: 0px; background: rgb(255, 255, 255);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: 宋体; letter-spacing: 0px; font-size: 19px;&quot;&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;多家权威机构认证&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;:ISO9001质量体系生产，环保、节能、食品、环境管理多项认证。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;样式齐全&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：主营板块式、厢式、隔膜式压滤机，滤板滤布等，品类多样，型号齐全。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;急速发货&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：每种型号备货充足，最快的速度送货上门。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;性价比高&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;：厂家直销，支持定制，一台也是批发价&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;脱水效率高&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;，泥饼固含率高&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 0px; margin-bottom: 0px; white-space: normal; padding: 0px; background: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;处理量大&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt; 低噪低耗 高效过滤 耐酸耐碱 耐温耐压 规格齐全&lt;/span&gt;&lt;span style=&quot;font-family: 宋体; font-size: 19px;&quot;&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: 宋体; font-size: 19px;&quot;&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;;font-family:宋体;font-weight:normal;font-size:19px&quot;&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202402/17084845405f3215.jpg&quot; title=&quot;程控压滤机参数图&quot; alt=&quot;程控压滤机参数图&quot; width=&quot;900&quot; height=&quot;681&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202402/1708484566161e80.jpg&quot; title=&quot;豫工隔膜压滤机参数图&quot; alt=&quot;豫工隔膜压滤机参数图&quot; width=&quot;774&quot; height=&quot;899&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202402/1708484584bcf9da.jpg&quot; title=&quot;液压压滤机参数图&quot; alt=&quot;液压压滤机参数图&quot; width=&quot;900&quot; height=&quot;690&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202402/1708484595f3dc67.jpg&quot; title=&quot;1-19113011015b11&quot; alt=&quot;1-19113011015b11&quot; width=&quot;900&quot; height=&quot;252&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: 微软雅黑; font-size: 18px; color: rgb(0, 0, 0);&quot;&gt;豫工厢式压滤机部分型号详细参数，如有定制或者其他采购需求，可以直接拨打24小时热线：18937135091&lt;/span&gt;&lt;/p&gt;', '[\"386\",\"387\",\"388\",\"389\"]', '471', '2', '1490', '1'),
(148, 19, '除雪铲', '355', '汽车推雪铲,装载机车载除雪铲', '除雪铲根据路况具有自动调节功能，与车辆的安装及拆卸简单方便快捷； 除雪铲结构合理，作业时可将雪推向一侧，高速作业时能将雪抛起；具有独立于车体之外的照明系统，便于夜间作业；采用铲体整体避障，铲刀遇到障碍时，铲板整体翻转，能有效的保护铲板及车辆，液压驱动，性能稳定，质量可靠。', 1, 1, '创始人', 9, '/show-148.html', 0, 0, '127.0.0.1-55522', 1706945854, 1773192120, 0, '226', '227', '[\"223\",\"222\",\"224\",\"225\"]', '雪铲宽度：2米、2.5米、3米、3.5米', '左右摆角：±30°', '作业速度：≥30km/h', '600', '', '', '', '[\"218\",\"217\",\"219\",\"220\"]', '303', '2', '1470', '2'),
(149, 20, '泥浆分离器', '368', '桥梁桩基泥浆分离器,泥浆分离器', '打桩泥沙 盾构泥浆 顶管污泥 高效净化', 1, 1, '创始人', 9, '/show-149.html', 0, 0, '127.0.0.1-55522', 1706945866, 1727322518, 7, '345', '343', '[\"347\",\"346\",\"348\",\"350\",\"365\"]', '浆液处理能力：100-250m3/h', '分离粒度：20d50（μm）', '渣料筛分能力：10-15t/h', '2000', '', '', '', '[\"361\",\"362\",\"364\",\"363\"]', '369', '1', '1493', '2'),
(150, 20, '客土喷播机', '456', '草籽草种喷播机,客土喷播机', '客土喷播机核心泵采用特制加压多级泵，可以将粘稠物料从喷嘴处高速喷出，直接射程 -减少施工难度，提高，增加安全，高边坡可接橡胶耐磨管，增加扬程，方便施工。', 1, 1, '创始人', 9, '/show-150.html', 0, 0, '127.0.0.1-55523', 1706945878, 1773192252, 3, '322', '323', '[\"332\",\"335\",\"334\",\"336\",\"337\"]', '型号：88kw客土喷播机', '罐体容量：6m³', '引管扬程：80米', '1000', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;主要用于人工施工难度大、坡度陡峭或地质条件差的绿化工程：&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;矿山修复：&lt;/strong&gt; 矿山开采后的裸露岩体、尾矿库边坡复绿。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;道路护坡：&lt;/strong&gt; 高速公路、铁路两侧的高陡岩石边坡或土质边坡绿化。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;水利工程：&lt;/strong&gt; 河道、水库岸坡的生态防护与绿化。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;荒漠治理：&lt;/strong&gt; 贫瘠土地的改良与植被恢复。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;高尔夫球场/公园：&lt;/strong&gt; 大面积草坪的建植。&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;对比传统的人工撒种或铺草皮，喷播机在工程应用上优势巨大：&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;效率极高：&lt;/strong&gt; 机械化作业，效率是人工的几十倍，非常适合工期紧张的工程项目。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;适应高陡边坡：&lt;/strong&gt; 能解决70度甚至更陡峭岩石坡面的施工难题，这是人工无法完成的。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;成活率高：&lt;/strong&gt; 种子与肥料、保水剂混合均匀，且喷播后在坡面形成保护膜，抗雨水冲刷能力强，发芽率高。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;成本可控：&lt;/strong&gt; 虽然设备投入有一定成本，但大大降低了人工成本和后期养护成本，综合性价比高。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;施工灵活：&lt;/strong&gt; 既可用于岩石边坡的厚层基材喷播(客土喷播)，也可用于普通土坡的液力喷播。&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;工程上常用的喷播机规格通常以罐体容积和发动机功率区分：&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;罐体容积：&lt;/strong&gt; 常见有4m³、6m³、8m³、10m³、12m³(根据工程量大小选择)。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;发动机：&lt;/strong&gt; 多采用柴油发动机，功率范围一般在30kW-100kW之间。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;水平输送距离：&lt;/strong&gt; 一般在200m-500m(垂直输送距离通常在50m-100m，取决于扬程)。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;喷射效率：&lt;/strong&gt; 根据机型不同，每小时喷播面积约为500-2000平方米。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;搅拌系统：&lt;/strong&gt; 采用机械搅龙搅拌或水力循环搅拌，要求无死角、不沉淀。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;通过性：&lt;/strong&gt; 设备通常搭载在卡车底盘或拖车上，需适应复杂的工地路况。&lt;/span&gt;&lt;/p&gt;', '[\"329\",\"328\",\"330\",\"331\"]', '455', '2', '1495', '1'),
(151, 21, '马路吹风机', '354', '车载式马路吹风机,马路吹风机,路面吹扫机、路面吹扫机', '车载式路面吹风机具有外形美观、振动小、噪音低操作舒适、油耗低、风量大、清扫效率高。省时省力，提高工效，通常配合路面清扫机使用。配备柴油机,适合吹扫高速，国道，省道等。', 1, 1, '创始人', 9, '/show-151.html', 0, 0, '127.0.0.1-55523', 1706945894, 1721291498, 0, '313', '314', '[\"315\",\"316\",\"317\",\"318\"]', '设备型号：YG-150', '风叶直径：1100mm', '吹扫距离：0---12米', '600', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;background-color: rgb(255, 255, 255); color: rgb(51, 51, 51); font-family: system-ui, -apple-system, &amp;quot;Segoe UI&amp;quot;, Roboto, Ubuntu, Cantarell, &amp;quot;Noto Sans&amp;quot;, sans-serif, &amp;quot;Apple Color Emoji&amp;quot;, &amp;quot;Segoe UI Emoji&amp;quot;, &amp;quot;Segoe UI Symbol&amp;quot;, &amp;quot;Noto Color Emoji&amp;quot;, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, Arial, &amp;quot;PingFang SC&amp;quot;, &amp;quot;PingFang TC&amp;quot;, &amp;quot;PingFang HK&amp;quot;, &amp;quot;Microsoft Yahei&amp;quot;, &amp;quot;Microsoft JhengHei&amp;quot;; font-size: 18px; white-space: pre-wrap;&quot;&gt;马路吹风机主要由一台小型的滑移装载机加吹风机附件构成，其风力强劲，能够有效地吹除道路上的灰尘、落叶、砂石等杂物。这种设备在道路标线施工前的清扫、沥青路面的铺设前水稳层的清扫、路面裂缝和灌缝前的清扫等方面发挥着重要作用。此外，它还可以用于露天体育比赛的除湿吹干，以及大型广场、绿地、公园和高尔夫球场的落叶吹落及吹扫等任务。&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, &amp;quot;Segoe UI&amp;quot;, Roboto, Ubuntu, Cantarell, &amp;quot;Noto Sans&amp;quot;, sans-serif, &amp;quot;Apple Color Emoji&amp;quot;, &amp;quot;Segoe UI Emoji&amp;quot;, &amp;quot;Segoe UI Symbol&amp;quot;, &amp;quot;Noto Color Emoji&amp;quot;, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, Arial, &amp;quot;PingFang SC&amp;quot;, &amp;quot;PingFang TC&amp;quot;, &amp;quot;PingFang HK&amp;quot;, &amp;quot;Microsoft Yahei&amp;quot;, &amp;quot;Microsoft JhengHei&amp;quot;; white-space: pre; background-color: rgb(255, 255, 255); font-size: 18px;&quot;&gt;马路吹风机具有灵活简便的特点，能够适应不同的工作环境和作业需求。其操作简便，可以快速地调整风力大小和吹扫方向，提高工作效率。同时，马路吹风机费用相对低廉，维修方便，降低了使用成本。\r\n另外，马路吹风机还具有环保性。相比于传统的清扫方式，马路吹风机能够减少清扫过程中产生的二次污染，保护环境和生态。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备参数&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/172129191074f20c.webp&quot; title=&quot;参数&quot; alt=&quot;参数&quot;/&gt;&lt;br/&gt;&lt;/p&gt;', '[\"309\",\"308\",\"310\",\"311\"]', '320', '1', '1486', '2'),
(152, 21, '绿篱修剪机', '3276', '车载绿篱修剪机,绿篱修剪机', '绿篱修剪机经常用在市政园林工程，高枝修剪，城市中间绿化带修剪，边坡草坪树枝的修剪工作。绿篱修剪机有很多种规格，伸缩臂绿篱修剪机，折叠臂绿篱修剪机，避障类绿篱修剪机等，伸展臂的长度可以根据客户要求定，一般伸缩臂的长度在4.5米-6米；折叠臂的长度在6米-8米左右。', 1, 1, '创始人', 9, '/show-152.html', 0, 0, '127.0.0.1-60225', 1706950121, 1769574648, 0, '279', '280', '[\"281\",\"282\",\"283\",\"284\",\"3279\"]', '臂长：3000-6000mm', '修剪幅宽：1500mm-2000m', '平剪高度：100-2840mm', '1000', '&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;绿篱修剪机是一种用于对绿植进行造型和养护的专业机械，其适用范围广泛，可根据设备类型和动力方式应用于多种场景。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;园林绿化&lt;/strong&gt;‌：适用于公园、庭园、道路旁的绿篱、树篱修剪，以及草坪边缘修整，满足日常维护和景观造景需求。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;高速公路与市政工程&lt;/strong&gt;‌：用于高速公路中央隔离带、边坡绿化带的修剪，部分车载式机型可实现高效作业，修剪宽度可达1.5米，速度1-15公里/小时。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;茶园管理&lt;/strong&gt;‌：专业机型可用于茶树修剪，促进新芽萌发，提高作业效率。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;居民区、别墅区等私人区域&lt;/strong&gt;：对于一些小型居民区或别墅区，绿篱修剪车也可以提供便利的服务，使得绿化带保持整洁美观。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;商业区、办公区等场所&lt;/strong&gt;：商业区、办公区等地的绿化带通常需要定期修剪和，绿篱修剪车可以帮助这些地方提高工作效率和质量。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;垂直绿化与立体景观&lt;/strong&gt;‌：新型侧平一体式设计机型可修剪垂直绿墙，最大修剪高度达3.2米，扩展了在建筑立面等立体绿化中的应用。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;家庭园艺&lt;/strong&gt;‌：便携式电动或手动绿篱剪适合别墅、庭院等小型绿植修剪，注重操作灵活性和修剪精度。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备类型上，‌&lt;strong&gt;便携式&lt;/strong&gt;‌绿篱机适合精细作业(如灌木造型)，而‌&lt;strong&gt;悬挂式&lt;/strong&gt;‌或车载机型则适用于大面积、高强度环境(如高速公路)。动力方式包括电动(如锂电池驱动)和汽油机，可根据场景需求选择。 ‌&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1769574416e2ad36.jpg&quot; title=&quot;豫工绿篱修剪机&quot; alt=&quot;豫工绿篱修剪机&quot; width=&quot;774&quot; height=&quot;774&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工伸缩臂绿篱修剪机结构优势。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;伸缩臂绿篱修剪机是一种结合了伸缩臂设计与绿篱修剪功能的专业园林工具，其结构优势主要体现在‌&lt;strong&gt;提升操作灵活性、增强安全性与扩大作业范围&lt;/strong&gt;‌等方面。 ‌&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;灵活调整作业高度&lt;/strong&gt;‌：伸缩臂可根据需要自由调节长度(常见范围260-330cm)，使操作者无需借助梯子等登高设备，即可轻松修剪2-5米高的绿篱或树枝，显著提升高空作业的便捷性。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;扩大作业覆盖范围&lt;/strong&gt;‌：配合加长刀片(如50cm以上)，单次修剪宽度可提升至60cm，减少移动次数，提高单位时间内的修剪效率。 ‌&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;降低劳动强度与提升安全性&lt;/strong&gt;‌：操作者可站在地面完成修剪，避免了登高作业的风险，同时减少体力消耗，尤其适合长时间或大面积作业。 ‌&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;‌&lt;strong&gt;精准控制修剪角度&lt;/strong&gt;‌：部分机型的伸缩臂与刀头可联动调节，便于在复杂地形(如靠近围墙、坡地)实现多角度修剪，确保造型整齐。 ‌&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;此类设计广泛应用于城市绿化、庭院维护及茶园管理，兼顾效率与人性化操作。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1769574253d48804.jpg&quot; title=&quot;绿篱修剪机型号参数&quot; alt=&quot;绿篱修剪机型号参数&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工绿篱修剪机80YG-2型号参数，其他型号参数可咨询线上客服，也可拨打24小时热线18937135091。&lt;/span&gt;&lt;/p&gt;', '[\"288\",\"287\",\"289\",\"290\"]', '3278', '2', '3277', '2');
INSERT INTO `dr_1_chanpinzhongxin` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `cpxqydblbtsp`, `cpxqydblbtspfm`, `cpxqydblbt`, `cpxqydbcs1`, `cpxqydbcs2`, `cpxqydbcs3`, `cpxqydbxjskq`, `cpxqyzbsyfw`, `cpxqyzbjgys`, `cpxqyzbsbcs`, `cpxqyzbbfyhxc`, `cplbycpzyslt`, `cpzxjhm`, `allbyzbyctmbjtp`, `syrmcpjhm`) VALUES
(153, 21, '液压铣刨机', '360', '自行走混凝土铣刨机,350液压铣刨机', '路面铣刨机是沥青路面养护施工机械的主要机种之一，沥青混凝土路面养护施工的主要设备之一。', 1, 1, '创始人', 9, '/show-153.html', 0, 0, '127.0.0.1-60223', 1706950165, 1713428883, 0, '269', '268', '[\"264\",\"265\",\"266\",\"267\"]', '型号：350型电动铣刨机', '铣刨深度：5公分', '工作宽度：0-500mm', '500', '&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;路面铣刨机的用途:&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;1、对水泥、沥青混凝土路面、高速公路桥面、桥梁错台，环氧树脂地面的多出标高部位进行铣削调平;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2、对沥青路面的局部涌包，车辙，网裂，坑槽部位的铣刨。桥面和路面的冰雪。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;3、沥青砼新铺前对原有路面的轻度拉毛，或配合大型铣刨机完成边角区域和钢筋区域的铣刨拉毛作业。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;4、去除地面涂层、油漆、各种交通标线；地面受损、积污需要翻新时，旧地坪表面铣刨等。&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;路面铣刨机的&lt;span style=&quot;font-family: Arial, Helvetica, sans-serif; background-color: rgb(255, 255, 255);&quot;&gt;工作、施工工艺简单、铣削深度易于控制、操作方便灵活、机动性能好、铣削的旧料能直接回收利用等，因而用于城镇市政道路和高速公路养护工程中。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;效率：拉毛、凿毛300平方左右/小时&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;深铣100多平方/小时&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;铣刨机刀片：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;300型&amp;nbsp; 96片&amp;nbsp; φ83&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;350型&amp;nbsp; 114片&amp;nbsp; φ83&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;500型拉毛的 用 210片的 φ60刀片&lt;/span&gt;&lt;/p&gt;', '[\"260\",\"261\",\"262\",\"263\"]', '277', '2', '1483', '2'),
(154, 21, '机载凿毛机', '630', '履带式拉毛机,机载凿毛机', '凿毛机是一种把已经完成的主体结构面进行处理的设备，是使两个施工阶段的施工面粘接牢固，类似于“斩斧”的工具。通常应用在混凝土表面凿毛，凿毛深度5-20毫米，根据施工要求而定，（一般情况是混凝土表面1-2厘米保护层去除，露出大骨料）。', 1, 1, '创始人', 9, '/show-154.html', 0, 0, '127.0.0.1-60223', 1706950183, 1769393294, 0, '248', '249', '[\"250\",\"251\",\"252\",\"253\"]', '凿毛深度：5-20毫米', '凿毛头：2台11头凿毛机', 'C30-40混凝土每小时40-50平方米，C50每小时20-30平方米', '600', '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1769392349d6e677.jpg&quot; title=&quot;豫工机载凿毛机&quot; alt=&quot;豫工机载凿毛机&quot; width=&quot;750&quot; height=&quot;750&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机载凿毛机适用范围：&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;1、桥面表面防水处理凿毛。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2、高速铁路箱梁(预制梁)的梁面防水处理凿毛&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;3、桥侧、桥端面、梁侧、梁端面的混凝土凿毛&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;4、去除地面图层、油漆、各种交通标线&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;5、清洗、清除机场跑道标线、飞机跑道轮胎制动痕迹等，重新获得摩擦系数很高的粗糙表面&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;6、对水泥沥青路面、高速公路桥面、桥梁错台，环氧树脂耐磨地面等的表面处理&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;7、道路微表处施工，对原有旧路路面层进行凿毛清楚，为稀浆封层作准备&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;主要适用于水库、大坝渗漏、险桥危桥加固、电厂、高速公路、高速铁路、隧道等各类建筑补强和混凝土凿毛工程。对各种陈旧地面做翻新前的地坪处理;去除破损地面凸起部分;环氧树脂地面凿毛;地面做防滑面;新面层打毛等。&lt;/span&gt;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1769392654510c3d.jpg&quot; title=&quot;豫工机载凿毛机设备优势&quot; alt=&quot;豫工机载凿毛机设备优势&quot; width=&quot;774&quot; height=&quot;774&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机载凿毛机设备优势&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;寿命长：钨钢合金制作，使用寿命8000-10000平方米&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;凿毛效果好 ：凿击频率2400次/min，不破坏基础主体&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;操作灵活 ：自动行走，高低可调，移机方便，凿毛均匀&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;凿毛效率高 ：C50凿毛效率120㎡/h，C40凿毛效率150㎡/h&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工凿毛机型号: YG-22 (22个凿毛头)&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;凿毛深度: 0.5-30MM深度可调&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;动力: 柴油，电启动，8升46号液压油&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;凿毛宽度: 900MM&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;尺寸: 2.9*0.9*1.78米&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;机型小.重量轻.凿毛头是高优质的钨钢合金制作.硬度强.质量优.主要用于小面积的凿毛(局部、立面、侧面、顶面凿毛)，且不会对原有结构造成破坏.&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1769393274f676be.jpg&quot; title=&quot;机载凿毛机参数&quot; alt=&quot;机载凿毛机参数&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '[\"254\",\"255\",\"256\",\"257\"]', '631', '2', '1485', '2'),
(155, 21, '非固化喷涂机', '359', '非固化喷涂机,桥梁非固化喷涂机', '​非固化热熔喷涂机可加热熔化380kg非固化材料，仅需1小时左右，同时兼保温喷涂功能。', 1, 1, '创始人', 9, '/show-155.html', 0, 0, '127.0.0.1-60223', 1706950201, 1713428865, 0, '237', '243', '[\"233\",\"234\",\"235\",\"236\"]', '工作电源：380V', '胶管耐压：4mpa', '总功率：8.5kw', '600', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;background-color: rgb(255, 255, 255); font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;非固化热熔喷涂机可用于楼顶、隧道、屋面、地下室、地下车库、游泳池、小面积工地等工程非固化材料，如非固化沥青、高温沥青等防水工程喷涂施工作业，在应用时配备加热棒或者熔胶机进行使用，若是工程量小，可配备3-4个加热棒；若是工程量大，需要配备熔胶机。&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;background-color: rgb(255, 255, 255); font-family: Arial, Helvetica, sans-serif;&quot;&gt;1.&lt;/span&gt;&lt;span style=&quot;font-family: Arial, Helvetica, sans-serif;&quot;&gt;非固化热熔喷涂机&lt;/span&gt;&lt;span style=&quot;background-color: rgb(255, 255, 255); font-family: Arial, Helvetica, sans-serif;&quot;&gt;移动方便，四角有手提把手，采用定制万向轮，行走移动更加方便；体积小，可以进入狭小空间作业，更利于施工安全。&lt;/span&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2.一体成型，集成控制面板为一键智能操作，简单易学，方便快捷，避免误操作；电气保护装置，防水防尘，。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;3.温度调节，智能可控，喷管喷枪自动加热，温度可调节。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;4.定制非固化泵，高品质，寿命是普通泵的三倍。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;5.进料口添加过滤网，完善的过滤系统，喷涂不堵塞；喷涂顺畅，反复使用喷头不堵塞，设置涂料回转功能，喷嘴和管不形成沥青凝固。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;6.防缺相防水插头，为施工安全提供保障。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;7.喷涂管可加温260度，耐高压，耐高温，耐磨损，免清洗，不易积碳。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; padding: 0px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; white-space: normal; background-color: rgb(255, 255, 255); line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;8.两个散热扇装置，散热降温效果更好。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: Arial, Helvetica, sans-serif; font-size: 16px; background-color: rgb(255, 255, 255);&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;', '&lt;table class=&quot;table&quot;&gt;&lt;tbody style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;tr style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot; class=&quot;firstRow&quot;&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;产品名称&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;非固化喷涂机&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;电压&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;380v&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;功率&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;8.5kw&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;管长&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;10m&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;加热方式&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;电加热&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;电源线&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;三相四线&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;保质期&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;一年&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;产品尺寸&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; word-break: break-all;&quot;&gt;&lt;p style=&quot;text-align:center;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;900*650*840mm&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;', '[\"238\",\"239\",\"240\",\"241\"]', '286', '2', '1482', '2'),
(156, 21, '路面抛丸机', '358', '路面抛丸机,桥面抛丸机', '路面抛丸机使用钢丸钢砂能将混凝土的表面浮浆、杂质清理，并且可以对混凝土的表面进行打毛处理，使其表面均匀粗糙，提高了防水层和混凝土基层的黏着强度，以便防水层和桥面更好的结合，同时也能够将混凝土的裂纹充分暴露出来，便于及时解决。', 1, 1, '创始人', 9, '/show-156.html', 0, 0, '127.0.0.1-60225', 1706950216, 1769397268, 0, '190', '2376', '[\"186\",\"185\",\"187\",\"188\",\"189\"]', '工作宽度：270mm 550mm 850mm', '清理效率：180-600立方米/', '行走速度：30m/min', '800', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;豫工路面抛丸机广泛应用于 混凝土桥面防水打毛、沥青路面的清理和打毛，以增加表面粗糙度；路面、隧道及桥粱的抗滑性能恢复；沥青路面泛油的清理、标志线清理；钢桥面除锈防腐涂装处理；机场道路除胶和除线、跑道机坪表面摩擦系数和纹理恢复。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1769397222b8e7c0.jpg&quot; title=&quot;豫工550抛丸机钢板除锈&quot; alt=&quot;豫工550抛丸机钢板除锈&quot; width=&quot;774&quot; height=&quot;581&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;1.操作和准备工作简单，随时清理，随时撤离。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2.采用了变频调速、PLC控制、相序保护、文本显示等多项先进的电器调控技术，确保各项功能的准确实现。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;3.可以根据路面的不同状况来设定清理速度、钢丸供给量、脉冲反吹时间周期、除尘滤筒的清灰间隔时间等，通过参数组合的调整、达到理想的清理效果。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;4.工作幅面较宽、效率高。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;5.整个施工过程无尘、无污染，有利于环保和施工人员的身体健康。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;6.脉冲自动反吹除尘，可以实现连续工作。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;7.施工中基本上不损伤路面结构。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;8.钢丸在设备内部自动循环，消耗很低。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;9.整机结构合理，拆卸快捷，维修及更换易损件方便。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;', '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202402/1708247344610783.png&quot; title=&quot;image&quot; alt=&quot;image&quot;/&gt;&lt;/p&gt;', '[\"191\",\"192\",\"193\",\"194\"]', '292', '2', '1481', '2'),
(157, 19, '融雪撒布机', '357', '融雪剂撒布机,融雪撒盐机', '盘式撒布设备，选用离心力抛射的作业原理，经过料仓的融雪剂被送入盘式撒布设备后，在高速旋转抛盘的离心力作用下被抛出，转速越高抛程越远。', 1, 1, '创始人', 9, '/show-157.html', 0, 0, '127.0.0.1-60223', 1706950231, 1773191529, 0, '209', '174', '[\"175\",\"176\",\"177\",\"178\",\"179\"]', '料斗容积：0.3方 3方 5方', '撒布宽度： 0.6-12 米', '料斗材质：聚乙烯', '800', '&lt;p&gt;&lt;span style=&quot;font-family: 微软雅黑; color: rgb(0, 0, 0); font-size: 18px;&quot;&gt;聚乙烯融雪撒布机主要用于公路、小区、机场等道路冬季应急撒盐融雪作业&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;撒布机采用聚 乙烯材质制作工艺，直流减速电机驱动，运用汽车自带电瓶电源提供动力，无极调速调节撒布宽度， 其特色主要是低功耗，节能环保，不产生有害气体，耐腐蚀，经久耐用，解决了传统撒盐设备的易 腐蚀难题。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 19px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;撒布宽度连续可调&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 19px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;span style=&quot;font-size: 19px;&quot;&gt;撒布均匀&lt;/span&gt; &lt;span style=&quot;font-size: 19px;&quot;&gt;稳定可靠&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 19px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;span style=&quot;font-size: 19px;&quot;&gt;聚乙烯材质&lt;/span&gt; &lt;span style=&quot;font-size: 19px;&quot;&gt;抗腐蚀&lt;/span&gt; &lt;span style=&quot;font-size: 19px;&quot;&gt;使用寿命长&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 19px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;span style=&quot;font-size: 19px;&quot;&gt;接电方便&lt;/span&gt; &lt;span style=&quot;font-size: 19px;&quot;&gt;搭载多种轻型汽车&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 19px; font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;;&quot;&gt;&lt;span style=&quot;font-size: 19px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;', '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;型号： YG-30000 型聚乙烯撒布机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;外形尺寸： 286cm 长 x1300cm 高 x1380cm 宽&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;撒布机净重： 322Kg&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;料斗容积 ：3m³/3300kg&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;撒布介质：盐、沙子、颗粒石子、融雪剂&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;料斗材质：聚乙烯&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;进料机制：内部螺旋绞龙传送，可调速度（16CM 螺旋外径*23CM 螺旋间距）&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;最大进料：每分钟 0.06 立方&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;齿轮箱减速比：1:80&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;出料马达：大扭矩 DC12V（24V 可选）&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;甩盘：36.8cm 聚酯&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;撒布宽度：0.6-12 米&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;V 型槽：不锈钢&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;可调挡板：聚酯材质&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;绞龙电机：800W(12V24V)&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;撒布电机：300W(12V24V)&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;接收器挂钩：4 类&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;甩盘总成：便于拆卸&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;控制装置：双变速控制，带防爆功能和过载保护&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;最小车厢长度：168CM&lt;/span&gt;&lt;/p&gt;', '[\"211\",\"210\",\"212\",\"213\"]', '297', '2', '1478', '2');
