ot;Apple Color Emoji&amp;quot;, &amp;quot;Segoe UI Emoji&amp;quot;, &amp;quot;Segoe UI Symbol&amp;quot;, &amp;quot;Noto Color Emoji&amp;quot;; text-align: start; white-space: normal; display: table-cell; flex: 0 1 auto; flex-direction: row; justify-content: normal; align-items: normal; padding: 0px; margin: 0px; background: none; word-break: break-all;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;三维控制系统、复杂曲面适应能力、品牌知名度&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/202601/5bcfe2589595805.jpg&quot; title=&quot;QQ截图20260113173611&quot; alt=&quot;QQ截图20260113173611&quot;/&gt;&lt;/span&gt;&lt;/p&gt;', '&lt;h3 style=&quot;color: rgb(31, 35, 41); font: 16px / 24px ui-sans-serif, system-ui, sans-serif, &amp;quot;Apple Color Emoji&amp;quot;, &amp;quot;Segoe UI Emoji&amp;quot;, &amp;quot;Segoe UI Symbol&amp;quot;, &amp;quot;Noto Color Emoji&amp;quot;; font-size: 16px; font-weight: 400; line-height: 24px; text-align: start; white-space: normal; display: block; flex: 0 1 auto; flex-direction: row; justify-content: normal; align-items: normal; padding: 0px; margin: 0px; background: none; background-color: rgba(0, 0, 0, 0);&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;激光摊铺机维护保养指南：&lt;/span&gt;&lt;/h3&gt;&lt;h4 style=&quot;color: rgb(31, 35, 41); font: 16px / 24px ui-sans-serif, system-ui, sans-serif, &amp;quot;Apple Color Emoji&amp;quot;, &amp;quot;Segoe UI Emoji&amp;quot;, &amp;quot;Segoe UI Symbol&amp;quot;, &amp;quot;Noto Color Emoji&amp;quot;; font-size: 16px; font-weight: 400; line-height: 24px; text-align: start; white-space: normal; display: block; flex: 0 1 auto; flex-direction: row; justify-content: normal; align-items: normal; padding: 0px; margin: 0px; background: none; background-color: rgba(0, 0, 0, 0);&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1. 日常保养（每日作业前后）&lt;/span&gt;&lt;/h4&gt;&lt;ul style=&quot;color: rgb(31, 35, 41); font: 16px / 24px ui-sans-serif, system-ui, sans-serif, &amp;quot;Apple Color Emoji&amp;quot;, &amp;quot;Segoe UI Emoji&amp;quot;, &amp;quot;Segoe UI Symbol&amp;quot;, &amp;quot;Noto Color Emoji&amp;quot;; font-size: 16px; font-weight: 400; line-height: 24px; text-align: start; white-space: normal; display: block; flex: 0 1 auto; flex-direction: row; justify-content: normal; align-items: normal; padding: 0px; margin: 0px; background: none; background-color: rgba(0, 0, 0, 0);&quot; class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;清洁整平头、激光接收器窗口，确保无混凝土附着影响信号接收&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;检查液压油位、燃油位、发动机机油位，确保在标准范围内&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;检查各连接螺栓紧固情况，特别是整平头与机架连接处&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;清洁空气滤清器，避免灰尘进入发动机&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;检查激光发射器水平状态，确保基准面准确&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;h4 style=&quot;color: rgb(31, 35, 41); font: 16px / 24px ui-sans-serif, system-ui, sans-serif, &amp;quot;Apple Color Emoji&amp;quot;, &amp;quot;Segoe UI Emoji&amp;quot;, &amp;quot;Segoe UI Symbol&amp;quot;, &amp;quot;Noto Color Emoji&amp;quot;; font-size: 16px; font-weight: 400; line-height: 24px; text-align: start; white-space: normal; display: block; flex: 0 1 auto; flex-direction: row; justify-content: normal; align-items: normal; padding: 0px; margin: 0px; background: none; background-color: rgba(0, 0, 0, 0);&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;周期性保养（按工作小时）&lt;/span&gt;&lt;/h4&gt;&lt;table&gt;&lt;thead style=