INSERT INTO `dr_1_xinwenzhongxin` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `xinwenzuobian`, `xinwenyoubian`) VALUES
(211, 9, '豫工机械2023收官大战燃情启动         ', '912', '', '这里是荣誉的殿堂，这里是梦想的舞台，这里是成功的摇篮。2023年12月12日，郑州豫工机械营销中心，200多名员工齐聚一堂，共同开启豫工金秋表彰暨丰年之战启动会。金色的王冠，丰厚的奖金，奋进的感言，豫工金秋大战优秀表彰，遇见豫工 誉见自己。在豫工，从来不乏闪闪发光的人，他们专注自信热情热爱，在豫工的每一天，他们勇于突破 、勇敢成就，为目标 全力以赴，为成功 所向披靡！金秋大战期间，他们在奋斗的路上', 1, 1, '创始人', 9, '/show-211.html', 0, 0, '39.96.59.7-47142', 1709279383, 1709343144, 0, NULL, NULL),
(212, 9, '复工啦！豫工机械为全体员工发放高额福利！                 ', '879', '', '秋高气爽、云开疫散，豫工机械全面复工复产，红包不断，为员工发放高额生活补贴，首批8万元复工红包已发放完毕。      适逢豫工金秋大战，叠加双11嗨购节，您的VIP专属红包已备好，超级钜惠，重磅加码，感谢广大新老客户一直以来的信任和支持，诚心相邀“，郑”等您来。  河南豫工机械是国内工程设备生产基地，拥有18年服务经验，公司规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施', 1, 1, '创始人', 9, '/show-212.html', 0, 0, '39.96.59.7-47150', 1709279383, 1709343164, 0, NULL, NULL),
(213, 9, '2023新年庆典，豫工达人秀惊喜上线！                 ', '963', '', '岁末将至，豫工机械2023新年庆典，欢乐上线。今天不谈工作，不谈业务，只谈“笑”“疯”声，红包、奖品、表彰，歌曲、小品、舞蹈，好事扎堆 快乐排队！优秀员工表彰，红包不停，礼品不断，荣誉感十足 幸福感爆棚......好嗨哟，感觉人生已经达到了巅峰！  看！这不就是努力的意义嘛！忙有所得 耕有所获，走路带风 眼神坚定，每根头发都散发着自信的光芒，内心富足 自律自强，有所忙有所爱有所期待！   才艺展示', 1, 1, '创始人', 9, '/show-213.html', 0, 0, '39.96.59.7-47158', 1709279384, 1709344114, 0, NULL, NULL),
(214, 9, '豫工机械旺春大战火热启动                 ', '964', '', '伴随着恢弘的音乐，豫工人满怀信心，火热开启，2023旺春大战启动会！作为一年一度的重头戏，豫工人最重要的日子，每个人精致妆容，盛装出席，大有与三月争春的劲头，只有额头上的红头巾，写着“赢战旺春”“舍我其谁”的宣言，时刻提醒我们，这是一场时间紧、任务重的百天大战（2023.3.1-6.15）。音乐停止，国内事业部成员入场就坐，200多位豫工人齐聚一堂，火热开启，2023旺春大战启动会。   本次大会', 1, 1, '创始人', 9, '/show-214.html', 0, 0, '39.96.59.7-47166', 1709279384, 1709344126, 0, NULL, NULL),
(215, 9, '豫工机械十八周年庆典隆重举行                 ', '1244', '', '春余夏首 微风习习,2023.6.21,豫工机械十八周年庆典隆重开启,索菲特国际酒店 五星级会议大厅,公司总部300多人盛装出席,共同见证豫工发展高光时刻!    辉煌大厅别具匠心,签名墙精心布置,留下了豫工人自信优雅的身影!一张张喜逐颜开的笑脸,一幅幅轻松融洽的合影,让豫工人的心更牢固地粘在一起!        在欢快动感的舞蹈中，庆典拉开序幕,豫工人活力四射 舞力全开，上演才艺大比拼。宫廷风', 1, 1, '创始人', 9, '/show-215.html', 0, 0, '39.96.59.7-47174', 1709279384, 1710126199, 0, NULL, NULL),
(216, 9, '豫工机械秋日团建 连云港三日游                 ', '957', '', '工作中乘风破浪，生活中多姿多彩，2023年8月18日，豫工机械2023秋季团建，三天两夜 欢乐启程。4辆豪华大巴满载我们的快乐奔赴美丽连云港，游山观海 不负时光，一起感受港城的秋天。  打卡羊山岛，渔村情调 潮声灌耳，感谢豫工的贴心安排，让我们一起，来一场诗和远方的浪漫。    敢问路在何方，路在脚下......，走进现实版的花果山，洞天福地 人间仙境，感受心中的桃花源。45°的侧脸很好看，45°', 1, 1, '创始人', 9, '/show-216.html', 0, 0, '39.96.59.7-47182', 1709279385, 1709344082, 0, NULL, NULL),
(217, 9, '99公益日丨豫工邀您一起献爱心！                 ', '959', '', '“99公益日”来临，豫工机械作为常年热心公益的爱心企业，特发起2022年度“99公益日”助力“困境儿童守护计划”公益募捐活动，携手助童 共护成长。即日起至9月9日，您的每一笔捐款，豫工机械将进行1：1金额的“陪捐”！也就是你捐多少，我公司会“陪捐”多少！“薅羊毛”式捐赠，为爱加油！积小善，成大爱 捐助10元，可以帮助一个孩子解决一天的生活补助； 捐助20元，可以帮助孩子买一本课外书； 捐助100元', 1, 1, '创始人', 9, '/show-217.html', 0, 0, '39.96.59.7-47192', 1709279385, 1709344093, 0, NULL, NULL),
(218, 9, '豫工机械17周年庆典，巅峰时刻 群星闪耀                 ', '961', '', '2022年6月18日 中都大酒店，豫工机械17周年庆典暨第二届女神节隆重举行，总部营销中心300多人参加活动，现场星光璀璨 精彩纷呈！董事长开幕式致辞李总表示：豫工17年高速发展与科学的规划密不可分，立足长远，计划落地。未来，公司还要继续练内功，强本领，做规划！做精、做深、做强主营业务，为客户提供不可替代的服务和价值!  2022旺春大战颁奖典礼柔肩担重任  巾帼绽芳华，旺春大战期间，豫工人执着于', 1, 1, '创始人', 9, '/show-218.html', 0, 0, '39.96.59.7-47200', 1709279385, 1709344104, 0, NULL, NULL),
(219, 9, '福利！豫工端午全家福新鲜出炉                 ', '955', '', '美好恰逢其时，生活与“粽”不同，端午如期而至，豫工的福利也一如往昔，丰厚 健康 贴心！两箱粽子，一箱火龙果，一箱哈蜜瓜，沉甸甸的感觉，像极了豫工对家人的关爱，感谢大家为公司发展的辛勤付出！因为有你，所以出粽，2022是不平凡的一年，因为大家的不懈努力，豫工在充满机遇与挑战的市场竞争中，逆势而来 强势崛起！一粽传情，浓情端午，一盒盒精致的端午礼品，承载了公司对大家满满的关怀，代表着公司对全体员工的真', 1, 1, '创始人', 9, '/show-219.html', 0, 0, '39.96.59.7-47208', 1709279386, 1709344069, 0, NULL, NULL),
(220, 9, '豫工机械2022团建欢乐启程                 ', '954', '', '生活不止眼前的工作，还有静下来的诗意和远方，2022年8月13日，伴着动感的音乐，踏着欢快的节拍，豫工机械2022主题团建第一趴，快乐出发！  感谢公司的贴心安排，本次团建以部门为单位，自主规划活动路线，漂流、爬山、温泉、轰趴、划船......各赴人间惊鸿宴，一睹人间盛世颜！        打卡云上牧场，感受风的温柔，体验花的浪漫，听蝉鸣鸟叫，看蝴蝶纷飞，再和天空来一张合作！        生活中', 1, 1, '创始人', 9, '/show-220.html', 0, 0, '39.96.59.7-47326', 1709279413, 1709344047, 0, NULL, NULL),
(221, 9, '豫工旺春大战启动会燃情启动                 ', '949', '', '2022年2月22日，豫工机械“如虎添亿，奋战51”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工200多人参加此次活动！2021，在豫工人的共同努力下，公司全年销售总额再破3亿元大关，品牌知名度、市场接受度、老客户返单率、生产总值、团队业绩再创新高。期间，公司涌现出了众多业绩精英、营销达人、优秀团队、百万英雄。她们8小时内求生存，8小时外求发展，每一天、每一分钟，都在', 1, 1, '创始人', 9, '/show-221.html', 0, 0, '39.96.59.7-47334', 1709279414, 1709344006, 0, NULL, NULL),
(222, 9, '飒！豫工机械金秋大战燃情启动                 ', '950', '', '2022年9月14日，豫工机械营销总部，金秋大战在国内事业部率先启动，近200名员工斗志昂扬，众志成城，正式打响金九银十决胜战！总结过去，赢战未来，表彰卓越，见证辉煌在热烈的掌声中，优秀代表纷纷登台，荣誉和鲜花，是对他们最大的鼓舞和肯定。在金九银十关键节点，豫工机械金秋大战也如期而至，作为公司2022年51工程（2022年销售额突破5个亿）的关键一战，本次启动会既要制定目标、分解过程，更要为营销团', 1, 1, '创始人', 9, '/show-222.html', 0, 0, '39.96.59.7-47342', 1709279414, 1709344016, 0, NULL, NULL),
(223, 9, ' 豫工机械发福利了，中秋快乐！                 ', '951', '', '中秋节发福利了！红红火火的包装，至诚至爱的心意，节礼在手，温暖在心，感谢公司一如既往的厚爱！ 作为国人重要的传统佳节，每年中秋，公司都会精心准备节日贺礼，感谢大家一年来的努力与付出，希望每一位员工都能与家人，阖家团圆，把酒言欢，满满的仪式感，引来隔壁公司羡慕的眼光。   心怀感恩 所遇皆温柔，公司满满的关爱，不仅让豫工人找到归属感，也让背后的家庭对豫工好感度俱增，多年工作下来，他们都成了最合格的豫', 1, 1, '创始人', 9, '/show-223.html', 0, 0, '39.96.59.7-47350', 1709279414, 1709344035, 0, NULL, NULL),
(224, 9, '豫工机械通过ISO9001-2016国际管理体系认证                 ', '945', '', '河南豫工机械是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目', 1, 1, '创始人', 9, '/show-224.html', 0, 0, '39.96.59.7-47358', 1709279415, 1709343953, 0, NULL, NULL),
(225, 9, '您的中秋贺礼已发货！请注意查收！                 ', '946', '', '金色九月，喜迎中秋!豫工机械为答谢新老客户的支持和厚爱，精心定制中秋贺礼800份,已包装完毕，即将发货！刚刚过去的两个月，郑州人过得极不容易,先抗洪灾、又战疫情,幸运的是，有像您这样一群老朋友新伙伴的一路相伴,豫工人才能凭借勇敢无畏的干劲，排除万难，顺利闯关!7月抗汛,赈灾义卖,!筹款30万捐向灾区8月抗疫，涝疫补贴,每人500元中秋佳节将至，金九银十已来，为答谢您一如既往的信任和支持，除中秋贺礼', 1, 1, '创始人', 9, '/show-225.html', 0, 0, '39.96.59.7-47366', 1709279415, 1709343964, 0, NULL, NULL),
(226, 9, '豫工机械金秋大战燃情启动                 ', '947', '', '2021年9月11日，豫工机械“2021金秋大战暨旺春优秀表彰” 燃情启动，郑州总部营销中心，全体员工180多人参加活动！国内事业部活动现场国际事业部活动现场旺春大战优秀表彰2个月前，公司旺春大战圆满收官，诞生了许多业绩标兵、百万英雄、服务之星、优秀团队，今天是见证荣誉的时刻！ 国内事业部旺春英雄奖 国内事业部捷报奖国际事业部旺春英雄奖国际事业部旺春达人奖国际事业部旺春捷报奖优秀个人表彰在豫工，从', 1, 1, '创始人', 9, '/show-226.html', 0, 0, '39.96.59.7-47374', 1709279415, 1709343978, 0, NULL, NULL),
(227, 9, '豫工机械2021中秋节放假通知                 ', '948', '', '金秋九月，花好月圆，又是一年中秋时！河南豫工机械有限公司根据国假办放假规定，结合公司实际情况，中秋节放假安排如下：  放假时间：2021年9月19-21日，共三天。9月22日（周三）正式上班 温馨提示   1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。2、各部门根据公司放假通知，安排好假期工作；工厂', 1, 1, '创始人', 9, '/show-227.html', 0, 0, '39.96.59.7-47384', 1709279415, 1709343990, 0, NULL, NULL),
(228, 9, '豫工机械2021国庆放假通知                 ', '943', '', '神州大地，举国欢庆！山河壮丽，岁月峥嵘！江山不老，祖国常青！豫工机械祝福我们的祖国繁荣昌盛十一国庆节来了，根据国家放假规定，结合公司实际情况，河南豫工机械有限公司2021年国庆放假安排如下： 注意事项 1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。2、各部门根据公司放假通知，安排好假期工作；工厂仓库', 1, 1, '创始人', 9, '/show-228.html', 0, 0, '39.96.59.7-47392', 1709279416, 1709343899, 0, NULL, NULL),
(229, 9, '豫工两台湿喷台车助力中铁隧道局开工大吉!                 ', '944', '', '2022年3月31日，在豫工机械生产车间，两台3017型湿喷台车完成最后的装配，成功下线，通过严格功能检测，即将发车！它们将用于中铁隧道局宜兴铁路ZQ-3标隧道喷浆支护项目。作为3月的第49、50台喷浆支护系列设备，它的成功发车，意味着豫工机械喷浆支护设备3月销量再创新高。这台外形酷似机械手臂的升级版全机械化液压湿喷台车，与常规型液压湿喷机相比，工作效率提升2倍，轻松达到30㎥/h，而且，机械化程', 1, 1, '创始人', 9, '/show-229.html', 0, 0, '39.96.59.7-47400', 1709279416, 1709343943, 0, NULL, NULL),
(230, 9, '豫工机械通过企业AAA诚信认证                 ', '942', '', '河南豫工机械是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目</h2>', 1, 1, '创始人', 9, '/show-230.html', 0, 0, '39.96.59.7-47434', 1709279425, 1709343831, 0, NULL, NULL),
(231, 9, '五一劳动节 ，豫工机械放假通知                 ', '939', '', '在这个世界上，有这么一群人，他们不是叱咤风云的英雄，不是风光无限的明星，也不是天赋异禀的能人。他们只是热爱生活的普通人，是努力生活在平凡世界中的每一个人。在即将到来的五一劳动节，豫工机械向所有平凡又非凡的劳动者致敬！愿你们都能以全力以赴的热忱，过梦寐以求的生活！河南豫工机械五一放假通知根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，劳动节放假安排如下：1、2021年劳动节', 1, 1, '创始人', 9, '/show-231.html', 0, 0, '39.96.59.7-47444', 1709279426, 1719979963, 0, '1', '1'),
(232, 9, '豫工机械16周年庆典暨第一届女神节                 ', '940', '', '2021年5月21日，郑州禧逸酒店会议大厅，豫工机械“保持热爱，共赴山海”16周年庆典暨第一届女神节欢乐开启，总部营销中心全体员工220多人参加了此次活动。生日趴在众人的生日祝福中，董事长李总为大家分切蛋糕，开启今天的活动庆典。    迎新环节16年开拓创新，争先、争勇、争光，创新、创业、创享,收获累累硕果！公司焕发的强大活力，不断吸引众多行业精英的加入！为让新入职小伙伴尽快融入集体，公司精心准备', 1, 1, '创始人', 9, '/show-232.html', 0, 0, '39.96.59.7-47452', 1709279426, 1709343809, 0, NULL, NULL),
(233, 9, '赞！豫工端午福利多，老板实力宠员工！                 ', '941', '', '端午来啦！老板实力宠员工2盒粽子，2箱水果啧啧......豪横，果然是中国好老板！  丰厚的节日福利是公司对中国文化的传承更体现了对豫工家人细致入微的关怀其实，每逢传统佳节公司都会为客户朋友和豫工家人精心准备节日贺礼这个习惯，豫工一干就是16年！    福利发放现场，欢声笑语！大家暂时放下手中繁忙的工作，聚在一起，享受节日的快乐！  国内事业部员工风采国际事业部员工风采今年端午，赶上公司16周年庆', 1, 1, '创始人', 9, '/show-233.html', 0, 0, '39.96.59.7-47460', 1709279426, 1709343820, 0, NULL, NULL),
(234, 9, '豫工机械2021端午节放假通知                 ', '936', '', '豫工机械五一放假通知根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，端午节放假安排如下：1、2021年端午节放假共3天，时间为2021年6月12日至6月14日，6月15日（星期二）正常上班。2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。3、各部门根据公司放假通知，安排好假期', 1, 1, '创始人', 9, '/show-234.html', 0, 0, '39.96.59.7-47468', 1709279427, 1719990213, 0, '1', '1'),
(235, 9, '豫工机械为河南灾区捐赠的4车物资发车                 ', '937', '', '7月23日，豫工机械通过郑州西峡商会捐赠的12.8万元善款，已筹集4辆车的救灾物资，在河南红十字会的统一调配下，发往灾区！董事长李红旗先生携部分员工代表，义工一天，帮忙装车！7月20日，台风“烟花”携带的强降雨席卷郑州，千年不遇的降雨量令河南1300万人民群众的生命和财产遭受巨大的损失，全国 各省市兄弟单位星夜驰援。董事长李红旗先生第一时间捐款12万元用于抗洪救灾。', 1, 1, '创始人', 9, '/show-235.html', 0, 0, '39.96.59.7-47476', 1709279427, 1770691398, 0, '1', '1'),
(236, 9, '燃！豫工液压湿喷机助战郑州地铁建设                 ', '938', '', '2021年2月6日，豫工售后与技术支持部乔工来到水利七局项目工地——郑州地铁8号线五龙口地铁口，安装调试液压湿喷机。订购单位中国水电7局，隶属于中国电建，承建郑州地铁8号线建设项目。 客户对喷射距离、产品质量、售后服务非常看重，曾亲自到工厂考察，对工厂生产实力、产品品质很放心。 客户所选机型为90型单喷头液压湿喷机，具有泵送压力大、输送距离远、回弹率低、施工效率高等优势，生产能力7㎥/h,配合空压', 1, 1, '创始人', 9, '/show-236.html', 0, 0, '39.96.59.7-47486', 1709279427, 1719990304, 0, '1', '1'),
(237, 9, '豫工大型中秋福利现场，堪比红毯走秀                 ', '933', '', '中秋佳节，豫工的福利真是.......这是老板要向我们表白吗？福利发放现场，大家暂时放下手中繁忙的工作，聚在一起，享受节日快乐一份中秋礼品代表一份美好的祝福，传递出豫工对大家浓浓的关爱，这里不仅是豫工人的发展平台，更是豫工小伙伴们相亲相爱的大家庭。 报道称,中秋圆月将出现在10月2日,国庆、中秋喜相逢,有人说：今年国庆和中秋是用来弥补春节遗憾的,国兴、家睦、月明,祖国快乐、月亮快乐、你我也快乐 满', 1, 1, '创始人', 9, '/show-237.html', 0, 0, '39.96.59.7-47494', 1709279428, 1711597241, 0, NULL, NULL),
(238, 9, '一粽传情 快乐端午，豫工机械端午福利多                 ', '934', '', '端午粽飘香，欢乐事儿忙！为迎接端午佳节的到来，表达公司对员工的关爱，2020年6月22日，按照公司惯例，豫工机械提前为大家发放暖心福利，表达节日问候。豫工历来重视中华民族的传统节日，自公司成立至今十五年间，每年节假日都会给员工发放节日福利，更是把大家当家人看待，感谢大家一直以来的辛勤付出，共享企业发展的成果。端午历来有消灾去病的习俗。在北京疫情依然严峻的形势下，豫工借五月端午，祝愿大家迎祥纳福，辟', 1, 1, '创始人', 9, '/show-238.html', 0, 0, '39.96.59.7-47502', 1709279428, 1711597241, 0, NULL, NULL),
(239, 9, '豫工收官启动，秒变大型跨年晚会现场                 ', '935', '', '2020年12月21日，在郑州总部营销中心，豫工机械金秋表彰暨收官大战启动仪式火热开场，全体员工180多人参加活动。迎新环节虽历15年，豫工依然保持高速发展状态，员工队伍不断壮大。为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家打开自己，融入团队。  金秋大战60天，在豫工人的共同努力下，拿下了2020年同期棒的成绩，销售业绩突破3700万。其中，老客户返单率直线飙升，突破52%。 大', 1, 1, '创始人', 9, '/show-239.html', 0, 0, '39.96.59.7-47510', 1709279428, 1711597241, 0, NULL, NULL),
(240, 9, '豫工机械售后热情服务获赞誉，客户感激送锦旗', '929', '豫工售后,豫工机械,售后服务', '客户服务无小事！江西武吉高速九岭山隧道，客户第一次使用液压湿喷机，售后人员耐心讲解，获客户由衷感谢。豫工机械致力于服务是公司核心竞争力的打造，客户至上，服务如一！本次客户订购的是豫工单喷头液压湿喷机表现出色，生产能力7 m3/h ，搭配16立方空压机，输送距离可达100米，喷射混凝土密实、匀质、高强度，效果、效率远超客户预期。', 1, 1, '创始人', 9, '/show-240.html', 0, 0, '39.96.59.7-47544', 1709279435, 1775888601, 0, '1', '1'),
(241, 9, '豫工特邀消防部门宣讲消防安全知识                 ', '930', '', '安全生产 消防为先，8月4日下午4点，豫工机械开展消防安全讲座。公司特邀河南省护民防火中心祝教官，前往总部营销中心，为大家讲解消防安全知识，全体员工140多人参加。祝教官对近年发生的火灾以图片、视频的形式提高大家消防安全意识，从贴近生活，实用性强的单位、家庭用气、用电、夏季汽车自燃等方面入手，讲解消防知识，和火灾初期如何灭火的方法，提高大家防灾减灾能力！ 祝教官现场演示灭火器“一摇、二拔、三瞄、四', 1, 1, '创始人', 9, '/show-241.html', 0, 0, '39.96.59.7-47552', 1709279435, 1711597241, 0, NULL, NULL),
(242, 9, '豫工机械北京团建欢畅启程                 ', '931', '', '战前OUTING豫工机械一年一度的金秋大战即将拉开序幕，为了让大家以更好的状态决战金秋，公司组织小伙伴们畅游北京，三天两夜的行程，大家放空自己，调整状态，争取打出牛的战绩！    豫工机械金秋大战于每年9月15日-11月15日期间举行，与旺春大战（每年3月16日-6月30日）一样，公司将采取各种促销活动让利客户，有求必应做好售后服务，保证在金九银十的工程建设旺季，为广大客户朋友提供高品质、高性价比', 1, 1, '创始人', 9, '/show-242.html', 0, 0, '39.96.59.7-47560', 1709279435, 1711597241, 0, NULL, NULL),
(243, 9, '旅游团建｜豫工的小姐姐，你笑起来真好看                 ', '932', '', '7月18日，河南豫工机械,“认真工作，快乐生活”主题团建欢畅启程!豫工的小伙伴们集合完毕,乘坐两辆舒适的大巴向云台山进发,这次我们不谈工作，不谈业务,只谈...笑风生!  大家一路欢声笑语,工作严谨认真，生活中却不乏开朗活泼,能干会玩，是我们的标签太行山把美的一段给了河南！焦作云台山，山美 水美 云美 泉美!还有豫工的小姐姐更美！美得不像话!!!大家来到小寨沟，这里被称为北方九寨沟!三步一泉，五步', 1, 1, '创始人', 9, '/show-243.html', 0, 0, '39.96.59.7-47568', 1709279435, 1711597241, 0, NULL, NULL),
(244, 9, '好嗨哟！豫工机械旺春大战盛大启动                 ', '913', '', '2021年2月27日，豫工机械“春风十里，不如有你”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工180多人参加此次活动！      豫工小姐姐化身舞林高手，精彩演绎提神洗脑神曲，可可爱爱，奇奇怪怪，换个舞台，依旧是灯光下耀眼的小姑娘        2020年，在全体豫工人的共同努力下，全年销售总额突破亿元大关;品牌知名度、市场接受度、老客户返单率直线飙升，综合上升9.', 1, 1, '创始人', 9, '/show-244.html', 0, 0, '39.96.59.7-47576', 1709279436, 1709343152, 0, NULL, NULL),
(245, 9, '以色列客户考察豫工锚固钻车', '927', '锚固钻车                ,豫工锚固钻机,锚杆钻机', '经过邮件来往沟通，2020年4月29日，以色列客户来我司工厂参观考察 国外以色列客户来访，要目的是为了商讨豫工锚固钻机后续大批量订单交期及质量控制事宜。  经过多次的沟通，该客户对我司有了更深更好的了解。经过此次会谈，我们产品的技术和质量，价格优势，订单交期，服务方面得到了客户的认可，客户表示将与河南豫工机械长期订单合同，同时客户还表达豫工机械将成为自己核心的供用商。', 1, 1, '创始人', 9, '/show-245.html', 0, 0, '39.96.59.7-47584', 1709279436, 1769827207, 0, '1', '1'),
(246, 9, '豫工机械第八届司庆日暨表彰大会                 ', '928', '', '2020年5月18日，河南豫工机械第八届司庆日暨表彰大会在郑州禧逸酒店隆重召开。首先豫工生日趴，小伙伴们和主持人一起齐声祝福“河南豫工，生日快乐”。这时灯光熄灭，伴随着生日快乐歌，我们的大蛋糕上场了，大家热情高涨的唱着生日歌，歌声刚落下，我们的小伙伴们就向着蛋糕蜂拥而上，蛋糕的香甜味道弥漫在会场的上空，整个大厅都沉浸在一片欢乐的海洋……分享完蛋糕，接下来是我们的年度表彰环节，首先是我们2019年度', 1, 1, '创始人', 9, '/show-246.html', 0, 0, '39.96.59.7-47592', 1709279436, 1709343432, 0, NULL, NULL),
(247, 10, '高速公路车载式绿篱修剪机多少钱？', '925', '', '车载绿篱修剪机的价格一直是每个客户关心的问题，但是，目前国内绿篱修剪机生产厂家众多，竞争激烈，各厂家会定期推出优惠政策，给出的报价不一！另外，市场平均价格水平，配置型号，安装调试，运送距离，发票等因素，都会影响产品最终报价！公路绿篱及边坡灌木修剪专用设备在没有绿篱修剪机之前，都是通过人工修建的方式，这种方式的缺点非常明显，不仅效率低下，而且也存在一定的安全问题，所以绿化带修剪机的出现，不仅解决了这', 1, 1, '创始人', 9, '/show-247.html', 0, 0, '39.96.59.7-48390', 1709280900, 1709343394, 0, NULL, NULL),
(248, 10, '桥面抛丸机有那些型号？多少钱一台？     ', '926', '抛丸机,路面抛丸机,移动抛丸机', '混凝土路面抛丸机能够一次将混凝土表面的浮浆、杂质清理和清除干净，最重要的是在同时对混凝土表面进行了打毛处理，使其表面均匀粗糙，大大提高防水层和混凝土基层的黏结强度。', 1, 1, '创始人', 9, '/show-248.html', 0, 0, '39.96.59.7-48398', 1709280900, 1769396307, 0, '1', '1'),
(249, 10, '豫工22头机载凿毛机多少钱？', '924', '凿毛机,机载凿毛机,22头机载凿毛机', '混凝土凿毛机是一种把已经完成的主体结构面进行处理，使两个施工阶段的施工面粘结牢固的类似于&quot;斩斧&quot;的工具。通常凿毛机是应用在在现浇混凝土结构中，在现浇板浇注完毕后，要凿毛，进行下一层的浇注，让混凝土粘结牢固。', 1, 1, '创始人', 9, '/show-249.html', 0, 0, '39.96.59.7-48406', 1709280900, 1769503129, 0, '1', '1'),
(250, 10, '智能张拉设备不可忽视的几点 ', 'http://www.zzyugong.cn/uploadfile/202311/a83e7b70d411899.jpg', '', '智能张拉设备在进行张拉作业之前，除了要对张拉设备的构件进行检验，还有几个不能忽视的地方，一起来看一下吧。1、开机后如果发现主从控制柜通讯不上的问题，需要先检查通讯线是否连接正常或有断线，如果没有需要重新启动系统。2、在张拉过程中油管和控制电缆要顺直，不得扭曲打卷，防止扯断油管和电缆。3、在张拉过程中如果出现问题应首先按下控制柜面板上“油泵停止“按钮，不能强行继续张拉。4、在移动设备的过程中，泵站、', 1, 1, '创始人', 9, '/show-250.html', 0, 0, '39.96.59.7-48414', 1709280901, 1709343171, 0, NULL, NULL),
(251, 10, ' 什么是预应力机械？一分钟了解预应力   ', 'http://www.zzyugong.cn/uploadfile/202311/1095bf2790d3ce0.jpg', '', '预应力机械顾名思义就是强化产生预应力并进行施工的机械设备，这种机械通常必须要具备产生很大外力的能力，因为受力模块本身通常具有很强的刚度和硬度，普通机械很难起到作用，预应力机械便发挥了作用。在各种工程结构构件承受外荷载之前,对受拉模块中的钢筋等受力模块，施加预拉应力，提高构件的刚度和硬度，推迟裂缝出现的时间，增加构件的耐久性。对于机械结构来看，其含义为预先使其产生应力，其好处是可以提高构造本身刚性和', 1, 1, '创始人', 9, '/show-251.html', 0, 0, '39.96.59.7-48424', 1709280901, 1709343364, 0, NULL, NULL),
(252, 10, '选购喷播机时都要注意哪些内容呢？   ', '3170', '喷播机,客土喷播机,液力喷播机,喷播植草机', '喷播机是边坡绿化施工的机械设备，它质量的好坏直接影响喷播效率的高低。喷播机主要用于高速公路(铁路）边坡绿化、边坡防护、山体治理、矿山复绿、荒漠治理等工程。', 1, 1, '创始人', 9, '/show-252.html', 0, 0, '39.96.59.7-48432', 1709280901, 1768804084, 0, '1', '1'),
(253, 10, ' 路面抛丸机对混凝土桥面的表面处理工艺      ', '915', '', '欧美国家自20世纪70年代以来在混凝土桥面铺装中广泛使用防水层，大大减少了混凝土桥梁因为渗水的原因而造成的损坏，延长桥梁的使用寿命。但随着交通量的增加，同时出现了防水层和面层以及桥面黏结强度不足而产生推移的病害。在我国，混凝土桥梁也经常发生类似病害，以及由于渗水甚至造成的混凝土疏松、脱落，钢筋锈蚀。造成以上病害的原因之一是因为混凝土面层的处理没有能够完全去除表面残留物质，没有保留一定的粗糙表面来保', 1, 1, '创始人', 9, '/show-253.html', 0, 0, '39.96.59.7-48442', 1709280902, 1709343209, 0, NULL, NULL),
(254, 10, '做防水，选对设备，不花冤枉钱！ ', 'http://www.zzyugong.cn/uploadfile/202311/55bad77d53d0.png', '', '防水早已不再是一个新鲜的话题，不论是隧道、桥梁、堤坝、道路、建筑还是我们日常居住的房屋，防水都不容忽视。相对于老式的防水方式的笨重和繁琐，豫工推出非固化防水材料喷涂设备，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。对于非固化设备的选购，许多人没有眉目。有的人贪图便宜，去买一下低价位的产品，有的人只看外表，购买一些外表看起来很好的机器，其实这些做法都是不正确的，一个合', 1, 1, '创始人', 9, '/show-254.html', 0, 0, '39.96.59.7-48450', 1709280902, 1709343200, 0, NULL, NULL),
(255, 10, '液压铣刨机价格，液压铣刨机有那些型号？    ', '914', '', '目前，液压铣刨机型号比较多，其中，电机款统用18.5KW；300型也有15KW的，300型和350型适合2公分左右、3公分之内铣刨;500型适合半公分左右、1公分左右铣刨等，因施工要求、设备型号、配置差异加大，价格也不尽相同，大部分设备价格在3万-5万左右。液压铣刨机主要型号针对深度铣刨的施工要求，豫工机械热销机型是350型的电动和燃油款，4根轴、大刀片、直径110刀片、数量是76片。500型号的', 1, 1, '创始人', 9, '/show-255.html', 0, 0, '39.96.59.7-48458', 1709280902, 1709343190, 0, NULL, NULL),
(256, 10, ' 三辊路面摊铺机有那些型号，多少钱一台？      ', '916', '路面摊铺机,激光摊铺机', '天气回温，路面施工市场的火热程度也在随之飙升，一众基建项目的开工使得路面摊铺设备出现了供不应求的状况。不少客户朋友来咨询豫工机械关于混凝土摊铺机的型号和情况，那么一台滚轴式摊铺机有哪些型号呢？买一台三辊的摊铺机需要多少钱呢？', 1, 1, '创始人', 9, '/show-256.html', 0, 0, '39.96.59.7-48466', 1709280903, 1769826555, 0, '1', '1'),
(257, 10, '豫工桥面抛丸机防水打毛有那些优势？', '917', '桥面抛丸机,豫工抛丸机', '路面清理打毛是防水喷涂施工前处理的重要环节，那么路面抛丸机在粗化打毛混凝土路面方面有那些优势呢？防水基层处理抛丸机路面抛丸机的抛丸工艺可以一次性将混凝土外表的浮浆，杂质清算洁净，同时对混凝土外表进行打毛处置，使其外表均匀粗糙，大大进步了防水层和混凝土基层的黏结强度。', 1, 1, '创始人', 9, '/show-257.html', 0, 0, '39.96.59.7-48590', 1709280919, 1769398346, 0, '1', '1'),
(258, 10, '超大雾化面非固化喷涂机多少钱一台？', '921', '', '近日，有客户找到豫工机械咨询关于超大雾化扇面非固化喷涂设备的型号及价格的问题。在充分了解了这位客户的施工场景、施工面积、工人数量、项目工期后，豫工产品经理为其推荐了以下几种机型，现将其列出，以供大家参考。客户需求信息项目介绍90000平方地库顶板防水施工喷涂物料非固化橡胶沥青防水涂料现场情况 客户第一次从事防水施工项目，工人无经验！其他需求工期紧，天气炎热，工人室外作业，希望设备高效作业，要求设备', 1, 1, '创始人', 9, '/show-258.html', 0, 0, '39.96.59.7-48598', 1709280920, 1709343323, 0, NULL, NULL),
(259, 10, '什么是预应力机械？一分钟了解预应力    ', '920', '', '预应力机械顾名思义就是强化产生预应力并进行施工的机械设备，这种机械通常必须要具备产生很大外力的能力，因为受力模块本身通常具有很强的刚度和硬度，普通机械很难起到作用，预应力机械便发挥了作用。在各种工程结构构件承受外荷载之前,对受拉模块中的钢筋等受力模块，施加预拉应力，提高构件的刚度和硬度，推迟裂缝出现的时间，增加构件的耐久性。对于机械结构来看，其含义为预先使其产生应力，其好处是可以提高构造本身刚性和', 1, 1, '创始人', 9, '/show-259.html', 0, 0, '39.96.59.7-48606', 1709280920, 1709343308, 0, NULL, NULL),
(260, 10, '智能张拉设备不可忽视的几点 ', '919', '', '智能张拉设备在进行张拉作业之前，除了要对张拉设备的构件进行检验，还有几个不能忽视的地方，一起来看一下吧。1、开机后如果发现主从控制柜通讯不上的问题，需要先检查通讯线是否连接正常或有断线，如果没有需要重新启动系统。2、在张拉过程中油管和控制电缆要顺直，不得扭曲打卷，防止扯断油管和电缆。3、在张拉过程中如果出现问题应首先按下控制柜面板上“油泵停止“按钮，不能强行继续张拉。4、在移动设备的过程中，泵站、', 1, 1, '创始人', 9, '/show-260.html', 0, 0, '39.96.59.7-48614', 1709280920, 1709343296, 0, NULL, '1'),
(261, 10, ' 选购喷播机时都要注意哪些内容呢？     ', '918', '喷播机,客土喷播机,豫工喷播机,液力喷播机', '喷播机是边坡绿化施工的机械设备，它质量的好坏直接影响喷播效率的高低。喷播机主要用于高速公路(铁路）边坡绿化、边坡防护、山体治理、矿山复绿、荒漠治理等工程。因此，用户在购买时，会有很多问题注意。下面我们来看选购喷播机时需要注意哪些事项。', 1, 1, '创始人', 9, '/show-261.html', 0, 0, '39.96.59.7-48622', 1709280920, 1768804269, 0, '1', '1'),
(262, 10, '豫工路面抛丸机对混凝土桥面的表面处理工艺', '923', '抛丸机,豫工抛丸机,路面抛丸机,混凝土抛丸机', '欧美国家自20世纪70年代以来在混凝土桥面铺装中广泛使用防水层，大大减少了混凝土桥梁因为渗水的原因而造成的损坏，延长桥梁的使用寿命。但随着交通量的增加，同时出现了防水层和面层以及桥面黏结强度不足而产生推移的病害。在我国，混凝土桥梁也经常发生类似病害，以及由于渗水甚至造成的混凝土疏松、脱落，钢筋锈蚀。', 1, 1, '创始人', 9, '/show-262.html', 0, 0, '39.96.59.7-48630', 1709280921, 1769397397, 0, '1', '1'),
(263, 10, '做防水，选豫工非固化防水喷涂设备，不花冤枉钱！ ', '922', '非固化喷涂机', '防水早已不再是一个新鲜的话题，不论是隧道、桥梁、堤坝、道路、建筑还是我们日常居住的房屋，防水都不容忽视。相对于老式的防水方式的笨重和繁琐，豫工推出非固化防水材料喷涂设备，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。', 1, 1, '创始人', 9, '/show-263.html', 0, 0, '39.96.59.7-48638', 1709280921, 1769479041, 0, '1', '1'),
(330, 9, '豫工机械端午发福利啦', '1660', '', '端午将至，豫工精心准备厚厚的礼品，送给最“粽”要的人，分享快乐，共迎端午，2箱粽子，两箱水果，甜甜蜜蜜 红红火火，仪式感满满，感谢豫工对我们的厚爱。每逢传统佳节，豫工家人都能收到一份甜甜的祝福，每个人脸上绽放的笑容，是身为豫工人的幸福，并肩作战的日子，平添了更多热爱和坚守！相信这个夏天，我们拼搏的汗水，将会闪耀整个盛夏，我们奋斗的脚步，必然让豫工更出“粽”，祝福豫工越来越好 ，未来宏图大展！为答谢', 1, 2, '豫工机械', 9, '/show-330.html', 0, 0, '123.160.152.20-1383', 1717660652, 1719979952, 0, '1', '1'),
(334, 9, '豫工机械19周年庆典燃爆全场', '1683', '周年庆,豫工机械周年庆,司庆日', '2024年6月20日，河南豫工机械迎来19岁生日！全体员工欢聚一堂，共同见证这一辉煌的时刻！旺春优秀表彰，总结过去 赢战未来 表彰卓越 见证辉煌！刚刚过去的旺春大战，有热情 有汗水 有鲜花 有掌声，豫工人抵住压力 拼搏向上，踏实 努力 灵动 极致，成绩突飞猛进 信心与日俱增。领奖台上王冠耀眼夺目，领奖台下掌声持久不息，炽热如初 脚步如故，每一次平凡的坚守，在这一刻有了具体的意义！年度优秀表彰，豫工', 1, 2, '豫工机械', 9, '/show-334.html', 0, 0, '1.192.2.75-26514', 1719804366, 1719989998, 0, '1', '1'),
(345, 9, '豫工机械与长沙应急局达成80台永磁泵采购意向', '1894', '永磁泵,永磁防汛泵,暴雨,城市排水,防汛排涝', '受厄尔尼诺事件与全球变暖等因素影响，江南中南部到华南中北部一带降雨异常偏多，导致湖南发生了多次强降雨过程。7月5日下午，受长期集中强降雨影响，湖南省岳阳市华容县团洲垸洞庭湖一线堤防发生决口。为应对汛情，湖南应急管理局采购豫工机械永磁防汛泵80台，发往湖南岳阳华容县，提高当地防汛救援效率。客户首先咨询的是豫工柴油防汛泵车，经过深入沟通，客户对于体积小、重量轻、携带便捷，却排水量可观的永磁防汛泵青睐有', 1, 2, '豫工机械', 9, '/show-345.html', 0, 0, '1.192.3.119-8150', 1721715619, 1721716646, 0, '2', '2'),
(346, 9, '豫工机械开展一线员工慰问送清凉活动', '1917', '豫工机械,豫工机械工厂,豫工机械高温慰问', '炎炎夏日，骄阳似火，豫工机械工厂一线员工战高温、斗酷暑，保生产 保质量 保交付！公司总部关爱生产一线，开展情系员工，关爱员工，“送清凉”慰问活动。8月2日，豫工机械总经理与公司主要领导一行来到豫工河南本部生产基地，带来西瓜、毛巾、水杯、矿泉水、藿香口服液等降暑物资，为奋战在高温一线的员工送来清凉关怀。并添置价值10多万元的防暑降温装备，为工人提供更加舒适的工作环境！“来看看大家，你们辛苦了!” “', 1, 2, '豫工机械', 9, '/show-346.html', 0, 0, '123.160.154.171-49355', 1722909351, 1722912554, 0, '1', '1'),
(348, 9, '豫工机械2024团建内蒙古之旅风采合辑', '1978', '公司福利,团建,内蒙古团建', '2024年8月14日-8月18日，豫工机械2024团建第一趴，内蒙古之旅欢乐开启，草原之上 拒绝“蕉绿”，一起去吹一吹自由的风。感谢公司的贴心安排，本次团建以部门为单位，自由选择内蒙古 秦皇岛两条线路，或策马扬鞭 或帆船出海，人间皆是浪漫，奔赴一场诗与远方的美好。选择内蒙古的小伙伴率先出发，开始为期5天的美好之旅，他们乘飞机到达呼和浩特，拥抱这座有温度的草原都市。第一站 5A景区响沙湾，金色沙丘绵', 1, 2, '豫工机械', 9, '/show-348.html', 0, 0, '1.192.1.51-12185', 1724385569, 1724386576, 0, '1', '1'),
(349, 9, '豫工机械2024团建秦皇岛精彩合辑', '1994', '公司团建,公司福利,旅游', '2024年8月15日,工机械2024团建第二趴欢乐启程,伙伴们乘高铁奔向美丽的海滨城市,始为期4天的秦皇岛之旅，aaaaappy的一天。列车即将到达：北戴河，段悠闲的旅程，为一群可可爱爱的人儿，路是风景，一路是欢笑，好！最好的年纪，们因豫工而更加美好。海水清爽 沙滩柔软，起来海边吹吹风，是颜值和美味在线的一天，好喝好玩好，谢豫工的无限宠爱，费旅游，简直不要太幸福。夏天 夕阳 晚风，酒吧 音乐 好友', 1, 2, '豫工机械', 9, '/show-349.html', 0, 0, '1.192.1.51-29408', 1724386607, 1724386607, 0, '1', '1'),
(354, 9, '不怕输，才能赢，豫工机械金秋大战燃情启动', '2087', '金秋大战,豫工机械', '征程未有尽期，行稳方能致远，金九银十 奋进正当时，豫工机械厉兵秣马 赢战金秋。2024年9月20日，金秋大战启动会在国内事业部燃情启动，营销总部200多人齐聚一堂，斗志昂扬，众志成城，正式打响金秋决胜战！全体豫工人整装待发，带着对目标的执着，对事业的热忱，以乘风破浪的勇气，以永不消退的拼劲，赴一场星辰大海的征程。伴随着激昂振奋的音乐，豫工人整装待发，有序入场，一场对豫工人极其重要的大战，正式拉开序', 1, 2, '豫工机械', 9, '/show-354.html', 0, 0, '123.160.153.105-46777', 1727148214, 1727148879, 0, '1', '1'),
(363, 10, '​除雪滚刷的工作原理是什么？', '2179', '除雪滚,除雪滚刷,除雪滚刷工作效率,除雪滚刷价格', '除雪滚刷的工作原理，简而言之，是通过机械旋转与物理刮擦相结合的方式，高效清除道路、停车场等区域的积雪，确保交通顺畅与公共安全。其具体运作机制如下：除雪滚刷通常由一组或多组高强度、耐磨损的刷毛或金属刮板组成，这些部件安装在可旋转的滚筒上。', 1, 2, '豫工机械', 9, '/show-363.html', 0, 0, '123.52.23.105-17208', 1729234667, 1769478798, 0, '2', '2'),
(364, 10, '除雪滚的作业效率与什么有关？', '2184', '除雪滚,除雪滚刷,扫雪机,除雪滚的作业效率', '除雪滚的除雪效率与设计构造起决定性作用。其直径、宽度、除雪滚的材质选择有关', 1, 2, '豫工机械', 9, '/show-364.html', 0, 0, '123.52.23.105-10150', 1729235471, 1729235781, 0, '2', '2'),
(366, 9, '豫工机械2024丰年大战，超燃出征！', '2217', '收官大战,豫工机械', '决战收官，赢战丰年，2024年11月28日，豫工机械2024丰年大战热情启动，郑州总部国内事业部全体成员200人，齐聚一堂，发起年底总攻，50天的火热征程，即将燃情启程！刚刚过去的金秋大战，豫工人以高度的热情投入工作，以品质为先，以服务为本，专业、热情、真心，赢得一个又一个客户的认可，收获了成长与荣誉。他们尽职尽责、勇于担当，他们成绩耀眼 业绩领先，他们凭借过硬的实力登顶巅峰，王冠，奖金，礼品，红', 1, 2, '豫工机械', 9, '/show-366.html', 0, 0, '1.192.1.118-53207', 1733906007, 1733992880, 0, '1', '1'),
(405, 9, '豫工机械2025供应商大会盛大启幕', '2550', '供应商大会,豫工机械,公司年会', '2025年2月19日，豫工机械隆重举办以“‘豫’见未来，‘工’谱新章”为主题的2025供应商大会。这次大会，旨在为豫工机械2025年达成6亿产值提供高品质配件供应，为豫工规模化发展保驾护航。100多个核心供应商厂家，豫工全体高管，相关职能部门负责人，齐聚一堂，共同探讨当前市场环境下，如何提升品质，如何以高质量产品和服务赢得市场，共建互利互信的可持续发展供应链体系，携手开创合作发展新局面。豫工机械董', 1, 2, '豫工机械', 9, '/show-405.html', 0, 0, '123.160.242.143-58104', 1740193944, 1740194174, 0, '1', '1'),
(411, 9, '豫工机械旺春大战火爆开启', '2605', '旺春大战,2025,豫工机械', '春回大地，万象更新。2025年2月28日，豫工机械“AI赋能，智启新篇”旺春启动会隆重开启，这是一场凝聚共识、点燃斗志的盛会，国内事业部200余名精英齐聚，共启2025的辉煌征程。这场开年首战，打的不仅是业绩，更是企业的创新宣言！100天的征程，豫工人将借助AI数字技术，打出豫工发展加速度，将响应效率、产品优势、服务温度全面升级，向旺春大战1亿产值的目标冲锋。这一战，既要赢得漂亮，更要赢得智慧！丰', 1, 2, '豫工机械', 9, '/show-411.html', 0, 0, '123.160.241.175-62234', 1741070138, 1741073124, 0, '1', '1'),
(424, 9, '豫工机械为员工发放端午福利', '2742', '端午福利,豫工机械,端午', '粽情端午 感恩同行夏风裹着粽香又是一年端午至今年的豫工“心意”已就位300多份节日问候准时送达豫工总部4大办公区由主管送到每位家人的手上两盒甜心粽、两盒土特产可甜可咸，诚意满满这波福利真是太赞啦！福利发放现场一片欢乐，一箱箱礼品填满了每个人的办公区大家脸上都笑开了花又是被豫工实力宠爱的一天这就是豫工人的专属浪漫是豫工给“最‘粽’要人”的节日祝福拆盒的惊喜、分享的欢乐每一个被仪式感填满的瞬间好似都在', 1, 2, '豫工机械', 9, '/show-424.html', 0, 0, '123.52.23.132-51250', 1748504490, 1768982450, 0, '1', '1'),
(427, 9, '豫工机械20周年颁奖盛典', '2786', '周年庆典,豫工机械,颁奖典礼', '二十年征途 步履铿锵二十年热血 初心滚烫2025年6月20日，在郑州总部营销中心，豫工机械“保持热爱，筑梦山海”20周年庆典燃情启动，国内事业部200多名员工齐聚一堂，为豫工20周岁生日祝福。20年，是豫工与时代同频的奋斗史诗，从萌芽起航到战略出海，豫工人以品质之笔，以热爱为墨，书写了“让世界爱上河南造”的辉煌华章！本次庆典由三个环节组成，荣耀表彰、股东分红、盛夏誓师，环环相扣，精彩纷呈，点燃了大', 1, 2, '豫工机械', 9, '/show-427.html', 0, 0, '123.160.154.109-50487', 1750745787, 1750747254, 0, '1', '1'),
(441, 10, '如何选到合适的除雪滚型号', '3043', '除雪滚多少钱一台,除雪滚尺寸怎么选,除雪滚型号', '如何选择一台合适的除雪滚，绝不是简单的“看报价、比大小”，而是一场系统性的需求匹配工程。步 匹配在查看任何具体型号前，先回答以下三个问题，它们构成了选型的“黄金三角”：匹配主机：您计划将除雪滚安装在什么设备上？装载机：常用，需明确主机型号、吨位、液压系统流量（升/分钟）和工作压力（兆帕）。这是决定滚刷尺寸和驱动方式的核心。', 1, 2, '豫工机械', 9, '/show-441.html', 0, 0, '123.160.241.6-56330', 1766827088, 1769478655, 0, '1', '1'),
(442, 10, '道路破冰机多少钱一台', '3044', '路面破冰机,道路破冰设备,装载机破冰机', '道路破冰机的价格由其根本类型和应用定位决定，主要分为三大价格梯队：1. 基础功能级（轻型/附属式）价格区间：约 3万 - 15万元人民币设备描述：主要为手推式小型电动或汽油机驱动设备，或可快速挂接于小型拖拉机、装载机的轻型附属装置。', 1, 2, '豫工机械', 9, '/show-442.html', 0, 0, '123.160.241.6-56422', 1766827207, 1769478283, 0, '1', '1'),
(443, 10, '高速公路除雪滚什么价格,才算值?', '3048', '扫雪滚刷,市政道路除雪滚,快速拆装除雪滚', '一台真正“值”的除雪滚到底多少钱？看懂以下三点，您就能跳出“比价陷阱”，做出明智选择', 1, 2, '豫工机械', 9, '/show-443.html', 0, 0, '123.160.241.6-56681', 1766827563, 1768364545, 0, '1', '1'),
(456, 9, '豫工机械2025金秋大战火爆开启！', '3377', '豫工机械,金秋大战', '2025年9月18日，豫工机械“金秋当燃 再启新程”启动会在郑州总部营销中心盛大举行。国内事业部200多人斗志昂扬、气势如虹，共赴一场属于拼搏者的金秋之在激昂的乐曲中，豫工人步伐铿锵、意气风发，依次进入会场。各团队誓言如潮，接力传递，为豫工机械2025金秋攻坚拉开序幕！营销总监卢总监为大会作动员致辞。她强调，金秋大战不仅是业绩的角逐，更是自我超越的征程。她鼓励大家突破极限、重塑自我，在挑战中历练，', 1, 2, '豫工机械', 9, '/show-456.html', 0, 0, '123.160.243.73-64897', 1770101922, 1770103483, 0, '1', '1'),
(457, 9, '豫工机械2025中秋风采特辑欢乐来袭！', '3394', '豫工机械,中秋福利', '中秋未至，祝福已达。有一种幸运叫“豫工福利”，它如春花秋月，夏蝉冬雪总在恰好的时节为我们增添生活的美好。9月26日豫工集团为全体员工送上中秋福利礼盒双份，心意加倍豫工机械、富来机械、豫工严选集团旗下三大业务公司近千名员工深切感受到豫工的祝福礼物甜甜，情意绵绵笑容，绽放脸上温暖，流淌心间中秋的喜悦洋溢在每一个豫工人的眼眸在豫工节日的祝福从未缺席每一份精心准备的礼物都是豫工人踏实前行的底气它让平凡的日', 1, 2, '豫工机械', 9, '/show-457.html', 0, 0, '123.160.243.73-49249', 1770102464, 1770103349, 0, '1', '1'),
(462, 10, '清淤机器人的操作流程', '3487', '清淤机器人,清淤机器人操作视频,900型清淤机器人厂家,自动清淤机器人,清淤设备', '清淤机器人操作流程1、开机前检查清淤机器人和液压动力系统是否有漏油，电缆连接是否有破损、虚接，机械连接部分是否有松动，观察液压油箱油位是否达到指示位置。2、主电缆进入控制电箱是否连接牢固可靠，不得有虚接或缺相。3、将控制箱内主空并断路器合闸，同时观测控制柜控制面板是否有电电压指示显示，确认无误后，即可进行机器人操作。4、手持遥控控制器，调节液压系统溢流阀手轮逆时针调至最小处，松开侧面急停按钮，按下', 1, 2, '豫工机械', 9, '/show-462.html', 0, 0, '123.160.243.73-58460', 1770710247, 1770770404, 0, '1', '1'),
(463, 10, '清淤机器人的常见型号有哪些？', '3489', '清淤机器人的型号,清淤机器人,水下清淤机器人,水下清淤设备,履带式清淤机器人', '清淤机器人是用于河道、水库、管道、市政窨井等场景的智能化清淤装备，目前市场上主流型号主要根据应用场景、技术特点和品牌进行区分。豫工机械清淤机器人根据清淤工作宽度，分为500电动型清淤机器人、600电动型清淤机器人、700电动型清淤机器人、800电动型清淤机器人、900电动型清淤机器人。所有型号均采用履带式行走（速度2km/h）、无线遥控操控，并标配水下LED照明系统，保障在昏暗水下环境的可视性与操', 1, 2, '豫工机械', 9, '/show-463.html', 0, 0, '123.160.243.73-64808', 1770715010, 1770770552, 0, '1', '1'),
(464, 10, '绿篱修剪机工作前的注意事项', '3494', '绿篱修剪机,车载式绿篱修剪机,绿篱修剪机常见故障与维修,绿篱机', '1、开始作业之前，要认真检查机体各部，在确认没有螺丝的松动、漏油、损伤或变形等情况后方可开始作业。特别是刀片以及刀片连接部位更要仔细检查。　　2、确认刀片没有崩刃、裂口、弯曲之后方可使用。绝对不可以使用已出现异常的刀片。　　3.在使用过程中，如果人员离开或者需要转移作业场所，必须先关闭发动机直至刀片停止。4.在通风良好的地方使用绿篱机，因为工作过程中会排放出一氧化碳等有毒气体，千万不要在通风不良的', 1, 2, '豫工机械', 9, '/show-464.html', 0, 0, '123.160.243.73-58098', 1770777545, 1770778128, 0, '1', '1'),
(465, 10, '​避障式修剪机怎样保养维护？', '3496', '避障式修剪机,割草机,避障式割草机,避障式割草机保养方法', '1.剪刀运转累计8-12小时，向转轴部位注满高温润滑脂；2.及时注入#92汽油，应勤检查汽油箱容量，避免油烧干后进入空气后无法启动3.修剪3小时要检查水箱，散热器；适当添加冷却液4.随时检查发动汽油、机油、是否充足；5.长期停放应把主体放在托架上，刀头立起，缩回横臂应盖雨布或放入车库；6.修剪机需专人操作、管理、保养。7、每次工作前要检查刀片固定部分的松动。8、蓄电池连续超过1个月不用，应及时给电', 1, 2, '豫工机械', 9, '/show-465.html', 0, 0, '123.160.242.158-59599', 1770778567, 1770779087, 0, '1', '1'),
(466, 10, '避障式割草机是怎样工作的？', '3499', '', '避障式割草机是一种先进的园艺工具，它通过搭载传感器和导航系统，能够自动识别并避开障碍物，如树木、花坛、步道等，无需人工干预。这种割草机特别适合地形复杂、有多种障碍物的环境，它能够节省用户的时间和精力，提高作业效率，同时降低人工操作的安全风险。1避障式割草机的特点主要包括：高效性：能够快速高效地进行修剪作业，提高工作效率。灵活性：可以上下左右进行调节，全方位修剪，适应不同的修剪要求。省力性：只需要配', 1, 2, '豫工机械', 9, '/show-466.html', 0, 0, '123.160.242.158-61779', 1770780153, 1770780424, 0, '1', '1'),
(467, 10, '推荐几款合适的防汛泵？', '3505', '', '汛期来临，如何选择一台“靠谱”的防汛泵是应对内涝的关键。不同类型的泵适用于不同场景，选对才能高效排水。以下为您推荐几款主流防汛泵，助您精准决策。1. 便携式轻型潜水泵：应急抢险首选代表泵型：高扬程小型潜水电泵（如口径2-4寸），永磁泵等核心优势：重量轻、移动灵活、接电即用。通常采用铝合金机身，坚固耐用。适用场景：地下室、车库、小区低洼处等小范围短时积水抢排。单人即可操作，是家庭和物业应急的“尖兵”', 1, 2, '豫工机械', 9, '/show-467.html', 0, 0, '123.160.242.158-64428', 1770782806, 1770783680, 0, '1', '1'),
(470, 9, '豫工机械2026旺春大战启动会火热启幕', '3568', '豫工机械,旺春大战,豫工集团', '2026年3月5日，豫工集团国内事业部旺春大战启动会火热启幕，128名豫工人聚集一堂，以背水一战的决心，共同吹响旺春大战集结号。国内事业部总经理侯总首先致辞，他回顾了豫工人一路走来的拼搏历程，并发出热情动员：“希望每个豫工人都能在本次旺春大战中，找回初入豫工时的状态——为荣誉全力以赴、为目标拼尽全力”！面对2026的市场发展，侯总勉励大家不忘初心，不惧挑战，继续发扬敢想敢干、敢打敢拼的奋斗精神，不', 1, 2, '豫工机械', 9, '/show-470.html', 0, 0, '123.160.152.182-58803', 1773114917, 1773194935, 0, '1', '1'),
(473, 10, '清淤机器人多少钱一台？', '3598', '清淤机器人,水下清淤机器人,智能水下清淤机器人', '随着城市内涝治理的紧迫性增加以及厂矿企业安全作业要求的提高，清淤机器人正从“新奇玩具”转变为市政管网与工业沉淀池清理的标配装备。然而，对于大多数潜在用户来说，最直接的一个问题往往是：清淤机器人多少钱一台？通过对2026年一季度市场招标数据及行业报告的梳理可以发现，清淤机器人的价格跨度极大，从几万元到上百万元不等，其背后的价值逻辑值得每一位采购者深究。', 1, 2, '豫工机械', 9, '/show-473.html', 0, 0, '123.52.22.14-63272', 1773472128, 1775888985, 0, '1', '1'),
(476, 10, '圆盘处理量能达到多少？怎么选型号？', '3659', '圆盘过滤机,圆盘真空过滤机,陶瓷过滤机,陶瓷盘式过滤机', '圆盘过滤机的处理量没有固定数值，通常按每平方米过滤面积每小时处理0.6-0.85吨干物料估算。以一台过滤面积60平方米的设备为例，每小时可处理36-51吨干料。', 1, 2, '豫工机械', 9, '/show-476.html', 0, 0, '123.52.20.130-51966', 1774857796, 1775894720, 0, '1', '1'),
(477, 10, '清淤机器人技术如何重塑河道治理', '3489', '清淤机器人,清淤机械设备,水下清淤工程,清淤机器人多少钱一台', '传统清淤的困境</h2>河道淤泥堆积是困扰城市水环境治理的长期难题。传统人工清淤方式存在诸多难以回避的弊端：作业人员需要潜入浑浊水底，面临溺水、缺氧、水下生物攻击等多重安全风险；潜水员作业深度通常被限制在20米以内，难以应对更深水域的清淤需求；效率方面，一名熟练工人每天最多清理几十立方米淤泥，面对大面积水域时力不从心。更值得关注的是，人工清淤过程中搅动的淤泥会造成水体二次污染，影响周边生态环境。这', 1, 2, '豫工机械', 9, '/show-477.html', 0, 0, '123.52.20.130-53820', 1774921143, 1774921143, 0, '1', '1'),
(479, 10, '清淤机器人不同型号核心区别及适用场景', '3673', '清淤机器人,煤矿清淤设备,井下清淤机', '基于参数表，各型号核心差异集中在清淤宽度、动力配置、处理能力三个维度，适用场景也随配置不同有所区分，具体如下：一、核心区别500 电动型清淤机器人  清淤宽度 500mm（最窄）；主电机功率 22kw；水泵口径 3 寸、最大流量 100 立方；适配颗粒度 15mm600 电动型清淤机器人  清淤宽度 600mm；主电机功率 22kw；水泵口径 3 寸、最大流量 100 立方；适配颗粒度 15mm；', 1, 2, '豫工机械', 9, '/show-479.html', 0, 0, '123.160.154.38-51267', 1775635546, 1775635962, 0, '1', '1'),
(480, 10, '豫工机械清淤机器人行业标杆，源头工厂直供', '3676', '智能清淤机器人,市政清淤机器人,河道清淤机器人,清淤设备厂家', '豫工机械作为清淤机器人行业标杆企业，是专业研发、生产、销售智能清淤机器人的源头工厂，坚持厂家直供模式，凭借强大生产实力、齐全企业资质、海量客户使用案例，成为市政、水利、化工、矿山等领域首选的清淤机器人生产厂家。作为深耕工程机械领域的实力企业，豫工机械拥有现代化清淤机器人生产基地，具备规模化、标准化生产能力，核心部件自主研发制造，配备先进生产设备与严苛品控体系，确保每一台市政清淤机器人、河道清淤机器', 1, 2, '豫工机械', 9, '/show-480.html', 0, 0, '123.160.154.38-51780', 1775636139, 1775637632, 0, '1', '1'),
(481, 9, '豫工机械通过ISO9001:2015质量管理认证 AAA体系认证', '3686', '质量管理认证,清淤机器人,诚信体系认证,豫工机械', '近日，豫工机械凭借规范的生产管理、严格的品质控制、完善的服务体系，正式通过 ISO9001:2015 质量管理体系认证与 AAA 信用体系认证，标志着企业在质量管理、生产标准、品牌信誉、市场竞争力等方面再上新台阶，为清淤机器人研发、生产、销售与服务全流程提供更权威、更可靠的保障。ISO9001:2015 是国际公认的质量管理体系标准，代表企业在研发设计、物料采购、生产加工、成品检验、售后服务等全链', 1, 2, '豫工机械', 9, '/show-481.html', 0, 0, '123.160.154.38-53595', 1775638394, 1775701493, 0, '1', '1'),
(486, 9, '豫工集团二十一周年庆典暨618女神节燃情启动', '3768', '豫工机械,618,女神节,周年庆典', '初夏明媚，美好恰逢其时！6月17日-18日，郑州总部营销中心，豫工集团二十一周年庆典暨618女神节在集团四个事业部 接棒举行，600多人参与此次活动。6月17日下午，在豫工集团-豫工机械国内事业部活动第二场 燃情启动，一场热情与温情交织的盛会，正式拉开帷幕。笑语声声，芳华灼灼。一曲《桃花朵朵开》，开启今日的盛典表彰，刚刚过去的旺春大战，全员冲锋，逆势突围，豫工英雄桂冠加冕，成功登顶业绩之巅。旺春达', 1, 2, '豫工机械', 9, '/show-486.html', 0, 0, '123.160.152.74-61473', 1782965430, 1782965430, 0, '1', '1');
INSERT INTO `dr_1_xinwenzhongxin_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(211, 1, 9, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;这里是荣誉的殿堂，这里是梦想的舞台，这里是成功的摇篮。2023年12月12日，郑州豫工机械营销中心，200多名员工齐聚一堂，共同开启豫工金秋表彰暨丰年之战启动会。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/202403/316e192dea62e33.jpg&quot; title=&quot;IMG_5484&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702527851562262.jpg&quot; title=&quot;IMG_5841(20231208-180732)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;金色的王冠，丰厚的奖金，奋进的感言，豫工金秋大战优秀表彰，遇见豫工 誉见自己。在豫工，从来不乏闪闪发光的人，他们专注自信热情热爱，在豫工的每一天，他们勇于突破 、勇敢成就，为目标 全力以赴，为成功 所向披靡！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/170253378321934a.jpg&quot; title=&quot;IMG_5503&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17025337837fe4f0.jpg&quot; title=&quot;IMG_5512&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17025337830e1e2b.jpg&quot; title=&quot;IMG_5537(20231208-152143)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;金秋大战期间，他们在奋斗的路上，虽山高路远，仍步履不停，追梦的途中，虽跋山涉水，却一往无前！如何用有限的资源，创造无限的可能，等不是办法，干才有结果，唯有实干 唯有奋斗，依托团队合力 搭档助力 自身努力，勇于进取 稳扎稳打！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702533886064b13.jpg&quot; title=&quot;IMG_5527&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702533886e88248.jpg&quot; title=&quot;IMG_5549&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702533886c85ecd.jpg&quot; title=&quot;IMG_5555&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;转眼又是一年，豫工2023终极一战战鼓再起，过去的事，交给岁月处理，将来的事，交给时间证明，做好当下，才是最好的选择，黄金时刻，奋斗正当时！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702533980fad5c4.jpg&quot; title=&quot;IMG_5748(1)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17025339802d2288.jpg&quot; title=&quot;QQ图片20231213095554&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702533980956784.jpg&quot; title=&quot;QQ图片20231213112100&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702533980098166.jpg&quot; title=&quot;QQ图片20231213113451&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;洪亮的口号，铿锵的誓言，是豫工人对目标极致追求的信心，对成功势在必得的勇气，滚烫的军令状 额头的红飘带，是豫工战士又一次出征！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17025340511c9d84.jpg&quot; title=&quot;IMG_5694&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17025340517bbfdf.jpg&quot; title=&quot;IMG_5736(1)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702534051f2e0d1.jpg&quot; title=&quot;IMG_5759(1)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702534051366aea.jpg&quot; title=&quot;IMG_5765&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;百万英雄PK环节，大家纷纷为心中的准百万英雄，投上信任的一票，以信任换信任，以真心对真心！被信任是一种快乐，这种双向奔赴的美好，是豫工稳步发展的秘诀，以团队为中心，聚势聚力 同心同行，相互托举 互为成就！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702534146717285.jpg&quot; title=&quot;QQ图片20231213113839&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/170253414639118c.jpg&quot; title=&quot;QQ图片20231213140328&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17025341460617e6.jpg&quot; title=&quot;QQ图片20231213142900&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702534146205fd3.jpg&quot; title=&quot;R3`8F~KP])$9}RYK7AO6OFO&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;人生，需要历练，投身收官大战的精彩舞台，去成长 去提升 去成就，奋起直追，百炼成钢！大战之后的豫工人，必将更睿智、更自信、更优秀、更完美！豫工小伙伴们，加油！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17025342245ff041.jpg&quot; title=&quot;QQ图片20231213113831&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17025342251fbf35.jpg&quot; title=&quot;QQ图片20231213115443&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702534225a80ccd.jpg&quot; title=&quot;QQ图片20231213135528&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/170253422571b82a.jpg&quot; title=&quot;背景&quot;/&gt;&lt;/p&gt;'),
(212, 1, 9, '&lt;div&gt;秋高气爽、云开疫散，豫工机械全面复工复产，红包不断，为员工发放高额生活补贴，首批8万元复工红包已发放完毕。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94A2T8.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94I5217.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94KM27.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94R5142.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94SS15.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n 适逢豫工金秋大战，叠加双11嗨购节，您的VIP专属红包已备好，超级钜惠，重磅加码，感谢广大新老客户一直以来的信任和支持，诚心相邀“，郑”等您来。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P95402428.jpg&quot; style=&quot;width: 900px; height: 649px;&quot;/&gt;&lt;br/&gt;\r\n 河南豫工机械是国内工程设备生产基地，拥有18年服务经验，公司规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/div&gt;'),
(213, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;font-size:16px;&quot;&gt;岁末将至，豫工机械2023新年庆典，欢乐上线。今天不谈工作，不谈业务，只谈“笑”“疯”声，红包、奖品、表彰，歌曲、小品、舞蹈，好事扎堆 快乐排队！&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130143U4Y6.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023年会现场&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;优秀员工表彰，红包不停，礼品不断，荣誉感十足 幸福感爆棚......好嗨哟，感觉人生已经达到了巅峰！&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144053I4.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023年会现场颁奖礼&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301441495S.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023年会颁奖现场&quot;/&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144113D9.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023年会优秀表彰&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;看！这不就是努力的意义嘛！忙有所得 耕有所获，走路带风 眼神坚定，每根头发都散发着自信的光芒，内心富足 自律自强，有所忙有所爱有所期待！&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-23013014425a24.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会优秀新人奖&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301443262P.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会优秀进步奖&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;才艺展示环节，角色反转，曾经的职场精英，化身才艺明星，说、演、唱、跳，上演豫工达人秀，爆笑逗乐 嗨翻全场，欢欢喜喜迎新年！&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144449338.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会才艺展示&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-23013014450S39.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会才艺展示&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144531J5.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会才艺展示&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;活动现场，歌声与鼓声共振，笑声与掌声齐飞，酣畅淋漓 开心尽兴！&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144645Q8.jpg&quot; style=&quot;width: 900px; height: 570px;&quot; title=&quot;豫工机械2023年会活动现场&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144J6222.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会活动现场&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144FQb.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023新年庆典&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2022带着我们的热爱走进历史，我与旧事归于尽，来年依旧迎花开，感恩一路同行的小伙伴们，2023制胜之年，归零 更新 重启 向上，让我们继续加油！&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/6a93b8b8f95d59b.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023新年庆典&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是国内工程设备生产基地，拥有18年服务经验，公司规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(214, 1, 9, '&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;伴随着恢弘的音乐，豫工人满怀信心，火热开启，2023旺春大战启动会！作为一年一度的重头戏，豫工人最重要的日子，每个人精致妆容，盛装出席，大有与三月争春的劲头，只有额头上的红头巾，写着“赢战旺春”“舍我其谁”的宣言，时刻提醒我们，这是一场时间紧、任务重的百天大战（2023.3.1-6.15）。音乐停止，国内事业部成员入场就坐，200多位豫工人齐聚一堂，火热开启，2023旺春大战启动会。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/576c3da48828c5e.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324121523942.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;本次大会分为三个部分，团队风采、最美传帮带、百万英雄show，满满的仪式感，鼓励大家躬身入局，以强烈的责任感 使命感，珍惜每一个客户，坚守每一份荣誉，大干100天，拿下2个亿！&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122145I4.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;董事长致辞&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;李总强调：2023，豫工人要更懂换位思考，时刻站在客户的角度思考问题，将豫工服务做成一大特色、一个标杆、一面旗帜！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122240N4.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;团队风采展示&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;各团队小伙伴，自信满满，稳操胜券，在主管激情带领下，集结完毕 整装待发，正式出征！大家现场喊出大战目标，勇敢向最优秀者发起挑战，业绩PK&amp;nbsp; 勇往直前，逼迫自己更好更强，在优秀的路上永不止步&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122452562.jpg&quot; style=&quot;width: 900px; height: 493px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122505400.jpg&quot; style=&quot;width: 900px; height: 572px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-2303241225211M.jpg&quot; style=&quot;width: 900px; height: 638px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;最美传帮带&amp;nbsp;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;人才之兴 豫工之幸，豫工传帮带，作为公司人才输送站，培养了一批又一批 一代又一代，想干事、能干事的精英强将，助力豫工更高 更强 更大的发展！传帮带的导师们无私分享工作经验，让新人少走弯路 高效成长，星火相传 成功相继，此刻！致敬豫工最美园丁&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122644253.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;百万英雄show，自信的女生会发光，参加百万英雄挑战的小伙伴，以巾帼英姿 必胜信念，用庄重响亮的誓言，展示自己力破百万的勇气！&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324142924631.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-2303241429443A.jpg&quot; style=&quot;width: 900px; height: 575px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324143001X1.jpg&quot; style=&quot;width: 900px; height: 571px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;2023的豫工，是全力拼搏者的舞台，是孕育成功者的摇篮，期待豫工人，多一份坚持 多一点热情，以昂扬奋斗的姿态 脚踏实地的干劲，去创造、去突破、去提升！&lt;/span&gt;&lt;/div&gt;'),
(215, 1, 9, '&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;春余夏首 微风习习,2023.6.21,豫工机械十八周年庆典隆重开启,索菲特国际酒店 五星级会议大厅,公司总部300多人盛装出席,共同见证豫工发展高光时刻!&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GA64B08.jpg&quot; style=&quot;width: 900px; height: 476px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF152K0.png&quot; style=&quot;width: 900px; height: 459px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/8ca93d1cb0484b.png&quot; style=&quot;width: 900px; height: 464px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;辉煌大厅别具匠心,签名墙精心布置,留下了豫工人自信优雅的身影!一张张喜逐颜开的笑脸,一幅幅轻松融洽的合影,让豫工人的心更牢固地粘在一起!&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF41BF.jpg&quot; style=&quot;width: 900px; height: 512px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF43N49.jpg&quot; style=&quot;width: 900px; height: 1200px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF5204O.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;在欢快动感的舞蹈中，庆典拉开序幕,豫工人活力四射 舞力全开，上演才艺大比拼。宫廷风 民国风 劲爆风 ，甜美风 波斯风 冷酷风，每个人用自己擅长的方式，表达对豫工的热爱，庆祝豫工18岁生日快乐，穿插的抽奖游戏和奖品，让大家同享欢乐时刻。&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GFI5317.jpg&quot; style=&quot;width: 900px; height: 480px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GFK9639.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GFS5Y9.jpg&quot; style=&quot;width: 900px; height: 554px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;遇见豫工 遇见自己，在激昂的音乐中，开启优秀表彰环节，金色皇冠见证王者归来，耀眼奖杯镌刻拼搏的力量，经久不息的掌声，是对家人们取得成功的由衷祝贺。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG054341.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG122B5.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG142b7.jpg&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;庆典重磅环节——股东分红，公司为2022年近百名股东发放分红，并宣读股东誓词，庄严的仪式感 字字铿锵，每句话都是股东们对豫工的责任与信心，未来，相信股东们必会齐心协力，再接再励，祝愿豫工明天会更好&lt;/span&gt;。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/435afa7112cf08f.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG30VX.jpg&quot; style=&quot;width: 900px; height: 405px;&quot;/&gt;&lt;br/&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;庆典下半场，盛夏大战火热启动，大会现场气势磅礴，豫工人以飒爽英姿 亮剑出征，敢于挑战，敢闯敢拼，各团队精神抖擞，震撼有力的大战口号，喊出了团队的士气，也喊出豫工人赢战未来的信心。&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG459536.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG5124I.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG613551.jpg&quot; style=&quot;width: 900px; height: 613px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GGG94O.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GGK51U.jpg&quot; style=&quot;width: 900px; height: 618px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt; &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;火热的时刻 缤纷的舞台，未来因我们而在，豫工因我更精彩，斗志在这一瞬间迸发，激情在此时此刻绽放，热血、骄傲、拼搏、奔跑，汇成豫工盛夏大战的主旋律，愿我们努力的汗水，闪耀今年整个盛夏。&lt;br/&gt; &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG95IX.jpg&quot; style=&quot;width: 900px; height: 605px;&quot;/&gt;&lt;br/&gt; &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GH015963.jpg&quot; style=&quot;width: 900px; height: 623px;&quot;/&gt;&lt;br/&gt; &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GH12E63.jpg&quot; style=&quot;width: 900px; height: 632px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt; &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;除了精美的生日蛋糕，公司还贴心安排西式晚宴，开启惬意的悠闲时光，酒杯碰在一起，是我们梦想飞翔的声音！&lt;br/&gt; &amp;nbsp; &lt;br/&gt; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GJK5960.png&quot; style=&quot;width: 956px; height: 528px;&quot;/&gt;&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GH5235F.png&quot; style=&quot;width: 797px; height: 471px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;豫工机械十八载正青春！回顾过去，感谢公司高瞻远瞩，感谢全体员工奋力拼搏，感谢支持豫工的客户朋友，未来，我们将不忘初心，砥砺前行，激情、拼搏、感恩，以高品质服务共赢美好明天。&lt;/span&gt;&lt;/div&gt;'),
(216, 1, 9, '&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;工作中乘风破浪，生活中多姿多彩，2023年8月18日，豫工机械2023秋季团建，三天两夜 欢乐启程。4辆豪华大巴满载我们的快乐奔赴美丽连云港，游山观海 不负时光，一起感受港城的秋天。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3161JR56.jpg&quot; style=&quot;width: 900px; height: 507px;&quot;/&gt;&lt;br/&gt;\r\n 打卡羊山岛，渔村情调 潮声灌耳，感谢豫工的贴心安排，让我们一起，来一场诗和远方的浪漫。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3161U3956.jpg&quot; style=&quot;width: 900px; height: 692px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/a21828b0bb6163e.jpg&quot; style=&quot;width: 900px; height: 736px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R316194E95.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n 敢问路在何方，路在脚下......，走进现实版的花果山，洞天福地 人间仙境，感受心中的桃花源。45°的侧脸很好看，45°角的石梯很难攀，加油！豫工人，相互鼓励 一路高歌，我们终将抵达顶峰。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162024J6.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R316214C95.jpg&quot; style=&quot;width: 900px; height: 540px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;畅游大海的怀抱，一揽连岛风貌，体验乘风破浪的壮阔，大家一路高歌，感受激情浪漫的美好，豫工机械，感谢有你！今天被好风景收买，剩下的都是好心情，漫步细沙浅滩，亲近自然 放空心情，遇见更好的自己。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162211J6.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R316222N24.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R31623504E.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;云台铺海 群山环绕，畅游海上云台山，山海美景 尽收眼底，我爱这山色，就像对生活热烈的爱！&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162649414.png&quot; style=&quot;width: 900px; height: 710px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162J0F8.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162GM42.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; 你笑的真好看，像春天的花一样，美丽连云港，山美 海美 人更美。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162500Y4.png&quot; style=&quot;width: 897px; height: 433px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R31625449A.jpg&quot; style=&quot;width: 900px; height: 453px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R31626305K.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3天的旅游圆满结束，大家收获满满，是前所未有的欢乐，是给予彼此的信任，未来，让我们一起 继续同行。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(217, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/a80d4187210fc65.jpg&quot; style=&quot;width: 900px; height: 381px;&quot;/&gt;&lt;br/&gt;“99公益日”来临，豫工机械作为常年热心公益的爱心企业，特发起2022年度“99公益日”助力“困境儿童守护计划”公益募捐活动，携手助童 共护成长。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS133351.png&quot; style=&quot;width: 900px; height: 552px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS151222.png&quot; style=&quot;width: 900px; height: 570px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS204496.jpg&quot; style=&quot;width: 900px; height: 497px;&quot;/&gt;&lt;br/&gt;即日起至9月9日，您的每一笔捐款，豫工机械将进行1：1金额的“陪捐”！也就是你捐多少，我公司会“陪捐”多少！“薅羊毛”式捐赠，为爱加油！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS24M13.jpg&quot; style=&quot;width: 900px; height: 500px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;积小善，成大爱&lt;/strong&gt;&lt;br/&gt;\r\n 捐助10元，可以帮助一个孩子解决一天的生活补助；&lt;br/&gt;\r\n 捐助20元，可以帮助孩子买一本课外书；&lt;br/&gt;\r\n 捐助100元，可以资助一名特困孩子1个月生活费；&lt;br/&gt;\r\n 捐助500元，可以帮助她们买够一学年的学习用品；&lt;br/&gt;\r\n 捐助1000元，可以捐助特困孩子一年的生活费&amp;nbsp;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS404324.png&quot; style=&quot;width: 900px; height: 569px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;希望您也能加入我们,让我们的队伍越来越强大，让更多困境儿童获益！&lt;/div&gt;&lt;div&gt;&lt;div&gt;&lt;strong&gt;募捐活动时间&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;2022.9.7-9.9&lt;/div&gt;&lt;div&gt;&lt;strong&gt;获取配捐&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;腾讯基金会将拿出3亿元，向所有参与99公益日的公益项目进行配捐，每人每天配捐总额最高可达999元。&lt;/div&gt;&lt;div&gt;同时，豫工机械将对参与“困境儿童守护计划”的善款进行1：1的“陪捐”。&lt;/div&gt;&lt;div&gt;&lt;strong&gt;参与方式&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;（1）长按图片识别二维码；&lt;/div&gt;&lt;div&gt;（2）自定义或者选择捐款金额；&lt;/div&gt;&lt;div&gt;（3）点击确定，完成捐赠；&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS524420.png&quot; style=&quot;width: 684px; height: 955px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;一起做好事&amp;nbsp; 让爱加倍，一份份捐助，一份份爱心，可以帮助困境中的孩子快乐成长，各位爱心人士可以在微信群、朋友圈 、发动家人、朋友一起捐，一起为爱翻倍，为爱加油！&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000cd;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/span&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目!&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(218, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2022年6月18日 中都大酒店，豫工机械17周年庆典暨第二届女神节隆重举行，总部营销中心300多人参加活动，现场星光璀璨 精彩纷呈！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QTQY23.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;董事长开幕式致辞&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;李总表示：豫工17年高速发展与科学的规划密不可分，立足长远，计划落地。未来，公司还要继续练内功，强本领，做规划！做精、做深、做强主营业务，为客户提供不可替代的服务和价值!&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QTZcB.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;strong&gt;2022旺春大战颁奖典礼&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;柔肩担重任&amp;nbsp; 巾帼绽芳华，旺春大战期间，豫工人执着于未来，奋斗于脚下，他们始于热爱，终于丰盈，立一个目标，守一份初心，今天他们是最亮的星，全力以赴，满载而归。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU14I53.jpg&quot; style=&quot;width: 900px; height: 544px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/d7b7cc2ddf13.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU245N2.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;strong&gt;总经理总结致辞&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;国内事业部侯总和国际事业部赵总为本次颁奖环节总结致辞，回顾公司17年发展成果，侯总表示：豫工从桥梁设备生产起步，到形成八大产品系列，一百多款产品的庞大规模，用了17年！目前，豫工进入迅猛爆发期，生产总值连续5年持续翻番，客户遍布全球一百多个国家和地区，多款产品在国家大批重点建设项目中被广泛采用！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU319133.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;2022年度股东分红,不忘初心,方得始终,在公司领导的英明领导下,豫工人用务实浇灌硕果，用初心赢得绽放,取得丰硕成果!&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU41X04.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;2022盛夏大战启动仪式&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;梦想不设限 人生无极限，17年豫工正青春，引进新技术 吸纳新人才 规划新未来朝气蓬勃、积极向上 ，2022新征程&amp;nbsp; 亦有新发展。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU5302J.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU545P1.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU610413.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;strong&gt;2022第二届女神节&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;文艺表演高潮迭起，载歌载舞展现豪情壮志，畅想未来图景，豫工人总是这样多才多艺，既有脚踏实地的努力，也有仰望星空的诗意，心如花木 向阳而生！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QUGUG.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QUHb32.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QUJQ25.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;时光奔流不息，初心历久弥坚，我们真诚期待，豫工未来波澜壮阔 绚丽多彩我们心怀感恩，诚邀广大客户朋友一起奋进新未来，逐梦星辰大海，成就互惠共赢！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(219, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 美好恰逢其时，生活与“粽”不同，端午如期而至，豫工的福利也一如往昔，丰厚 健康 贴心！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91030R6.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q9104O39.jpg&quot; style=&quot;width: 900px; height: 428px;&quot;/&gt;&lt;br/&gt;两箱粽子，一箱火龙果，一箱哈蜜瓜，沉甸甸的感觉，像极了豫工对家人的关爱，感谢大家为公司发展的辛勤付出！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91130595.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;因为有你，所以出粽，2022是不平凡的一年，因为大家的不懈努力，豫工在充满机遇与挑战的市场竞争中，逆势而来 强势崛起！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91224N1.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q9123Q35.jpg&quot; style=&quot;width: 900px; height: 451px;&quot;/&gt;&lt;br/&gt;一粽传情，浓情端午，一盒盒精致的端午礼品，承载了公司对大家满满的关怀，代表着公司对全体员工的真挚祝福，感谢公司每个节日的恩宠，很幸运在最美的年华相聚于此，一起奋斗一起成长！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91323R6.jpg&quot; style=&quot;width: 900px; height: 578px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/947dab807e903b2.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;/&gt;&lt;br/&gt;春风有信，花开有期，所有的美好都已经在路上了，值此端午佳节，豫工机械恭祝新老客户朋友，事业顺利 阖家幸福，粽享幸福 端午安康！\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(220, 1, 9, '&lt;div&gt;生活不止眼前的工作，还有静下来的诗意和远方，2022年8月13日，伴着动感的音乐，踏着欢快的节拍，豫工机械2022主题团建第一趴，快乐出发！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/da8c13aec96fd86.jpg&quot; style=&quot;width: 800px; height: 599px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;感谢公司的贴心安排，本次团建以部门为单位，自主规划活动路线，漂流、爬山、温泉、轰趴、划船......各赴人间惊鸿宴，一睹人间盛世颜！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010142204911.jpg&quot; style=&quot;width: 800px; height: 599px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010142231345.jpg&quot; style=&quot;width: 800px; height: 410px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101442405G.jpg&quot; style=&quot;width: 800px; height: 361px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-22101014430CE.jpg&quot; style=&quot;width: 800px; height: 1730px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;打卡云上牧场，感受风的温柔，体验花的浪漫，听蝉鸣鸟叫，看蝴蝶纷飞，再和天空来一张合作！&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010142400236.jpg&quot; style=&quot;width: 800px; height: 802px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010143912603.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;生活中可能遇到的小情绪，在这天地间晒一晒，就好了，为明天的工作重拾心情，归来的我们，依旧元气满满。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-22101014410D43.jpg&quot; style=&quot;width: 800px; height: 1066px;&quot;/&gt;&lt;br/&gt;&lt;div&gt;选择自驾游的小伙伴，吃喝玩乐更加随性，春风十里，不如美食有你，今天的减肥事业，可以暂时放一放了，分享美食，快乐第一！&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010144213Z8.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101443255O.jpg&quot; style=&quot;width: 800px; height: 1730px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;工作中乘风破浪，团建时激情绽放，打卡宝泉的小伙伴们，追逐清凉，趣味横生，在山水间撒个欢儿！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010144440D9.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;快乐的时光，小伙伴们乐在其中，增加了团队默契度，让大家彼此了解 并肩携手 ，一起创造豫工更好的明天！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(221, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2022年2月22日，豫工机械“如虎添亿，奋战51”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工200多人参加此次活动！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/49e7d21c6cf4360.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-2204191051314T.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;2021，在豫工人的共同努力下，公司全年销售总额再破3亿元大关，品牌知名度、市场接受度、老客户返单率、生产总值、团队业绩再创新高。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105220O3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;期间，公司涌现出了众多业绩精英、营销达人、优秀团队、百万英雄。她们8小时内求生存，8小时外求发展，每一天、每一分钟，都在为成功全力以赴！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-22041910530S45.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;3月，工程建设进入施工旺季，生产订单、设备售后、物流跟踪......等客户需求井喷式爆发，豫工特发起百天旺春大战冲锋号（3.1-5.31），各个部门与客户同频，大干100天，打好开局战。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105345Y3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;启动会上，豫工小伙伴胸有成竹梳理旺春目标，毫无保留分享工作方法，争取在接下来的100天，紧盯目标，协同向前，不达目的，绝不收兵。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105432b2.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105444K3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105500934.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;有人说你相信什么，就会吸引什么！&lt;/div&gt;&lt;div&gt;公司股东作为豫工的中流砥柱，纷纷签订绩效责任承诺书，不畏艰难，身先士卒，同心协力，共战51！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105541391.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;戮力同心，勇于担当是我们的态度，团结协作、相互帮扶是我们的法宝&lt;/div&gt;&lt;div&gt;百天旺春，时间紧任务重，每一个豫工人都要同心协力，互助帮扶！心中无敌，奋战“51”！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105620Q5.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105AMC.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;董事长赋能&amp;nbsp;&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;作为公司的掌舵人，豫工的精神支柱，李总表示：2022，豫工的主旋律就一个字“干”，干他个虎虎生威，干他个红红火火。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419110415237.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n “豫工十六年发展，吸引越来越多的优秀人才加入这个大家庭，终成今日盛势！2022，豫工人还要继续互帮互助，团结协作，推动豫工这艘航船扬帆远航，再创辉煌！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419110523B8.jpg&quot; style=&quot;width: 900px; height: 900px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目!&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(222, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2022年9月14日，豫工机械营销总部，金秋大战在国内事业部率先启动，近200名员工斗志昂扬，众志成城，正式打响金九银十决胜战！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI302X8.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/f85a35e064042dd.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI324337.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;总结过去，赢战未来，表彰卓越，见证辉煌&lt;br/&gt;&lt;/p&gt;&lt;div&gt;在热烈的掌声中，优秀代表纷纷登台，荣誉和鲜花，是对他们最大的鼓舞和肯定。&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI609157.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 0.544px; text-align: justify; background-color: rgba(246, 212, 218, 0.58);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI645949.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;在金九银十关键节点，豫工机械金秋大战也如期而至，作为公司2022年51工程（2022年销售额突破5个亿）的关键一战，本次启动会既要制定目标、分解过程，更要为营销团队蓄势蓄力，增强信心！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QIIX33.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QIK9209.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QIQ5T2.jpg&quot; style=&quot;width: 900px; height: 703px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;启动会上，每个人都制定可行的金秋目标，分解目标，规划过程，最大程度保证方案的可行性，一鼓作气，赢战“51”！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QKAW58.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QKG4559.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;在团队主管的带领下，各部门纷纷签署金秋军令状，立下铿锵雄心，军令如山，一往无前，巅峰对决，闪耀金秋。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QKQ5420.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QKS23B.jpg&quot; style=&quot;width: 900px; height: 551px;&quot;/&gt;&lt;br/&gt;战鼓声声，催人奋进，在公司各部门的大力支持下，营销中心全体人员枕戈待旦、鼓足干劲，金秋之战，志在必胜！豫工小伙伴，加油！\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(223, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 中秋节发福利了！红红火火的包装，至诚至爱的心意，节礼在手，温暖在心，感谢公司一如既往的厚爱！&lt;/p&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QPG4N2.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n 作为国人重要的传统佳节，每年中秋，公司都会精心准备节日贺礼，感谢大家一年来的努力与付出，希望每一位员工都能与家人，阖家团圆，把酒言欢，满满的仪式感，引来隔壁公司羡慕的眼光。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QPRB91.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QPT6225.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;/&gt;&lt;br/&gt;\r\n 心怀感恩 所遇皆温柔，公司满满的关爱，不仅让豫工人找到归属感，也让背后的家庭对豫工好感度俱增，多年工作下来，他们都成了最合格的豫工家属！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QP94G45.jpg&quot; style=&quot;width: 900px; height: 542px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QQ00R91.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n 每逢生产旺季 客户来访，他们总是主动担待，让豫工人有更多精力苛求细节 圆满服务，因为他们的全力支持，豫工人有更多时间研发生产 优化产品，赢得一个又一个客户的信赖。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QQ303T8.jpg&quot; style=&quot;width: 900px; height: 505px;&quot;/&gt;&lt;br/&gt;\r\n 在这花好月圆的欢庆时刻，在这金九银十的施工旺季，我们特意为全国客户朋友准备了大大的中秋福利，满满的诚意，礼到、心到、实惠到！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/30879890ebbf52a.jpg&quot; style=&quot;width: 900px; height: 370px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;9月8日-9月10日，豫工将送出30万中秋购机消费券，大到几十万的生产线，小到几百块的配件均可适用，爆款福利 限时派送 ，赶快联系你的业务经理领取吧！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(224, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G0123D.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/7aba8c273d46a08.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G04M16.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G103H4.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G11RU.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G132129.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(225, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 金色九月，喜迎中秋!豫工机械为答谢新老客户的支持和厚爱，精心定制中秋贺礼800份,已包装完毕，即将发货！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091610215A62.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091610221A35.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;刚刚过去的两个月，郑州人过得极不容易,先抗洪灾、又战疫情,幸运的是，有像您这样一群老朋友新伙伴的一路相伴,豫工人才能凭借勇敢无畏的干劲，排除万难，顺利闯关!&lt;br/&gt;&lt;strong&gt;7月抗汛,赈灾义卖,!筹款30万捐向灾区&lt;/strong&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091610345M33.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103512c7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/d516ca6d76458d.jpg&quot; style=&quot;width: 695px; height: 312px;&quot;/&gt;&lt;br/&gt;&lt;strong&gt;8月抗疫，涝疫补贴,每人500元&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103J3A6.jpg&quot; style=&quot;width: 695px; height: 428px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103Q1R7.jpg&quot; style=&quot;width: 695px; height: 445px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103S13A.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;/strong&gt;&lt;br/&gt;中秋佳节将至，金九银十已来，为答谢您一如既往的信任和支持，除中秋贺礼，豫工人也吹响金秋大战（9月15日-11月15日）集结号，各种促销感恩让利，全体员工60天无休无假，及时发货，专业售后，为您的工程保驾护航。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-2109161042243V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;花好月圆，天涯共此良辰，豫工机械恭祝新老客户朋友，财源滚滚、事业顺利，家庭美满、中秋安康！&lt;br/&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械有限公司&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！&lt;br/&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_xinwenzhongxin_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(226, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2021年9月11日，豫工机械“2021金秋大战暨旺春优秀表彰” 燃情启动，郑州总部营销中心，全体员工180多人参加活动！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916104T33V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国内事业部活动现场&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916104ZO24.png&quot; style=&quot;width: 695px; height: 813px;&quot;/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部活动现场&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091610500T94.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;旺春大战优秀表彰&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;2个月前，公司旺春大战圆满收官，诞生了许多业绩标兵、百万英雄、服务之星、优秀团队，今天是见证荣誉的时刻！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105423545.jpg&quot; style=&quot;width: 695px; height: 546px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div style=&quot;text-align: center;&quot;&gt;国内事业部旺春英雄奖&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105440121.jpg&quot; style=&quot;width: 695px; height: 474px;&quot;/&gt;\r\n &lt;div style=&quot;text-align: center;&quot;&gt;国内事业部捷报奖&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105614H5.jpg&quot; style=&quot;width: 695px; height: 739px;&quot;/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部旺春英雄奖&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105630b7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部旺春达人奖&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105HK63.jpg&quot; style=&quot;width: 695px; height: 528px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部旺春捷报奖&lt;/div&gt;&lt;div&gt;&lt;strong&gt;优秀个人表彰&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;在豫工，从不缺工作上的拼命三郎，他们拼搏进取 所向披靡，他们是当之无愧的业务精英，是豫工人应该崇拜的旺春英雄！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-2109161JGXM.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;div style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;国内事业部佳个人进步奖&lt;/span&gt;&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916110249236.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;/div&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部佳个人进步奖&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;&lt;strong&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916110441H0.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/strong&gt;&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;&lt;strong&gt;百万英雄表彰&lt;/strong&gt;&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;每一个不起眼的日子，都是逆风翻盘的机会，深夜办公室的灯火通明，陪伴豫工人日复一日的坚持，见证一个又一个百万大单的诞生！&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-2109161110101F.jpg&quot; style=&quot;width: 695px; height: 537px;&quot;/&gt;&lt;br/&gt;\r\n &lt;strong&gt;金秋大战燃情启动&lt;/strong&gt;\r\n &lt;div&gt;金九银十，豫工人吹响金秋大战（9月15日-11月15日）集结号，各种促销政策感恩回馈，全员60天无休无假，及时发货，专业售后，为客户工程保驾护航！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611123E64.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111301G7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111325Y8.jpg&quot; style=&quot;width: 695px; height: 538px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/d994a6a1f167b0b.jpg&quot; style=&quot;width: 695px; height: 541px;&quot;/&gt;\r\n &amp;nbsp;&lt;div style=&quot;text-align: center;&quot;&gt;国内事业部团队风采&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611151N02.jpg&quot; style=&quot;width: 695px; height: 605px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611152R61.jpg&quot; style=&quot;width: 695px; height: 473px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111604527.jpg&quot; style=&quot;width: 695px; height: 605px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611162E59.jpg&quot; style=&quot;width: 695px; height: 487px;&quot;/&gt;\r\n &amp;nbsp;&lt;div style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;国际事业部团队风采&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;奋斗不止的“军令状”&lt;/div&gt;&lt;div&gt;军令如山 使命必达！启动会上，各团队用热血誓言签下军令状，不找理由、不找借口，创新突破，勇于担当，全力以赴，目标必达！&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111QX07.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111SB03.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111UH34.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div style=&quot;text-align: center;&quot;&gt;国内事业部员工风采&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611193M58.jpg&quot; style=&quot;width: 695px; height: 756px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611195Hb.jpg&quot; style=&quot;width: 695px; height: 769px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916112010546.jpg&quot; style=&quot;width: 695px; height: 502px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部员工风采&lt;/div&gt;&lt;div&gt;&lt;strong&gt;实实在在豫工人&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;踏实独立，热爱上进，豫工女孩既爱红装也爱戎装，生活中追求仪式感，该努力时也绝不含糊，全力以赴，活出自己的色彩！&lt;/div&gt;&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916112149E9.jpg&quot; style=&quot;width: 695px; height: 530px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611215aD.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916112215230.jpg&quot; style=&quot;width: 695px; height: 815px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-2109161122251X.jpg&quot; style=&quot;width: 695px; height: 661px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;大好时光，奋斗正当时&lt;/div&gt;&lt;div&gt;豫工人天生勤奋、实干、永不服输&lt;/div&gt;&lt;div&gt;不抛弃不放弃，言出必行，使命必达&lt;/div&gt;&lt;div&gt;2021金秋大战&lt;/div&gt;&lt;div&gt;小伙伴们，加油！！！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;text-decoration:underline;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(227, 1, 9, '&lt;div&gt;金秋九月，花好月圆，又是一年中秋时！&lt;/div&gt;&lt;div&gt;河南豫工机械有限公司根据国假办放假规定，结合公司实际情况，中秋节放假安排如下：&lt;br/&gt;\r\n &lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;&lt;strong&gt;放假时间：2021年9月19-21日，共三天。9月22日（周三）正式上班&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/5ac863002143743.gif&quot; style=&quot;width: 640px; height: 440px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;background-color:#ffff00;&quot;&gt;温馨提示&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;&lt;div&gt;&lt;div&gt;1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;&lt;div&gt;2、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;&lt;/div&gt;&lt;div&gt;3、假期期间出行要佩戴好口罩，尽量避免乘坐公共交通，如需乘坐务必防护到位。外出游玩过程中注意保持人际距离，不去中高风险地区，保持良好卫生习惯。&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;月圆人团圆&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;中秋合家欢&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;豫工机械恭祝新老客户朋友财源滚滚、事业顺利、阖家幸福、中秋安康！&lt;/span&gt;&lt;/strong&gt;&lt;br/&gt;\r\n &lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;'),
(228, 1, 9, '&lt;div&gt;神州大地，举国欢庆！&lt;/div&gt;&lt;div&gt;山河壮丽，岁月峥嵘！&lt;/div&gt;&lt;div&gt;江山不老，祖国常青！&lt;/div&gt;&lt;div&gt;豫工机械祝福我们的祖国繁荣昌盛&lt;/div&gt;&lt;div&gt;十一国庆节来了，根据国家放假规定，结合公司实际情况，河南豫工机械有限公司2021年国庆放假安排如下：&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/3e3ee1515159fb1.jpg&quot; style=&quot;width: 850px; height: 1275px;&quot;/&gt;&lt;br/&gt;\r\n &lt;strong&gt;&lt;span style=&quot;color:#ff0000;&quot;&gt;注意事项&lt;/span&gt;&lt;/strong&gt;&lt;br/&gt;\r\n &lt;div&gt;1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;&lt;div&gt;2、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;&lt;div&gt;3、假期期间出行要佩戴好口罩，尽量避免乘坐公共交通，如需乘坐务必防护到位。外出游玩过程中注意保持人际距离，不去中高风险地区，保持良好卫生习惯。&lt;/div&gt;&lt;div&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(229, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2022年3月31日，在豫工机械生产车间，两台3017型湿喷台车完成最后的装配，成功下线，通过严格功能检测，即将发车！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103610J7.jpg&quot; style=&quot;width: 900px; height: 505px;&quot; title=&quot;湿喷台车发车现场&quot;/&gt;&lt;br/&gt;它们将用于中铁隧道局宜兴铁路ZQ-3标隧道喷浆支护项目。作为3月的第49、50台喷浆支护系列设备，它的成功发车，意味着豫工机械喷浆支护设备3月销量再创新高。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103645J2.jpg&quot; style=&quot;width: 900px; height: 405px;&quot; title=&quot;湿喷台车服务项目&quot;/&gt;&lt;br/&gt;这台外形酷似机械手臂的升级版全机械化液压湿喷台车，与常规型液压湿喷机相比，工作效率提升2倍，轻松达到30㎥/h，而且，机械化程度高，遥控操作，全自动喷浆无盲区，广泛应用于高铁、隧道、边坡、地铁、基坑等喷浆支护项目。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103I3547.jpg&quot; style=&quot;width: 900px; height: 674px;&quot; title=&quot;湿喷台车生产现场&quot;/&gt;&lt;br/&gt;据豫工机械研发部门陈主任介绍，该款湿喷台车的机械臂、泵送系统、液压系统、电器系统等关键零部件优选知名品牌。机、电、液一体化控制系统，实现对发动机、液压系统、工作状态的检测和保护，保证设备的高可靠性。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103Q3140.jpg&quot; style=&quot;width: 900px; height: 505px;&quot; title=&quot;湿喷台车调试现场&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;施工现场，操作人员使用无线遥控进行喷射作业，远离作业面，不仅操作方便，更增加了工人的安全性。&lt;/div&gt;&lt;div&gt;客户对设备高效的生产能力很满意，表示：根据工程需要，下次再上一台。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103913G1.jpg&quot; style=&quot;width: 900px; height: 675px;&quot; title=&quot;湿喷台车施工现场&quot;/&gt;&lt;br/&gt;\r\n 豫工机械作为17年喷浆支护设备生产厂家，型号齐全、品类完善，液压湿喷机、混凝土喷浆车，钢筋网片排焊机等设备深受欢迎，一站式采购，降低生产成本，提升施工效率！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419104024U2.jpg&quot; style=&quot;width: 900px; height: 600px;&quot; title=&quot;液压湿喷机仓库&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-22041910403R96.jpg&quot; style=&quot;width: 900px; height: 599px;&quot; title=&quot;喷浆支护设备仓库&quot;/&gt;&lt;br/&gt;\r\n 其实，豫工喷浆支护设备一直以“高效稳定”享誉市场，在高铁、地铁、隧道领域，发挥着举足轻重的作用，被国家大批重点建设项目广泛采用，累计服务工程项目30000+！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-22041910414V56.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419104201Y2.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419104211547.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/168adfb7e9f7ca7.jpg&quot; style=&quot;width: 900px; height: 507px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目!&lt;/div&gt;'),
(230, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/210730/2-210I01G4319B.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G4463H.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G45H50.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G510N4.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G53bb.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G555950.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G606393.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G61L18.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GF2928.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GHT01.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GQ0R1.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GS4517.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GT4910.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GU5362.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GZJX.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/0d495848fc24117.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G93H11.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;h2 class=&quot;rich_media_title&quot; id=&quot;activity-name&quot; style=&quot;margin: 0px 0px 14px; padding: 0px; font-size: 22px; line-height: 1.4; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); text-decoration-line: none; font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/span&gt;&lt;/h2&gt;'),
(231, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/284553bf9a746bb.png&quot; style=&quot;width: 695px; height: 295px;&quot;/&gt;&lt;br/&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 在这个世界上，有这么一群人，他们不是叱咤风云的英雄，不是风光无限的明星，也不是天赋异禀的能人。他们只是热爱生活的普通人，是努力生活在平凡世界中的每一个人。&lt;br/&gt;&lt;/p&gt;&lt;div&gt;在即将到来的五一劳动节，豫工机械向所有平凡又非凡的劳动者致敬！愿你们都能以全力以赴的热忱，过梦寐以求的生活！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210430/2-2104301453111a.jpg&quot; style=&quot;width: 695px; height: 1123px;&quot;/&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;&lt;div&gt;&lt;div&gt;根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，劳动节放假安排如下：&lt;/div&gt;&lt;div&gt;1、2021年劳动节放假共3天，时间为2021年5月1日至5月3日，5月4日（星期二）正常上班。&lt;/div&gt;&lt;div&gt;2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;&lt;div&gt;3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;&lt;/div&gt;&lt;div&gt;祝愿大家过一个安全、惬意、有意义的劳动节！&lt;br/&gt;\r\n 　　&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/div&gt;'),
(232, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2021年5月21日，郑州禧逸酒店会议大厅，&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;“保持热爱，共赴山海”16周年庆典暨第一届女神节欢乐开启，总部营销中心全体员工220多人参加了此次活动。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/8528a76fda43cba.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052514514K22.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;生日趴&lt;/div&gt;&lt;div&gt;在众人的生日祝福中，董事长李总为大家分切蛋糕，开启今天的活动庆典。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145505a7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145532F2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145550E4.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;迎新环节&lt;/div&gt;&lt;div&gt;16年开拓创新，争先、争勇、争光，创新、创业、创享,收获累累硕果！&lt;/div&gt;&lt;div&gt;公司焕发的强大活力，不断吸引众多行业精英的加入！为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家快速成长，融入团队。&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145I11X.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515004R20.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;年度职级晋升&amp;nbsp;&lt;/div&gt;&lt;div&gt;迎光奔跑，保持热爱，每一个认真努力的现在，都有一个水到渠成的未来！&lt;/div&gt;&lt;div&gt;本次年度职级晋升表彰，让我们再次见证努力的意义！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251501563B.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251502452a.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;2020年度表彰&lt;/div&gt;&lt;div&gt;知足上进，不负野心，各自努力，顶峰相见！&lt;/div&gt;&lt;div&gt;2020年度内外贸业绩冠军、亚军、季军表彰，高手过招，风景这边独好！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525150510133.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251505325P.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;“积极向上，热爱生活，找差距，强弱项，认真对待每一件事，定有收获”&lt;/div&gt;&lt;div&gt;2020豫工年度销冠——国内事业部魏红岩、国际事业部刘建华分享工作方法，鼓励大家保持热爱，厚积薄发。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251506312B.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525150A2324.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;优秀团队表彰&lt;/div&gt;&lt;div&gt;有人说：千人同心，则得万人之力；万人异心，则无一人可用！&lt;/div&gt;&lt;div&gt;豫工一直注重团队向心力的打造，追求一群人、一条心、一个目标、一起奋斗，所向披靡，战无不胜。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525150JKP.jpg&quot; style=&quot;width: 695px; height: 480px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515092S43.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525151011624.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;百万英雄表彰&lt;/div&gt;&lt;div&gt;2020精彩纷呈，豫工人凭借历久弥坚的决心，勇闯百万的勇气，涌现出许多百万业绩精英!&lt;/div&gt;&lt;div&gt;今天是他们的高光时刻！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515111YR.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251511391G.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;优秀运营表彰&amp;nbsp;&lt;/div&gt;&lt;div&gt;成绩的取得，离不开市场人员辛勤付出，是他们凭借敏锐的市场感知力，深挖客户需求，助力研发部门优化设备功能，推出切实符合工程需求的设备！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525151505458.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525151520R3.jpg&quot; style=&quot;width: 695px; height: 383px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525151P9411.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;十大领军人物表彰&lt;/div&gt;&lt;div&gt;航海千里，成于罗盘！在公司有这么一群人，他们肩挑领跑者的责任，心怀冲锋者的闯劲，勤勉务实，敢为人先，他们是业务团队的领头羊！他们是豫工机械业务团队的领军者。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152004441.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152325135.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;明日之星表彰&lt;/div&gt;&lt;div&gt;2021，豫工涌现出了一批执行力超强的业务精英，他们的成绩有目共睹，工作中不讲如果，只讲结果！步履不停，奋斗不止，终于成长为公司的业绩担当，荣获豫工机械明日之星称号。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152503244.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152605205.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;未来之星表彰&lt;/div&gt;&lt;div&gt;奋斗的路上，没有奇迹，只有努力的轨迹；没有运气，只有坚持的勇气，每一滴汗水都是成功的积累！&lt;/div&gt;&lt;div&gt;2021，豫工很多小伙伴在工作中展现巨大爆发力，目标坚定，温柔上进，持续努力，未来可期，喜获未来之星荣誉称号！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515292G45.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152944V5.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;优秀表彰致辞&lt;/div&gt;&lt;div&gt;“分享、担当、感恩、自信、坚毅”，豫工总经理为活动致辞 ，再次分享公司企业文化，揭秘豫工机械16年保持高速发展的能量源泉！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153111320.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;风雨同舟者赢，上下同欲者胜&lt;/div&gt;&lt;div&gt;有人说你相信什么，就会吸引什么！你怀疑什么，就会失去什么，这就是相信的力量，这就是成功的秘籍！&lt;/div&gt;&lt;div&gt;年度股东分红，让我们再次见证相信的力量！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515324C15.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153300J3.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;豫工十六年发展，终成今日势，跨越式发展步伐，吸引众多优秀员工成为股东，风雨同舟，荣辱与共，推动豫工这艘航船稳步向前，再创新高！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515340J40.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153431Y9.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;女神篇&lt;/div&gt;&lt;div&gt;恰逢521全民表白日,豫工机械特设第一届女神节，鼓励大家怀揣公主梦，装着女王心，&lt;/div&gt;&lt;div&gt;勇敢展现自己的美，独立、优雅、自信、坚韧、洒脱、有底气、做自己，不负时光，活得漂亮！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515353U03.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153552L6.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515360S18.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251536203H.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251536339A.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153Q3a5.jpg&quot; style=&quot;width: 695px; height: 451px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153P1V6.jpg&quot; style=&quot;width: 695px; height: 434px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153RR22.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;\r\n 无论是女王节还是女神节，往后余生，祝愿豫工这群可爱且善良的女生，眼中有光，心中有爱，温柔中带着刚强，努力优秀，大方拥有，有所为，有所爱，有所期待！&lt;br/&gt;\r\n &lt;strong style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px; text-indent: 32px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;&lt;/div&gt;'),
(233, 1, 9, '&lt;div&gt;端午来啦！&lt;/div&gt;&lt;div&gt;老板实力宠员工&lt;/div&gt;&lt;div&gt;&lt;div&gt;2盒粽子，2箱水果&lt;/div&gt;&lt;div&gt;啧啧......豪横，果然是中国好老板！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-2106111434414Z.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;丰厚的节日福利&lt;/div&gt;&lt;div&gt;是公司对中国文化的传承&lt;/div&gt;&lt;div&gt;更体现了对豫工家人细致入微的关怀&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143545919.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-2106111436032W.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143F4611.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;其实，每逢传统佳节&lt;/div&gt;&lt;div&gt;公司都会为客户朋友和豫工家人精心准备节日贺礼&lt;/div&gt;&lt;div&gt;这个习惯，豫工一干就是16年！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143K4933.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143PSA.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143RDW.jpg&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;福利发放现场，&lt;/div&gt;&lt;div&gt;欢声笑语！&lt;/div&gt;&lt;div&gt;大家暂时放下手中繁忙的工作，&lt;/div&gt;&lt;div&gt;聚在一起，享受节日的快乐！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143ZR25.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-2106111439463V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-2106111439593L.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144029260.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144055K8.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;国内事业部员工风采&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144120103.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144136439.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144149318.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144200196.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;国际事业部员工风采&lt;br/&gt;今年端午，赶上公司16周年庆典 为回馈新老客户的关爱 老板特批优惠方案 推出年中大促活动（2021年6月6日-6月30日） 价格一降到底，还有定金翻倍抵货款 买的多，更省钱。 &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/66ef65e24136a2e.jpg&quot; style=&quot;width: 695px; height: 350px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;心如糯米，越粘越紧，&lt;/div&gt;&lt;div&gt;情似粽叶，越煮越香。&lt;/div&gt;&lt;div&gt;端午佳节&lt;/div&gt;&lt;div&gt;我们向长期信任和支持豫工的客户朋友送上真诚的节日祝福&lt;/div&gt;&lt;div&gt;恭祝大家：事业顺利，生活安康，“粽”享幸福，端午安康！&lt;/div&gt;&lt;p&gt;&lt;br style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;&quot;/&gt;&lt;strong style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;span style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px; line-height: 32px; text-indent: 32px; display: inline-block; color: rgb(85, 85, 85);&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(234, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/fecdcd3ff85e2ee.jpg&quot; style=&quot;width: 695px; height: 1175px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;&lt;div&gt;根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，端午节放假安排如下：&lt;/div&gt;&lt;div&gt;1、2021年端午节放假共3天，时间为2021年6月12日至6月14日，6月15日（星期二）正常上班。&lt;/div&gt;&lt;div&gt;2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;&lt;div&gt;3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;&lt;div&gt;祝愿大家过一个安全、惬意、有意义的端午节！&lt;/div&gt;&lt;div&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;'),
(235, 1, 9, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;&amp;nbsp;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify;&quot;&gt;7月23日，豫工机械郑州西峡商会捐赠的12.8万元善款，已筹集4辆车的救灾物资，在河南红十字会的统一调配下，发往灾区！董事长李红旗先生携部分员工代表，义工一天，帮忙装车！&lt;br/&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/c040fab02f18135.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164H6492.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify; font-size: 18px;&quot;&gt;7月20日，台风“烟花”携带的强降雨席卷郑州，千年不遇的降雨量令河南1300万人民群众的生命和财产遭受巨大的损失，全国 各省市兄弟单位星夜驰援。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164R6355.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164Q31S.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;董事长李红旗先生第一时间捐款12万元用于抗洪救灾，并带领公司全体员工连续三天开展赈灾义卖，筹集救灾善款30余万元。&lt;br/&gt;\r\n &lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164U4624.jpg&quot; style=&quot;width: 695px; height: 1042px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;letter-spacing: 0.544px; font-size: 18px;&quot;&gt;李总表示：尽管我们也受灾，厂区被淹，但在大是大非，大灾大难面前，我们还应当义不容辞地腾出余力，自救的同时，向同胞伸出援手，这是企业价值所在，也是企业回馈社会、反哺社会的责任所在，必须履行好。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I016493YE.jpg&quot; style=&quot;width: 695px; height: 584px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I016494X18.jpg&quot; style=&quot;width: 695px; height: 452px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;span style=&quot;letter-spacing: 0.544px; font-size: 18px;&quot;&gt;企业有担当 社会有能量！只要国家、社会有需要，豫工机械一定义不容辞，不忘初心，勇担使命，传递正能量！就如这次“720特大暴雨洪灾”，我们一定尽心竭力，自救救人，与灾区人民风“豫”同舟！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01A113139.jpg&quot; style=&quot;width: 695px; height: 313px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01A135291.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01A212Z1.jpg&quot; style=&quot;width: 695px; height: 419px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;span style=&quot;letter-spacing: 0.544px; font-size: 18px;&quot;&gt;三天义卖结束后，全体员工同事一致意愿把每年的7月20日，设为公司的爱心慈善日（720爱心慈善日），成立专款专用的爱心慈善基金，每年720当天义卖 所得善款全部注入爱心慈善专项基金，用于慈善事业和爱心捐助。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01A32X61.jpg&quot; style=&quot;width: 696px; height: 666px;&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px; line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;'),
(236, 1, 9, '&lt;div&gt;2021年2月6日，豫工售后与技术支持部乔工来到水利七局项目工地——郑州地铁8号线五龙口地铁口，安装调试液压湿喷机。&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406094355Y2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040609521Q58.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;/div&gt;&lt;p&gt;订购单位中国水电7局，隶属于中国电建，承建郑州地铁8号线建设项目。 客户对喷射距离、产品质量、售后服务非常看重，曾亲自到工厂考察，对工厂生产实力、产品品质很放心。 &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/69456cf68759.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;br/&gt;客户所选机型为90型单喷头液压湿喷机，具有泵送压力大、输送距离远、回弹率低、施工效率高等优势，生产能力7㎥/h,配合空压机正常施工，喷射距离100米，垂直扬尘60米。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406094511R6.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;/&gt;&lt;br/&gt;试机中，在16/10空压机的配合下，液压湿喷机喷射距离达到100米，完全满足客户要求&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040609462a52.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;br/&gt;客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406094FM63.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(237, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 中秋佳节，豫工的福利真是.......这是老板要向我们表白吗？&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/8a49f433b55cdde.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;br/&gt;福利发放现场，大家暂时放下手中繁忙的工作，聚在一起，享受节日快乐&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120013401.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120034I8.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040612004TB.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120102Q2.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061201224D.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120135332.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120155449.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;一份中秋礼品代表一份美好的祝福，传递出豫工对大家浓浓的关爱，这里不仅是豫工人的发展平台，更是豫工小伙伴们相亲相爱的大家庭。 &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120229512.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120244545.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061203113D.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120334142.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;报道称,中秋圆月将出现在10月2日,国庆、中秋喜相逢,有人说：今年国庆和中秋是用来弥补春节遗憾的,国兴、家睦、月明,祖国快乐、月亮快乐、你我也快乐 满大街扬起的国旗和满街飘香的月饼,彰显祖国国泰民安 阖家团圆,国和家撞了个满怀,正如豫工和亲爱的客户朋友,坦诚相待 携手同行&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(238, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 端午粽飘香，欢乐事儿忙！为迎接端午佳节的到来，表达公司对员工的关爱，2020年6月22日，按照公司惯例，豫工机械提前为大家发放暖心福利，表达节日问候。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F9202D57.png&quot;/&gt;&lt;br/&gt;豫工历来重视中华民族的传统节日，自公司成立至今十五年间，每年节假日都会给员工发放节日福利，更是把大家当家人看待，感谢大家一直以来的辛勤付出，共享企业发展的成果。&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/12ac96f85623d4b.png&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F9211T46.png&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F92132129.png&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F923212I.png&quot;/&gt;&lt;br/&gt;端午历来有消灾去病的习俗。在北京疫情依然严峻的形势下，豫工借五月端午，祝愿大家迎祥纳福，辟邪消灾，平安健康！祝愿祖国繁荣昌盛，国泰民安！&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(239, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2020年12月21日，在郑州总部营销中心，豫工机械金秋表彰暨收官大战启动仪式火热开场，全体员工180多人参加活动。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113S1254.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;迎新环节&lt;/div&gt;&lt;div&gt;虽历15年，豫工依然保持高速发展状态，员工队伍不断壮大。为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家打开自己，融入团队。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113TR63.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n 金秋大战60天，在豫工人的共同努力下，拿下了2020年同期棒的成绩，销售业绩突破3700万。其中，老客户返单率直线飙升，突破52%。&lt;br/&gt;\r\n 大战期间，豫工涌现出了许多业绩标兵，百万英雄，服务之星，优秀团队。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113U9143.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113913W8.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/58e26e964a568d3.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040611395a28.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n 有人说：千人同心，则得万人之力；万人异心，则无一人可用！豫工一直注重团队向心力的打造，追求一群人、一条心、一个目标、一起奋斗，所向披靡，战无不胜。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040611401Q94.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406114039537.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040611405Q18.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406114114634.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406114154R1.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406114222230.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n 一分耕耘未必有一分收获，但是九分耕耘，必定会有一分收获。金秋大战期间，小伙伴们用实际行动证明了，这世间，唯有努力和坚持不可被辜负。&lt;br/&gt;\r\n &amp;nbsp;&lt;/div&gt;');
INSERT INTO `dr_1_xinwenzhongxin_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(240, 1, 9, '&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 客户服务无小事！江西武吉高速九岭山隧道，客户第一次使用液压湿喷机，售后人员耐心讲解，获客户由衷感谢。豫工机械致力于服务是公司核心竞争力的打造，客户至上，服务如一！&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/1470c09c16c80d4.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505111505c0.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505111515c3.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;本次客户订购的是豫工单喷头液压湿喷机表现出色，生产能力7 m3/h ，搭配16立方空压机，输送距离可达100米，喷射混凝土密实、匀质、高强度，效果、效率远超客户预期。&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-21050511262HY.png&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505112F2928.png&quot; style=&quot;width: 695px; height: 395px;&quot;/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-21050511264T06.png&quot; style=&quot;width: 695px; height: 396px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！&lt;br/&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 14px; text-indent: 0px;&quot;&gt;&lt;span style=&quot;font-size: 18px; color: rgb(0, 0, 255);&quot;&gt;豫工机械&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;拥有20余年隧道喷浆设备研发生产经验，匠心质造，品质如一！规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/span&gt;&lt;/p&gt;'),
(241, 1, 9, '&lt;div&gt;安全生产 消防为先，8月4日下午4点，豫工机械开展消防安全讲座。&lt;/div&gt;&lt;div&gt;公司特邀河南省护民防火中心祝教官，前往总部营销中心，为大家讲解消防安全知识，全体员工140多人参加。&lt;/div&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F95235R3.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/p&gt;&lt;div&gt;祝教官对近年发生的火灾以图片、视频的形式提高大家消防安全意识，从贴近生活，实用性强的单位、家庭用气、用电、夏季汽车自燃等方面入手，讲解消防知识，和火灾初期如何灭火的方法，提高大家防灾减灾能力！&lt;/div&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F953201T.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;\r\n 祝教官现场演示灭火器“一摇、二拔、三瞄、四压”的操作流程，介绍防火毯、防烟面具等消防器材的使用方法，火灾现场如何紧急疏散和逃生自救等知识，提高大家对突发事件的紧急处置能力。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/4fbed461b8ab5f7.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F9540MG.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/p&gt;&lt;div&gt;此次讲座豫工小伙伴再次感受中国消防官兵的美逆行，火灾面前，他们总是冲在一线，狭路相逢，火口夺人！&lt;/div&gt;&lt;div&gt;防患于未“燃”，是对他们好的致敬！大家纷纷表示要将学到的消防知识教给家人、朋友和身边的每个人，为提高社会整体消防意识尽自己的一份力。&lt;/div&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F95351S8.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;font-size: 15px;&quot;&gt;豫工机械作为工程机械类大型综合性企业，人员众多，设备沉重，消防安全重于泰山。此次培训，进一步增强了企业消防安全意识，为全面消除火灾隐患、创建稳定的工作环境打下坚实基础。&lt;/span&gt;&lt;/p&gt;'),
(242, 1, 9, '&lt;div&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1.8px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;战前OUTING&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1.8px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;豫工机械一年一度的金秋大战即将拉开序幕，为了让大家以更好的状态决战金秋，公司组织小伙伴们畅游北京，三天两夜的行程，大家放空自己，调整状态，争取打出牛的战绩！&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/9ae6451169e34eb.jpg&quot; style=&quot;width: 691px; height: 405px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;豫工机械金秋大战于每年9月15日-11月15日期间举行，与旺春大战（每年3月16日-6月30日）一样，公司将采取各种促销活动让利客户，有求必应做好售后服务，保证在金九银十的工程建设旺季，为广大客户朋友提供高品质、高性价比的设备，及时发货和高效施工！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94PS94.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94S0392.jpg&quot; style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; font-size: 12px; width: 691px; height: 518px;&quot;/&gt;&lt;/p&gt;&lt;div&gt;来到北京，小伙伴们的每个细胞都充盈起来，所求皆所愿，所见皆所喜，祝福祖国，祝福豫工，祝福每一个追梦人&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94T4620.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94U33Y.jpg&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;三天的美好时光,豫工的小伙伴们对工作按下暂停键,寄情山水，放空自己,争取以好的状态,迎接即将到来的金秋大战,努力工作，用心服务,用百分百的热情去朝着新的、更高的目标进发！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(243, 1, 9, '&lt;div&gt;7月18日，河南豫工机械,“认真工作，快乐生活”主题团建欢畅启程!豫工的小伙伴们集合完毕,乘坐两辆舒适的大巴向云台山进发,这次我们不谈工作，不谈业务,只谈...笑风生!&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061214235H.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;大家一路欢声笑语,工作严谨认真，生活中却不乏开朗活泼,能干会玩，是我们的标签&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040612161HR.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061216303b.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406121A2G6.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;em&gt;太行山把美的一段给了河南！焦作云台山，山美 水美 云美 泉美!还有豫工的小姐姐更美！美得不像话!!!&lt;/em&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406121K4600.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406121Q6223.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406121S1323.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;em&gt;大家来到小寨沟，这里被称为北方九寨沟!三步一泉，五步一瀑，十步一潭,小伙伴结伴而行!瀑布 小溪 竹筏 猕猴谷，玩的不亦乐乎！&lt;/em&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061220045H.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061220204O.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406122044244.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;em&gt;晚上，豫工机械2020旺春表彰，在云台山风景区会议大厅隆重举行百天旺春大战圆满收官，成绩引人注目，在过去100天，豫工产值突破3000万，国际事业部，更是以200%的业绩完成率超越了2019全年业绩之和，今晚注定是一个不眠之夜！&lt;/em&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/8e479100322c935.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406122552226.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;em&gt;第二天，伴随着山间清凉的风和偶尔飘来的雨丝，经过15座山，19个洞，三千多个台阶，终于到达茱萸峰，登顶而立 云锁雾绕 人间仙境，呼吸着没有PM2.5的空气，感受风的自由，果然，越往上，风景越好！就像豫工的小伙伴，勇往直前，不负韶华！&lt;/em&gt;&lt;br/&gt;&lt;br/&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(244, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2021年2月27日，豫工机械“春风十里，不如有你”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工180多人参加此次活动！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/a8d7008cc07c7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102420S7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; 豫工小姐姐化身舞林高手，精彩演绎提神洗脑神曲，可可爱爱，奇奇怪怪，换个舞台，依旧是灯光下耀眼的小姑娘&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061025125H.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 2020年，在全体豫工人的共同努力下，全年销售总额突破亿元大关;品牌知名度、市场接受度、老客户返单率直线飙升，综合上升9.2个百分点，一举突破52%。&lt;br/&gt;收官大战期间，豫工涌现出了众多业绩标兵，百万英雄，服务之星，优秀团队。今天，他们是豫工人眼中的SUPERSTAR！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102A6264.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102G3G1.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102HS19.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;旺春大战启动仪式&lt;/div&gt;&lt;div&gt;工程建设旺季随春而至，生产订单、设备售后、物流跟踪......等客户需求井喷式爆发，豫工特发起百天旺春大战冲锋号，与客户同频，以“起跑即冲刺、开局即决战”的奋发姿态，大干100天，打好开局战。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102SCD.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102TMS.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102Z4511.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061029193A.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; 奋斗赋予时间意义，其实，每个人的好运气都藏自己的实力里，藏在那些不为人知的努力里，看似波澜不起的日复一日，会突然在某一天让我们看到坚持的意义，2021，豫工小伙伴，加油!\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(245, 1, 9, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, Microsoft YaHei;&quot;&gt;经过邮件来往沟通，2020年4月29日，以色列客户来我司工厂参观考察 &lt;/span&gt;&lt;img alt=&quot;以色列客户考察豫工锚固钻车&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZS95I.jpg&quot; style=&quot;width: 691px; height: 517px;&quot; width=&quot;691&quot; height=&quot;517&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;以色列客户考察豫工锚固钻车&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, Microsoft YaHei;&quot;&gt;国外以色列客户来访，要目的是为了商讨豫工锚固钻机后续大批量订单交期及质量控制事宜。 &amp;nbsp;&lt;/span&gt;&lt;img alt=&quot;以色列客户考察豫工锚固钻车&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZUO33.jpg&quot; style=&quot;width: 691px; height: 517px;&quot; width=&quot;691&quot; height=&quot;517&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;以色列客户考察豫工锚固钻车&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;以色列客户考察豫工锚固钻车&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/bdc94983a653151.jpg&quot; style=&quot;width: 691px; height: 517px;&quot; width=&quot;691&quot; height=&quot;517&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;以色列客户考察豫工锚固钻车&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size: 18px; font-family: 微软雅黑, Microsoft YaHei;&quot;&gt;经过多次的沟通，该客户对我司有了更深更好的了解。经过此次会谈，我们产品的技术和质量，价格优势，订单交期，服务方面得到了客户的认可，客户表示将与河南豫工机械长期订单合同，同时客户还表达豫工机械将成为自己核心的供用商。 &amp;nbsp;&lt;/span&gt;&lt;img alt=&quot;以色列客户考察豫工锚固钻车&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZ929C6.jpg&quot; width=&quot;691&quot; height=&quot;517&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;以色列客户考察豫工锚固钻车&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;以色列客户考察豫工锚固钻车&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZ94H11.jpg&quot; style=&quot;width: 691px; height: 518px;&quot; width=&quot;691&quot; height=&quot;518&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;以色列客户考察豫工锚固钻车&quot;/&gt;&lt;/p&gt;'),
(246, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;2020年5月18日，河南豫工机械第八届司庆日暨表彰大会在郑州禧逸酒店隆重召开。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91455L0.png&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify;&quot;&gt;首先豫工生日趴，小伙伴们和主持人一起齐声祝福“河南豫工，生日快乐”。这时灯光熄灭，伴随着生日快乐歌，我们的大蛋糕上场了，大家热情高涨的唱着生日歌，歌声刚落下，我们的小伙伴们就向着蛋糕蜂拥而上，蛋糕的香甜味道弥漫在会场的上空，整个大厅都沉浸在一片欢乐的海洋……&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/5bbcb23e4cae.png&quot;/&gt;&lt;br/&gt;分享完蛋糕，接下来是我们的年度表彰环节，首先是我们2019年度销售冠亚军，他们出类拔萃，一直是公司的骨干精英，分别获得5000、8000的现金奖励，董事长李红旗先生和冠亚军进行合影留念！ &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F9153Y55.png&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91556362.png&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91622350.png&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;下面开始我们的重头大戏，也是各位股东们期盼的环节，那就是我们的股东分红……&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91A2F2.png&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;盛世谱华章、春秋铸辉煌，从星光点点到阳光璀璨，回首过去我们激情澎湃，把握现在我们豪情满怀，展望未来我们信心满满，让我们一起携手并肩，志存高远，实现河南豫工新跨越，共同再创辉煌！&lt;/span&gt;&lt;br/&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(247, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 车载绿篱修剪机的价格一直是每个客户关心的问题，但是，目前国内绿篱修剪机生产厂家众多，竞争激烈，各厂家会定期推出优惠政策，给出的报价不一！另外，市场平均价格水平，配置型号，安装调试，运送距离，发票等因素，都会影响产品最终报价！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401151S3440.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;公路绿篱及边坡灌木修剪专用设备&lt;/div&gt;&lt;div&gt;在没有绿篱修剪机之前，都是通过人工修建的方式，这种方式的缺点非常明显，不仅效率低下，而且也存在一定的安全问题，所以绿化带修剪机的出现，不仅解决了这个问题，还提高工作效率，使有限的劳动力发挥更加的作用车载式绿篱修剪机定做。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401151925431.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;豫工机械研发生产的车载式树篱修剪机只需在车辆驾驶室内就可完成修剪操作，而且修剪高度高，速度快，修剪效果好。可实现平剪、立剪、斜剪等动作，完全替代了人工，保证了安全作业。&lt;/div&gt;&lt;div&gt;豫工机械车载绿篱修剪机臂长，1.5-2m&amp;nbsp; &amp;nbsp;修剪高度1.8米，臂长类型1米-8米，既能够修剪直径100mm的粗树，也能修剪通常的绿篱。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/93740695e793292.jpg&quot; style=&quot;width: 838px; height: 1117px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;绿篱修剪机价格&lt;/div&gt;&lt;div&gt;车载式绿篱修剪机价格在6-8万、10-20万不等，之所以价格区间、跨度如此之大，主要原因在于各类设备型号多样、配置多样，运费、发票、售后服务不同，最终所呈现出的报价相差也就比较大。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040115205a32.jpg&quot; style=&quot;width: 838px; height: 791px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;如果您有购置绿篱修剪机的打算，可以点击&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://pwt.zoosnet.net/LR/Chatpre.aspx?id=PWT55787204&amp;lng=cn&quot;&gt;立即咨询&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;按钮，豫工机械产品经理为您提供一对一选型指导并报价，心动不如行动，快快咨询选购吧！&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机等，17年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/div&gt;'),
(248, 1, 10, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;近段时间，来豫工机械询问路面抛丸机的客户不在少数，小编将其中问到较多的问题进行了汇总，包括路面抛丸机的工作效率、工作宽度、适用环境、性能特征、价格等要点，小编为大家统一汇总，以便大家参考。&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/e12d4b0a90de7b7.png&quot; style=&quot;width: 838px; height: 493px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;混凝土路面抛丸机能够一次将混凝土表面的浮浆、杂质清理和清除干净，最重要的是在同时对混凝土表面进行了打毛处理，使其表面均匀粗糙，大大提高防水层和混凝土基层的黏结强度。而且在此过程中，抛丸工艺能够充分暴露混凝土的裂纹等病害，以便提前采取补救措施。&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401151410342.jpg&quot; style=&quot;width: 838px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;a href=&quot;https://www.zzyugong.cn/show-156.html&quot; target=&quot;_self&quot; title=&quot;豫工抛丸机&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工路面抛丸机&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;适用那些场景？&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401151513J9.png&quot; style=&quot;width: 838px; height: 652px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工路面抛丸机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械路面抛丸机通过机械方法把丸料以很高的速度和角度抛射工作表面，去除表面残留物并打毛。除尘器产生的负压将丸料和杂质粉尘等回收，经气流清洗后，完好的丸料自动循环使用，杂质和粉尘落入收尘箱中。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;适用范围&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;防水表面清理、打毛&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;道路标线清理、翻新&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;机场跑道除胶、除线&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;大型邮轮甲板、储油罐底除锈&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;产品优势&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;自动行走，操作简单，有效降低劳动强度&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;一次性清理，表面干净整洁粗糙面均匀&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;整个过程无尘、环保&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械路面抛丸机热销款价格在五万左右，不同的型号配置，其价格也不太一样，想了解路面抛丸机的详细报价和更多信息，可&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;联系&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械产品经理免费为选型报价，感兴趣的朋友也可以到厂实地考察一番，我们将竭诚为您服务！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;a href=&quot;https://www.zzyugong.cn&quot; target=&quot;_self&quot; title=&quot;郑州豫工机械&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;郑州豫工机械&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机等，20余年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/span&gt;&lt;/p&gt;'),
(249, 1, 10, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;什么是混凝土凿毛机？&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;混凝土凿毛机是一种把已经完成的主体结构面进行处理，使两个施工阶段的施工面粘结牢固的类似于&amp;quot;斩斧&amp;quot;的工具。通常凿毛机是应用在在现浇混凝土结构中，在现浇板浇注完毕后，要凿毛，进行下一层的浇注，让混凝土粘结牢固。&lt;br/&gt;\r\n &lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/07b91d73d0bdc97.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;\r\n &lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械22头机载凿毛机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;a href=&quot;https://www.zzyugong.cn/show-154.html&quot; target=&quot;_blank&quot; title=&quot;豫工机载凿毛机&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机载凿毛机&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;可对任何作业面做任意角度凿毛&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;C50混凝土凿毛深度5mm，效率120㎡/h&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;C40混凝土凿毛深度5mm，效率150㎡/h”&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;相较于配套挖机凿毛设备而言，22头凿毛机价格十分优惠，大概在2万左右，配套挖机机载凿毛机价格在8-10万不等。&lt;br/&gt;\r\n &amp;nbsp;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401150115520.jpg&quot; style=&quot;width: 838px; height: 628px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;市场上生产机载凿毛机厂家有很多，选择郑州豫工机械的客户却很多，主要原因在于它成立20余年来，经历了时间和市场的考验，质量可靠、型号齐全、售后完善，价格低于市场平均价，豫工机械实行仓储式管理，现货直发，全国联保！9大产品系列生产基地，&lt;a href=&quot;https://www.zzyugong.cn/list-chanpinzhongxin.html&quot; target=&quot;_self&quot; title=&quot;豫工机械设备&quot; style=&quot;font-size: 18px; text-decoration: underline;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械设备&lt;/span&gt;&lt;/a&gt;满足不同客户定制需求。&lt;br/&gt;\r\n &amp;nbsp;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040115015M59.jpg&quot; style=&quot;width: 838px; height: 630px;&quot;/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;如果您目前有购置设备的需求，可&lt;/span&gt;&lt;span style=&quot;font-size: 18px; text-decoration: none;&quot;&gt;咨询豫工机械厂家&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;了解详情，也可预约VR看厂进行考察！旺春时节，豫工机械优惠多多，不要犹豫，快咨询选购吧！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;a href=&quot;https://www.zzyugong.cn&quot; target=&quot;_blank&quot; title=&quot;郑州豫工机械&quot;&gt;&lt;span style=&quot;font-size: 18px; text-decoration: none;&quot;&gt;郑州豫工机械&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,机载凿毛机等，20余年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/span&gt;&lt;/p&gt;'),
(250, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/a83e7b70d411899.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify; text-indent: 34px;&quot;&gt;智能张拉设备在进行张拉作业之前，除了要对张拉设备的构件进行检验，还有几个不能忽视的地方，一起来看一下吧。&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;1、开机后如果发现主从控制柜通讯不上的问题，需要先检查通讯线是否连接正常或有断线，如果没有需要重新启动系统。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;2、在张拉过程中油管和控制电缆要顺直，不得扭曲打卷，防止扯断油管和电缆。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;3、在张拉过程中如果出现问题应首先按下控制柜面板上“油泵停止“按钮，不能强行继续张拉。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;4、在移动设备的过程中，泵站、千斤顶和控制系统要搁置在专用小车上，注意油管和连接线不能扭曲和拉断。一般情况下千斤顶和泵站油管不准拆卸。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;5、千斤顶的磨阻会随着使用时间而改变，应按工艺要求对千斤顶进行周期校验。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;6、智能张拉系统张拉过程中，预应力钢绞线出现断丝现象，千斤顶严重漏洞，调换千斤顶时，均应重新使用标准力校正系统校核张拉机具。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;7、油泵运转有不正常情况时，必须立即停车检查。在有压情况下，严禁随意拧动油泵或千斤顶各部位的螺丝。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;8、电源连接线必须接零线并保证连接正确，否则损毁控制箱电路板，设备应可靠接地，并随时检查各处绝缘情况，避免触电。&lt;/span&gt;&lt;/p&gt;&lt;section style=&quot;margin: 0px; padding: 0px; max-width: 100%; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; font-size: 14px;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; overflow-wrap: break-word !important;&quot;&gt;智能张拉设备作业时的注意就说到这里，更多的产品知识可以关注我们的网站或直接电话咨询。&lt;/span&gt;&lt;/span&gt;&lt;/section&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;'),
(251, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/1095bf2790d3ce0.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;预应力机械顾名思义就是强化产生预应力并进行施工的机械设备，这种机械通常必须要具备产生很大外力的能力，因为受力模块本身通常具有很强的刚度和硬度，普通机械很难起到作用，预应力机械便发挥了作用。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;在各种工程结构构件承受外荷载之前,对受拉模块中的钢筋等受力模块，施加预拉应力，提高构件的刚度和硬度，推迟裂缝出现的时间，增加构件的耐久性。对于机械结构来看，其含义为预先使其产生应力，其好处是可以提高构造本身刚性和硬度，减少受拉模块的振动和弹性变形。这样做可以明显改善受拉模块的强度，使原本的抗性更强。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;在结构承受外荷载之前，预先对在外荷载作用下的受拉区施加压应力，以改善结构使用的性能的结构型式称之为预应力结构。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;举例：预应力是在混凝土凝结前用钢筋机械把混凝土中的钢筋适度拉伸着，在混凝土凝结后撤去外力，钢筋就会在混凝土里产生一个收缩的应力，使钢筋混凝土强度更大。因而可以减少钢筋用量，节约钢材。&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(252, 1, 10, '&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;喷播机是边坡绿化施工的机械设备，它质量的好坏直接影响喷播效率的高低。喷播机主要用于高速公路(铁路)边坡绿化、边坡防护、山体治理、矿山复绿、荒漠治理等工程。因此，用户在购买时，会有很多问题注意。下面我们来看选购喷播机时需要注意哪些事项。&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;b5f30b294235aeb3644e08e2345dffd&quot; src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202601/1768803459e09048.jpg&quot; style=&quot;width: 695px; height: 472px;&quot; title=&quot;b5f30b294235aeb3644e08e2345dffd&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;一、选择合适的型号&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;喷播机常按不同的喷播对象分为客土喷播机和液力喷播机。合适的型号才能发挥出喷播机效用。要选择合适的型号，我们需要从两个方面考虑：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1、 根据边坡类型选择型号：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;边坡的高度、坡度都是影响选型的重要因素，高度和坡度越大，相应选配的发动机功率就越大。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2、 根据喷播厚度进行选择：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;一般客土喷播要求5-10公分，就要选用客土喷播机;液压喷播或喷播1-2公分可选用液力喷播机(&lt;a href=&quot;https://www.zzyugong.cn/show-150.html&quot; target=&quot;_blank&quot; title=&quot;豫工机械喷播机&quot;&gt;&lt;strong&gt;豫工机械喷播机&lt;/strong&gt;&lt;/a&gt;厂家的液力喷播机可以喷播大浓度的泥浆)。&lt;/span&gt;&lt;br type=&quot;_moz&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;二、选择合适的厂家&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1、主要注意机器罐体钢板厚度，发动机，泥浆泵，柴油机功率以及耐磨件的耐磨性能。现在生产喷播机的厂家有很多，但真正能做出经济实用方便实用的客土喷播机的厂家并不是很多。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2、在购买机器设备时要先考察好市场。实地考察更适合。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3、在购买产品时要考察该公司实力，是否在现实中真实存在的，有很多网站是没有实体公司的，所以我们要擦亮眼睛认真考核，如果条件可以的话，可以去厂家看看。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;4、看该公司产品外观设计、质量、试机效果如何。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;5、看该公司售后服务怎样，信誉度如何。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;6、再好的喷播机也要看设备自身的重量。外观相同的机器价格差很多时我们要注意看机器的内部构造，不能贪小便宜吃大亏。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;如果您正在考虑选购喷播机，不妨到豫工机械厂区看一看，选豫工机械喷播机，经济实用方便操作，24小时贴心服务，终身售后无忧。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(253, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;欧美国家自20世纪70年代以来在混凝土桥面铺装中广泛使用防水层，大大减少了混凝土桥梁因为渗水的原因而造成的损坏，延长桥梁的使用寿命。但随着交通量的增加，同时出现了防水层和面层以及桥面黏结强度不足而产生推移的病害。在我国，混凝土桥梁也经常发生类似病害，以及由于渗水甚至造成的混凝土疏松、脱落，钢筋锈蚀。造成以上病害的原因之一是因为混凝土面层的处理没有能够完全去除表面残留物质，没有保留一定的粗糙表面来保证防水层和桥面底层的黏结强度。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/e76564a1588e58e.jpg&quot; style=&quot;width: 611px; height: 344px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;抛丸工艺能够一次将混凝土表面的浮浆、杂质清理和清除干净，最重要的是在同时对混凝土表面进行了打毛处理，使其表面均匀粗糙，大大提高防水层和混凝土基层的黏结强度。而且在此过程中，抛丸工艺能够充分暴露混凝土的裂纹等病害，以便提前采取补救措施。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/9294f17b53b24b7.jpg&quot; style=&quot;width: 611px; height: 458px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;让顾客用上放心的设备是豫工机械一直以来坚持的使命，我们的愿景是依中原为根基，服务全国，走向世界。路漫漫其修远兮，吾将上下而求索，企业发展之路永无止境，豫工机械将始终坚持以合法合规经营为基本原则，以过程管理为核心，以两化融合为手段，建立企业一体化管理体系，以支撑企业卓越发展。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;http://yongjiu.hnyugong.com/uploads/allimg/210325/2-210325153421E7.jpg&quot; style=&quot;width: 611px; height: 454px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_xinwenzhongxin_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(254, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 1px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/55bad77d53d0.png&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;防水早已不再是一个新鲜的话题，不论是隧道、桥梁、堤坝、道路、建筑还是我们日常居住的房屋，防水都不容忽视。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;相对于老式的防水方式的笨重和繁琐，豫工推出非固化防水材料喷涂设备，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;对于非固化设备的选购，许多人没有眉目。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;有的人贪图便宜，去买一下低价位的产品，有的人只看外表，购买一些外表看起来很好的机器，其实这些做法都是不正确的，一个合格的非固化设备厂家应该具备优秀的产品，国家安全认证以及完善的服务体系，针对这些问题，今天非固化设备厂家就来教大家如何选择一套靠谱的非固化设备。&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;众所周知，由于沥青涂料的特殊性，经常有施工人员不熟悉机器的使用或是因为机器安全性能低而被沥青灼伤。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;且由于沥青加热后会变为流体。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;如果机器内部构造不严密就有可能被沥青侵入，造成大面积损坏。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;更有喷溅，起火等等一系列让人头痛的安全问题。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;对于以上这些安全问题，专业的设备工程师知道解决设备使用问题。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;防护服，防护镜等一系列确保施工人员安全的物件。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;稳定的机器出料口防止沥青喷溅，科学严密的内部构造防止沥青渗漏。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;工程研发部门研发定制的发动机防止机器起火等等。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;一系列安全隐患问题得到了很好的解决。&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;俗话说得好，时间就是金钱。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;当今社会。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;效率就代表着一切。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;就好像脱桶器的脱桶速度，熔胶机的熔胶速度和熔胶量无一不是施工效率的决定因素。豫工&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;非固化喷涂机一分钟脱桶，三分钟熔胶。&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;相信很多施工队都遇到过这样的情况，购买了一套设备，付过款以后卖方就音信全无，要不就是推推拖拖，只能靠施工方自己摸索使用，费时费力。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;所以您在选购非固化设备的同时一定要着重看一下该公司是否有完善的售后服务体系，这样才能确保您以后的设备使用放心。&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; text-indent: 34px; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;让顾客用上放心的设备是豫工机械一直以来坚持的使命，我们的愿景是依中原为根基，服务全国，走向世界。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; text-indent: 34px; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;路漫漫其修远兮，吾将上下而求索，企业发展之路永无止境，豫工机械将始终坚持以合法合规经营为基本原则，以过程管理为核心，以两化融合为手段，建立企业一体化管理体系，以支撑企业卓越发展。&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(255, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 目前，液压铣刨机型号比较多，其中，电机款统用18.5KW；300型也有15KW的，300型和350型适合2公分左右、3公分之内铣刨;500型适合半公分左右、1公分左右铣刨等，因施工要求、设备型号、配置差异加大，价格也不尽相同，大部分设备价格在3万-5万左右。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/618315c3fd72a12.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;液压铣刨机主要型号&lt;br/&gt;&lt;/p&gt;&lt;div&gt;针对深度铣刨的施工要求，豫工机械热销机型是350型的电动和燃油款，4根轴、大刀片、直径110刀片、数量是76片。500型号的电动/燃油铣刨机，主要用来拉毛，深度最好在1公分左右的，使用的是6根轴&amp;nbsp; 直径60刀片 数量210片。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152509122.png&quot; style=&quot;width: 838px; height: 603px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;设备特点&lt;/div&gt;&lt;div&gt;产品配置高，本机采用进口无极变速电机，使用寿命长，刀轴刀头为钨钢合金材质，每幅刀头使用寿命长达4000平方以上。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152553562.png&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;液压自行走 无级变速！&lt;/div&gt;&lt;div&gt;可快可慢 全进口液压系统！&lt;/div&gt;&lt;div&gt;配洒水箱，绿色环保！&lt;/div&gt;&lt;div&gt;进口刀头，行走速度跟深浅、地面硬度灵活控制！&lt;/div&gt;&lt;div&gt;设计合理，操作简单，施工效率高。维护简单，使用寿命长。&lt;/div&gt;&lt;div&gt;适用范围广&lt;/div&gt;&lt;div&gt;液压铣刨机广泛用于楼房、墙面、厂房、箱梁、高速公路、桥梁、铁路、水利、电力、机场、停车场及市政、建筑、建筑装饰、加固工程等的侧面立面狭窄空间各种混凝土表面处理拉毛，从而达到粗糙度用于二次铺装。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152A9202.jpg&quot; style=&quot;width: 838px; height: 450px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;液压铣刨机价格&lt;/div&gt;&lt;div&gt;相较于进口全液压铣刨机而言，豫工机械生产的铣刨机十分优惠，大概在3-5万左右，之多以价格区间如此之大，主要在于影响设备价格的因素很多。不同型号，不同配置的设备价格也不尽相同。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152J6304.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;市场上生产的液压铣刨机厂家很多，我们向您推荐豫工液压铣刨机，因为他成立17年，经历了时间和市场的考验，除了设备质量可靠、设备型号齐全、服务流程完善，价格也是非常优惠，既可现货直发，也可按需定制。如果您目前有购置液压铣刨机的需求，可点击&lt;a href=&quot;http://pwt.zoosnet.net/LR/Chatpre.aspx?id=PWT55787204&amp;lng=cn&quot;&gt;咨询厂家&lt;/a&gt;了解详情，也可预约到厂进行考察！旺春施工旺季，豫工机械优惠多多，不要犹豫，快咨询选购吧！&lt;/div&gt;&lt;div&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机等，17年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(256, 1, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;天气回温，路面施工市场的火热程度也在随之飙升，一众基建项目的开工使得路面摊铺设备出现了供不应求的状况。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;不少客户朋友蠢蠢欲动，来咨询豫工机械关于混凝土摊铺机的型号和情况，那么一台滚轴式摊铺机有哪些型号呢？买一台三辊的摊铺机需要多少钱呢？&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot; 三辊路面摊铺机有那些型号，多少钱一台？      &quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/08b0408c6c88.jpg&quot; style=&quot;width: 838px; height: 558px;&quot; width=&quot;774&quot; height=&quot;558&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot; 三辊路面摊铺机有那些型号，多少钱一台？      &quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;路面混凝土摊铺机的型号、摊铺效果&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;摊铺排振一体机：混凝土摊铺机+排式振捣机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备参数&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;辊子配置：两辊(2个行走轮)+1根绞龙（螺旋辊）&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;动力：4KW-4极电机2台(两根行走轮，双向行走，可前进，可后退)&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;辊轴直径：219mm&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;工作效率：每分钟大概行走8-10米，每小时摊铺2600-3300平方&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;辊轮宽度8.5米(机器总长9m)排振一体机，重量约1.5吨。实际摊铺8米路面，配10根棒。&lt;br/&gt;\r\n &lt;/span&gt;&lt;img alt=&quot; 豫工三辊路面摊铺机有那些型号，多少钱一台？      &quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040115311CG.jpg&quot; style=&quot;width: 838px; height: 558px;&quot; width=&quot;774&quot; height=&quot;558&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot; 豫工三辊路面摊铺机有那些型号，多少钱一台？      &quot;/&gt;&lt;br/&gt;\r\n &lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;常规混凝土路面摊铺机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;用途和分类：常规混凝土路面摊铺机根据滚轴主要分为双辊（168型）和三辊（219型）两种。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;一条轴负责行走，一条轴负责整平，另一条负责提浆。也可多配一条螺旋轴（绞龙轴）称为四辊，该轴主要起到刮平分料作用及减轻几条轴的负担，使摊铺效果更为明显。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;主要用途：用于高铁公路，桥梁，市政道路、乡村公路、机场跑道、水利斜坡等工程的混凝土面层摊铺整平。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;主要作用：对各种公路基层和面层各种材料摊铺，整平、振实、提浆、找平，解决路面平整度、提高机械化摊铺能力、加快施工进度。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备参数&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;摊铺厚度：300mm&amp;nbsp; &amp;nbsp; &amp;nbsp; 摊铺宽度:3-6m&amp;nbsp; &amp;nbsp; &amp;nbsp; 振动频率:32Hz&amp;nbsp; &amp;nbsp; &amp;nbsp;辊轴直径:168/219mm&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;激振力:5.5kn&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 行走速度:8-10m/min&amp;nbsp; &amp;nbsp; 功率:双辊 4kw +4kw ;三辊 5.5+7.5kw&lt;br/&gt;\r\n &amp;nbsp;&lt;/span&gt;&lt;img alt=&quot; 豫工三辊路面摊铺机有那些型号，多少钱一台？      &quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040115321Jc.jpg&quot; style=&quot;width: 838px; height: 558px;&quot; width=&quot;774&quot; height=&quot;558&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot; 豫工三辊路面摊铺机有那些型号，多少钱一台？      &quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;路面混凝土摊铺机价格&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;摊铺排振一体机属于定制款，型号不同，厂家的报价也不一样，跟随钢材价格变化。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;其中辊轮宽度8.5米(机器总长9m)排振一体机，重量约1.5吨。实际摊铺8米路面，配套10根震动棒的摊铺排振一体机价格在一万四左右。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;6米排振一体机总长7m，摊铺5.5米路面，配套10根震动棒，市场价格在一万左右。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;想要了解其他摊铺排振一体机规格的价格，可以电话咨询产品经理向您推荐高性价比的设备。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;对于常规款的混凝土路面摊铺机：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;两辊（168型）6米以下，市场价在四千左右，三辊（219型）6米以下市场价在七千左右，四辊 9米（10米）价格在一万左右。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;用户也可以根据施工的要求来定制不同长度的机器，豫工机械的混凝土摊铺机最长可以到12米。根据是否另外增加无缝管，价格差别比较大！大家可以让产品经理为您介绍不同型号的详细报价。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img alt=&quot; 豫工三辊路面摊铺机有那些型号，多少钱一台？      &quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-2204011533152M.jpg&quot; style=&quot;width: 838px; height: 562px;&quot; width=&quot;774&quot; height=&quot;562&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot; 豫工三辊路面摊铺机有那些型号，多少钱一台？      &quot;/&gt;&lt;br/&gt;&lt;a href=&quot;https://www.zzyugong.cn/&quot; target=&quot;_blank&quot; title=&quot;郑州豫工机械&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px; text-decoration: none;&quot;&gt;郑州豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机、混凝土摊铺机等，20余年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;'),
(257, 1, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;众所周知，路面清理打毛是防水喷涂施工前处理的重要环节，那么&lt;a href=&quot;https://www.zzyugong.cn/show-156.html&quot; target=&quot;_self&quot; title=&quot;豫工550抛丸机&quot;&gt;豫工路面抛丸机&lt;/a&gt;在粗化打毛混凝土路面方面有那些优势呢？&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/96cbae4eca1eea8.jpg&quot; style=&quot;width: 838px; height: 558px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;防水基层处理抛丸机&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;路面抛丸机的抛丸工艺可以一次性将混凝土外表的浮浆，杂质清算洁净，同时对混凝土外表进行打毛处置，使其外表均匀粗糙，大大进步了防水层和混凝土基层的黏结强度。而且在此过程中，可以充沛暴露混凝土的裂纹等病害，以便提早采取弥补措施。所以在推系统时，有条件状况下，采用抛丸处置基面，可以更好的保证防水效果。&lt;br/&gt;\r\n &lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153643J2.jpg&quot; style=&quot;width: 838px; height: 628px;&quot;/&gt;&lt;br/&gt;\r\n &lt;/p&gt;&lt;div&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;路面抛丸机在去除水泥浮浆打毛地面方面与铣刨机相比优势明显，抛丸机效率高，操作过程干净整洁，无任何污染，不需要二次处理；抛铣机在去除浮浆时灰尘污染大、效率慢，路面打完后还需要进一步处理灰尘！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;假如大面积施工，抛丸的效率很高！总包交过来的施工基面上，混凝土残渣，疙瘩，油渍，污染等，用人工清算，十分耗工，也清不洁净，而用抛丸机则能很快处理问题，效率高。 路面抛丸机主要应用于钢铁外表清算、机场划改线工程、铁路桥面防水施工、公路桥隧路面打毛、环氧地坪外表打毛等。&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153J55Y.jpg&quot; style=&quot;width: 838px; height: 472px;&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工抛丸机生产厂家&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械拥有20余年路面清理设备生产经验，自营的路面抛丸机是混凝土和沥青地面清理打毛、钢板除锈专用环保设备，经过6次升级换代，品质稳定，故障率低，清理效率高，受到中铁建工、中交集团等重量级客户的欢迎，服务客户30000余家。&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153R3634.jpg&quot; style=&quot;width: 838px; height: 471px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; text-decoration: underline;&quot;&gt;&lt;strong&gt;郑州豫工机械&lt;/strong&gt;&lt;/span&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机等，20余年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;'),
(258, 1, 10, '&lt;div&gt;近日，有客户找到豫工机械咨询关于超大雾化扇面非固化喷涂设备的型号及价格的问题。在充分了解了这位客户的施工场景、施工面积、工人数量、项目工期后，豫工产品经理为其推荐了以下几种机型，现将其列出，以供大家参考。&lt;/div&gt;&lt;p&gt;客户需求信息&lt;br/&gt;&lt;/p&gt;&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 500px&quot;&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td&gt;项目介绍&lt;/td&gt;&lt;td&gt;90000平方地库顶板防水施工&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;喷涂物料&lt;/td&gt;&lt;td&gt;&lt;div&gt;非固化橡胶沥青防水涂料&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;现场情况&amp;nbsp;&lt;/td&gt;&lt;td&gt;客户第一次从事防水施工项目，工人无经验！&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;其他需求&lt;/td&gt;&lt;td&gt;工期紧，天气炎热，工人室外作业，希望设备高效作业，要求设备操作简单，减轻工人的工作量，能够如期完工！&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;div&gt;每天喷涂2000平方米的非固化喷涂机&lt;/div&gt;&lt;div&gt;相对于老式的防水方式的笨重和繁琐，产品经理为客户推荐豫工经典非固化喷涂防水套装：非固化喷涂机、非固化溶胶机、非固化脱桶器！特别是非固化喷涂机，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040114311b32.jpg&quot; style=&quot;width: 838px; height: 472px;&quot;/&gt;&lt;/p&gt;&lt;div&gt;非固化喷涂机一分钟脱桶，三分钟熔胶。&lt;br/&gt;\r\n 自主研发、生产加热喷涂软管，加热均匀速度快，隔热效果好，耐高温、耐高压、耐磨损，性能稳定。&lt;br/&gt;\r\n 整机轻便，体积小，适用各种负责工程项目。豫工非固化喷涂机在国内较先采用非固化定制钢泵，经久耐用，压力稳定，寿命是普通泵的三倍以上。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/fc68bd5d491028f.png&quot; style=&quot;width: 838px; height: 472px;&quot;/&gt;&lt;br/&gt;\r\n 如果您有购置非固化喷涂机的打算，可以点击&lt;a href=&quot;http://pwt.zoosnet.net/LR/Chatpre.aspx?id=PWT55787204&amp;lng=cn&quot;&gt;&lt;strong&gt;立即咨询&lt;/strong&gt;&lt;/a&gt;按钮，豫工机械产品经理为您提供一对一选型指导并报价，心动不如行动，快快咨询选购吧！&amp;nbsp;&amp;nbsp;&lt;br/&gt;\r\n &lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机等，17年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/div&gt;'),
(259, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/c7d664221684ad8.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;预应力机械顾名思义就是强化产生预应力并进行施工的机械设备，这种机械通常必须要具备产生很大外力的能力，因为受力模块本身通常具有很强的刚度和硬度，普通机械很难起到作用，预应力机械便发挥了作用。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;在各种工程结构构件承受外荷载之前,对受拉模块中的钢筋等受力模块，施加预拉应力，提高构件的刚度和硬度，推迟裂缝出现的时间，增加构件的耐久性。对于机械结构来看，其含义为预先使其产生应力，其好处是可以提高构造本身刚性和硬度，减少受拉模块的振动和弹性变形。这样做可以明显改善受拉模块的强度，使原本的抗性更强。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;在结构承受外荷载之前，预先对在外荷载作用下的受拉区施加压应力，以改善结构使用的性能的结构型式称之为预应力结构。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;举例：预应力是在混凝土凝结前用钢筋机械把混凝土中的钢筋适度拉伸着，在混凝土凝结后撤去外力，钢筋就会在混凝土里产生一个收缩的应力，使钢筋混凝土强度更大。因而可以减少钢筋用量，节约钢材。&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(260, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/b5c64fcc6058799.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify; text-indent: 34px;&quot;&gt;智能张拉设备在进行张拉作业之前，除了要对张拉设备的构件进行检验，还有几个不能忽视的地方，一起来看一下吧。&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;1、开机后如果发现主从控制柜通讯不上的问题，需要先检查通讯线是否连接正常或有断线，如果没有需要重新启动系统。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;2、在张拉过程中油管和控制电缆要顺直，不得扭曲打卷，防止扯断油管和电缆。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;3、在张拉过程中如果出现问题应首先按下控制柜面板上“油泵停止“按钮，不能强行继续张拉。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;4、在移动设备的过程中，泵站、千斤顶和控制系统要搁置在专用小车上，注意油管和连接线不能扭曲和拉断。一般情况下千斤顶和泵站油管不准拆卸。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;5、千斤顶的磨阻会随着使用时间而改变，应按工艺要求对千斤顶进行周期校验。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;6、智能张拉系统张拉过程中，预应力钢绞线出现断丝现象，千斤顶严重漏洞，调换千斤顶时，均应重新使用标准力校正系统校核张拉机具。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;7、油泵运转有不正常情况时，必须立即停车检查。在有压情况下，严禁随意拧动油泵或千斤顶各部位的螺丝。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;8、电源连接线必须接零线并保证连接正确，否则损毁控制箱电路板，设备应可靠接地，并随时检查各处绝缘情况，避免触电。&lt;/span&gt;&lt;/p&gt;&lt;section style=&quot;margin: 0px; padding: 0px; max-width: 100%; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; font-size: 14px;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; overflow-wrap: break-word !important;&quot;&gt;智能张拉设备作业时的注意就说到这里，更多的产品知识可以关注我们的网站或直接电话咨询。&lt;/span&gt;&lt;/span&gt;&lt;/section&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;'),
(261, 1, 10, '&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;喷播机是边坡绿化施工的机械设备，它质量的好坏直接影响喷播效率的高低。喷播机主要用于高速公路(铁路)边坡绿化、边坡防护、山体治理、矿山复绿、荒漠治理等工程。因此，用户在购买时，会有很多问题注意。下面我们来看选购喷播机时需要注意哪些事项。&lt;br/&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/6d0e45d42002dfe.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;一、选择合适的型号&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;喷播机常按不同的喷播对象分为客土喷播机和液力喷播机。合适的型号才能发挥出喷播机效用。要选择合适的型号，我们需要从两个方面考虑：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1、 根据边坡类型选择型号：边坡的高度、坡度都是影响选型的重要因素，高度和坡度越大，相应选配的发动机功率就越大。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2、 根据喷播厚度进行选择：一般客土喷播要求5-10公分，就要选用客土喷播机;液压喷播或喷播1-2公分可选用液力喷播机(豫工机械喷播机厂家的液力喷播机可以喷播大浓度的泥浆)。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;二、选择合适的厂家&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1、主要注意机器罐体钢板厚度，发动机，泥浆泵，柴油机功率以及耐磨件的耐磨性能。现在生产喷播机的厂家有很多，但真正能做出经济实用方便实用的客土喷播机的厂家并不是很多。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2、在购买机器设备时要先考察好市场。实地考察更适合。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;3、在购买产品时要考察该公司实力，是否在现实中真实存在的，有很多网站是没有实体公司的，所以我们要擦亮眼睛认真考核，如果条件可以的话，可以去厂家看看。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;4、看该公司产品外观设计、质量、试机效果如何。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;5、看该公司售后服务怎样，信誉度如何。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;6、再好的喷播机也要看设备自身的重量。外观相同的机器价格差很多时我们要注意看机器的内部构造，不能贪小便宜吃大亏。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;选购喷播机就选豫工机械的喷播机，经济实用方便操作。&lt;/span&gt;&lt;/p&gt;'),
(262, 1, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;欧美国家自20世纪70年代以来在混凝土桥面铺装中广泛使用防水层，大大减少了混凝土桥梁因为渗水的原因而造成的损坏，延长桥梁的使用寿命。但随着交通量的增加，同时出现了防水层和面层以及桥面黏结强度不足而产生推移的病害。在我国，混凝土桥梁也经常发生类似病害，以及由于渗水甚至造成的混凝土疏松、脱落，钢筋锈蚀。造成以上病害的原因之一是因为混凝土面层的处理没有能够完全去除表面残留物质，没有保留一定的粗糙表面来保证防水层和桥面底层的黏结强度。&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-21032515315R41.jpg&quot; style=&quot;width: 611px; height: 344px;&quot;/&gt;&lt;br/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244); font-size: 18px;&quot;&gt;抛丸工艺能够一次将混凝土表面的浮浆、杂质清理和清除干净，重要的是在同时对混凝土表面进行了打毛处理，使其表面均匀粗糙，大大提高防水层和混凝土基层的黏结强度。而且在此过程中，抛丸工艺能够充分暴露混凝土的裂纹等病害，以便提前采取补救措施。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/dc6e7a3242094dd.jpg&quot; style=&quot;width: 611px; height: 458px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;让顾客用上放心的设备是豫工机械一直以来坚持的使命，我们的愿景是依中原为根基，服务全国，走向世界。路漫漫其修远兮，吾将上下而求索，企业发展之路永无止境，豫工机械厂家将始终坚持以合法合规经营为基本原则，以过程管理为核心，以两化融合为手段，建立企业一体化管理体系，以支撑企业卓越发展。&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-210325153421E7.jpg&quot; style=&quot;width: 611px; height: 454px;&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;'),
(263, 1, 10, '&lt;p style=&quot;text-align: left; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;&amp;nbsp;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 1px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;做防水，选豫工非固化防水喷涂设备，不花冤枉钱！ &quot; src=&quot;https://www.zzyugong.cn/uploadfile/202403/a44e9f746db0123.png&quot; style=&quot;width: 691px; height: 462px;&quot; width=&quot;691&quot; height=&quot;462&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;做防水，选豫工非固化防水喷涂设备，不花冤枉钱！ &quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 1px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important; font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;防水早已不再是一个新鲜的话题，不论是隧道、桥梁、堤坝、道路、建筑还是我们日常居住的房屋，防水都不容忽视。相对于老式的防水方式的笨重和繁琐，豫工推出非固化防水材料喷涂设备，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;对于非固化设备的选购，许多人没有眉目。有的人贪图便宜，去买一下低价位的产品，有的人只看外表，购买一些外表看起来很好的机器，其实这些做法都是不正确的，一个合格的非固化设备厂家应该具备优秀的产品，国家安全认证以及完善的服务体系，针对这些问题，今天非固化设备厂家就来教大家如何选择一套靠谱的非固化设备。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;众所周知，由于沥青涂料的特殊性，经常有施工人员不熟悉机器的使用或是因为机器安全性能低而被沥青灼伤。且由于沥青加热后会变为流体。如果机器内部构造不严密就有可能被沥青侵入，造成大面积损坏。更有喷溅，起火等等一系列让人头痛的安全问题。对于以上这些安全问题，专业的设备工程师知道解决设备使用问题。防护服，防护镜等一系列确保施工人员安全的物件。稳定的机器出料口防止沥青喷溅，科学严密的内部构造防止沥青渗漏。工程研发部门研发定制的发动机防止机器起火等等。一系列安全隐患问题得到了很好的解决。&lt;br type=&quot;_moz&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;俗话说得好，时间就是金钱。当今社会。效率就代表着一切。就好像脱桶器的脱桶速度，熔胶机的熔胶速度和熔胶量无一不是施工效率的决定因素。豫工非固化喷涂机一分钟脱桶，三分钟熔胶。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;相信很多施工队都遇到过这样的情况，购买了一套设备，付过款以后卖方就音信全无，要不就是推推拖拖，只能靠施工方自己摸索使用，费时费力。所以您在选购非固化设备的同时一定要着重看一下该公司是否有完善的售后服务体系，这样才能确保您以后的设备使用放心。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;让顾客用上放心的设备是豫工机械一直以来坚持的使命，我们的愿景是依中原为根基，服务全国，走向世界。路漫漫其修远兮，吾将上下而求索，企业发展之路永无止境，豫工机械将始终坚持以合法合规经营为基本原则，以过程管理为核心，以两化融合为手段，建立企业一体化管理体系，以支撑企业卓越发展。&lt;span style=&quot;font-size: 18px; margin: 0px; padding: 0px; max-width: 100%; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 1px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;'),
(330, 2, 9, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;端午将至，豫工精心准备厚厚的礼品，送给最“粽”要的人，分享快乐，共迎端午，2箱粽子，两箱水果，甜甜蜜蜜 红红火火，仪式感满满，感谢豫工对我们的厚爱。&lt;span style=&quot;font-family: 宋体;&quot;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/17176610895098ca.jpg&quot; title=&quot;IMG_20240604_165550(1)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/1717661089c00e7a.jpg&quot; title=&quot;T`R2[XL%%KPV7X@NGQMH}CK&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;每逢传统佳节，豫工家人都能收到一份甜甜的祝福，每个人脸上绽放的笑容，是身为豫工人的幸福，并肩作战的日子，平添了更多热爱和坚守！相信这个夏天，我们拼搏的汗水，将会闪耀整个盛夏，我们奋斗的脚步，必然让豫工更出“粽”，祝福豫工越来越好 ，未来宏图大展！&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/17176611245f7087.jpg&quot; title=&quot;9F40{WL[]C]T%)%D5{J3`BV&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/1717661124646cf1.jpg&quot; title=&quot;SE(KATGDNP{}2]4KIE9K~`6&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/1717661124d53ac3.jpg&quot; title=&quot;YJFLW]6A{%SEVYNC_N(OD36&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/1717661124f2dd70.jpg&quot; title=&quot;YWTMSJIZKSJ%(UC~C%3C({D&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;为答谢新老客户一直以来对豫工的厚爱，自今日起至6月25日，豫工机械特开启VIP客户答谢活动，8大系列产品 热销专场“惠”，价格超低 全部减减减！&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/17176611794c4a52.jpg&quot; title=&quot;1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/1717661179701d87.jpg&quot; title=&quot;2&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/171766117967f94c.jpg&quot; title=&quot;3&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/1717661179f6101f.jpg&quot; title=&quot;64ba73db03e9881802738a476d492d04&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/171766117914c849.jpg&quot; title=&quot;c29ce0a2db6193b7dba0072f01fd2c9e&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/1717661179048736.jpg&quot; title=&quot;d4ab17fc9b134d6c1ffabe52f7b8397e&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202406/17176611808647d9.jpg&quot; title=&quot;ff7e4c15e39864190f988ef6affe8720&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;值此端午佳节，豫工机械全体员工祝新老客户朋友，粽是好运 粽是快乐，粽是喜悦 粽是安康！&lt;/span&gt;&lt;/p&gt;'),
(334, 2, 9, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2024年6月20日，河南豫工机械迎来19岁生日！全体员工欢聚一堂，共同见证这一辉煌的时刻！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805105338f4e.jpg&quot; title=&quot;IMG_20240620_164256&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17198051055f3776.jpg&quot; title=&quot;IMG_20240620_164307&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/171980510517bb22.jpg&quot; title=&quot;IMG_20240620_164754&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;旺春优秀表彰，总结过去 赢战未来 表彰卓越 见证辉煌！刚刚过去的旺春大战，有热情 有汗水 有鲜花 有掌声，豫工人抵住压力 拼搏向上，踏实 努力 灵动 极致，成绩突飞猛进 信心与日俱增。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17198052244e5258.jpg&quot; title=&quot;3&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17198052241cb54b.jpg&quot; title=&quot;5&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805224d29895.jpg&quot; title=&quot;7&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;领奖台上王冠耀眼夺目，领奖台下掌声持久不息，炽热如初 脚步如故，每一次平凡的坚守，在这一刻有了具体的意义！&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805244d3d383.jpg&quot; title=&quot;4&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805244a64fc3.jpg&quot; title=&quot;6&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805244de788d.jpg&quot; title=&quot;13&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;年度优秀表彰，豫工是奋进者的舞台，是成功者的沃土，挑战与机遇并存，奋斗与成长同在，过去一年，豫工人简单全信 听话照做，取得了辉煌的成绩。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805280a42c9c.jpg&quot; title=&quot;12&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/171980528053bf7a.jpg&quot; title=&quot;ab642af74227f6ae42312339ef4f2735&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805280878859.jpg&quot; title=&quot;IMG_20240620_170846&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;他们珍惜每一次努力的机会，心往一处想，劲往一处使，为目标执着坚定，为成功竭尽全力。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805310191b12.jpg&quot; title=&quot;IMG_20240620_171138&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17198053100c5686.jpg&quot; title=&quot;IMG_20240620_171210&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805310637e34.jpg&quot; title=&quot;最佳&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2024年度股东分红，在全体员工的共同努力下，在新老客户的鼎力支持下，豫工机械顶住压力 再造巅峰，销售总额创历史新高，公司与员工同成长，共享发展成果，豫工人将继续携手并肩，共同开创公司美好未来。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805403cb834a.jpg&quot; title=&quot;12&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805403fd673e.jpg&quot; title=&quot;15&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805403e3a288.jpg&quot; title=&quot;分红&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;董事长李红旗先生致辞&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;李总表示：“豫工人太牛了！在激烈的市场竞争中，顶住压力，攻坚克难，将公司的业绩推向新的高度！未来，希望豫工人以更加顽强的毅力，奋力拼搏、积极进取，再造豫工新的奇迹！”&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17198054338dc202.jpg&quot; title=&quot;14&quot; alt=&quot;14&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;盛夏大战启动会&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;凡所过往，皆为序章，红红火火的盛夏大战燃情启动，为了共同的目标，为了拼搏的事业，全体豫工人誓言铿锵 自信满满，携手共进，继往开来。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/171980547620a06c.jpg&quot; title=&quot;步步高战队&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17198054768e3107.jpg&quot; title=&quot;超越队&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805476a3d8a7.jpg&quot; title=&quot;疯狂蚂蚁&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805477bed033.jpg&quot; title=&quot;齐心聚力&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/171980547770210f.jpg&quot; title=&quot;无畏蜜蜂&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17198054771152a3.jpg&quot; title=&quot;扬帆队&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17198054772b099c.jpg&quot; title=&quot;勇敢者&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1719805477ffe362.jpg&quot; title=&quot;追光者&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2024下半场，是尽力局，是拼命局，更是必胜局，面对新的机遇与挑战，全体豫工人，真拼实干，再谱新篇，续写豫工新的辉煌，加油！&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;');
INSERT INTO `dr_1_xinwenzhongxin_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(345, 2, 9, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;受厄尔尼诺事件与全球变暖等因素影响，江南中南部到华南中北部一带降雨异常偏多，导致湖南发生了多次强降雨过程。7月5日下午，受长期集中强降雨影响，湖南省岳阳市华容县团洲垸洞庭湖一线堤防发生决口。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1721716352ad531a.jpg&quot; title=&quot;7ffda6fb999c7a7cd7a68d4016926445&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1721716352df9cc8.jpg&quot; title=&quot;c05890745d2addcef5d9156acf7c640e&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217163522c036e.jpg&quot; title=&quot;Y(GZPDJ}ZW_5CLUFRYG`81N&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;为应对汛情，湖南应急管理局采购豫工机械永磁防汛泵80台，发往湖南岳阳华容县，提高当地防汛救援效率。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户首先咨询的是豫工柴油防汛泵车，经过深入沟通，客户对于体积小、重量轻、携带便捷，却排水量可观的永磁防汛泵青睐有加。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;7月14日，客户第一批次采购1000型永磁防汛泵20台！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;7月18日，客户第二批采购1000方，1200方，1500方永磁防汛泵共计60台。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;两批次防汛泵采购，共计80台！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/172171639311d38b.jpg&quot; title=&quot;00ff2d37a74be80347a4678645b66e49&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217163930e7b40.jpg&quot; title=&quot;1@}%($Z(%T15UMIHDU5H~O9&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;对于这批永磁泵的安装工作，客户选择自己调试！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;对此，技术部乔工表示：豫工的永磁防汛泵操作简单 安装方便，无论是公司售后现场调试，还是客户按照公司技术员的远程指导自己调试，都可以达到一样的效果，排水效果都是一如既往的好。&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217164467a26c2.jpg&quot; title=&quot;52DC81457A6E00F4CD0A7BAA60C239B9&quot; alt=&quot;52DC81457A6E00F4CD0A7BAA60C239B9&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;今年进入汛期以来，豫工防汛设备以品质过硬、排水高效的优势得到新老客户的欢迎，无论是移动防汛泵、还是永磁泵都异常火爆，甚至一度出现供不应求的现象！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217164903fefbf.jpg&quot; title=&quot;2bdc03ef3f0b46287eee84f5a1bcbf0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217164900f049b.jpg&quot; title=&quot;16a6693bda15a404072a86afedb72dd&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/172171649053f988.jpg&quot; title=&quot;29f86e3f972a7c986325ac18cd7782e6&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217164905f0f9c.jpg&quot; title=&quot;43c0d3227b60ef1e57edd04ea8b19a99_&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;为此，豫工机械全体员工是以高度的使命感，急客户之所急，全力以赴，保证按时发货，近一个月内，已完成防汛泵发货70多次，助力各地防汛减灾工作顺利进行。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217165153e9c2e.jpg&quot; title=&quot;243f725d5682cda75cbc6df91abfce8a&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1721716516054f73.jpg&quot; title=&quot;b7756862797a9f016eb1f6aa1e5884b6&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1721716516606291.jpg&quot; title=&quot;ca743d16b5ddc81010b576bb2c0596fc_&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户此次订购的永磁防汛泵系列，是豫工热销款型。经过多年的优化升级，该设备以轻便高效的优势深受客户欢迎！目前，工厂该系列设备规格齐全，覆盖面广，还有250-1200方10米扬程大流量永磁泵，有20-100米流量100至500方的高扬程永磁泵，配套完善，可以直接插电使用。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1721716542d67d4f.jpg&quot; title=&quot;c5b6301f8fe773b4d69f80a37fee30dc&quot; alt=&quot;c5b6301f8fe773b4d69f80a37fee30dc&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; background-color: rgb(250, 250, 239); font-size: 18px;&quot;&gt;该永磁泵系列已经入选国家防汛机具采购目录先进产品行列，多次获得永磁同步电机能效的一级能耗证书，拥有二十个高速轴流泵等永磁同步电机泵的实用新型专利，品质过硬 值得信赖！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; background-color: rgb(250, 250, 239); font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1721716581adee09.jpg&quot; title=&quot;_574c9f4f76c89d2ebacd2e7899326b5e_-1265425898_mmexport1690342381847&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1721716581185e3c.jpg&quot; title=&quot;1IMG_20220224_130214_副本&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/172171658119daa6.jpg&quot; title=&quot;QQ图片20230731141253&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;background-color: rgb(250, 250, 239); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px;&quot;&gt;作为19年防汛除雪应急设备生产厂家，豫工机械应急设备品类完善，除了防汛泵、永磁泵，还生产冲锋舟、橡皮艇、摩托艇、移动照明、消防泵等应急设备，一站式采购，降低客户采购成本，提升施工效率！&lt;/span&gt;&lt;span style=&quot;font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;background-color: rgb(250, 250, 239); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217166228753a5.jpg&quot; title=&quot;5d09b900c753b4ca5059480e791cb8cf&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/172171662277ef28.jpg&quot; title=&quot;59f44c73e4687c1313d0aa83a7c62d51_&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/17217166222ca12d.jpg&quot; title=&quot;e6a97b40b9d7f61449ca39369461cfb1&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/172171662239858c.jpg&quot; title=&quot;f88d3a8261d75a85e4921180f6ba112f&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202407/1721716622c07d15.jpg&quot; title=&quot;fbf95b4489d22c0450355d3afe35f28&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(346, 2, 9, '&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;炎炎夏日&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;，骄阳似火，豫工机械工厂一线员工战高温、斗酷暑，保生产 保质量 保交付！公司总部关爱生产一线，开展情系员工，关爱员工，“送清凉”慰问活动。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172290966838b624.jpg&quot; title=&quot;IMG_20240802_103719&quot; alt=&quot;IMG_20240802_103719&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;8月2日，豫工机械总经理与公司主要领导一行来到豫工河南本部生产基地，带来西瓜、毛巾、水杯、矿泉水、藿香口服液等降暑物资，为奋战在高温一线的员工送来清凉关怀。并添置价值10多万元的防暑降温装备，为工人提供更加舒适的工作环境！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229097146e859d.jpg&quot; title=&quot;IMG_20240802_104844&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229097140c0402.jpg&quot; title=&quot;IMG_20240802_105240&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229097146a12ac.jpg&quot; title=&quot;IMG_20240802_105944&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;“来看看大家，你们辛苦了!” “高温天气一定要注意防暑降温”……侯总代表公司向生产在一线的员工表达慰问和感谢，并一一送上防暑降温慰问品。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229097576d3b22.jpg&quot; title=&quot;IMG_20240802_105624&quot; alt=&quot;IMG_20240802_105624&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229097730cf731.jpg&quot; title=&quot;IMG_20240802_110539&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909773193fd6.jpg&quot; title=&quot;IMG_20240802_110556&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172290977322c22d.jpg&quot; title=&quot;IMG_20240802_111310&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;随后，侯总与工厂主要领导召开现场会，详细了解生产进展、员工保障等情况。侯总强调：工厂各生产线要认真落实防暑降温等安全措施，在统筹抓好安全生产和产品质量的同时，科学安排作息时间，严格落实各项防护措施，确保高温季节生产作业安全稳定。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229098033dce02.jpg&quot; title=&quot;IMG_20240802_104446&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229098031712da.jpg&quot; title=&quot;IMG_20240802_104522&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172290980331578d.jpg&quot; title=&quot;IMG_20240802_104526&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;人力资源总监刘总与工人代表通心交流，详细了解大家的工作和生活情况。刘总高度赞扬工人们“不畏高温、不惧酷暑”坚守岗位的敬业精神，并表示：公司将尽全力解决大家工作生活中的困难，免除大家后顾之忧！他叮嘱大家注意防暑降温，以健康的身体和饱满的精神投入工作。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229098330a0056.jpg&quot; title=&quot;1&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172290983386e275.jpg&quot; title=&quot;2&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909833ecd86f.jpg&quot; title=&quot;3&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;自今年汛期以来，豫工机械防汛应急设备需求井喷式爆发，豫工河南本部生产基地承担了公司防汛应急设备的生产任务。为了保生产保质量保交付 ，工厂一线员工以高度的使命感，不惧高温“烤”验、不惧汗水“洗”礼，开足马力，坚守岗位，不负客户信任，不负公司所托，为各地的防汛工作争取了时间，助力全国应急救援工作顺利开展。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172290984914560e.jpg&quot; title=&quot;b7756862797a9f016eb1f6aa1e5884b6&quot; alt=&quot;b7756862797a9f016eb1f6aa1e5884b6&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909888fc7fbc.jpg&quot; title=&quot;2bdc03ef3f0b46287eee84f5a1bcbf0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909888660f77.jpg&quot; title=&quot;243f725d5682cda75cbc6df91abfce8a&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909937ec6c0d.jpg&quot; title=&quot;00ff2d37a74be80347a4678645b66e49&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909937bc454b.jpg&quot; title=&quot;29f86e3f972a7c986325ac18cd7782e6&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;慰问现场，一线员工纷纷感受到公司领导的关怀，大家爽朗的笑声，是对此次关怀最大的感谢！厂长刘总表示“这份清凉真正送到了大家的心坎里，提振了一线兄弟们更大的工作热情”。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909964cbd25b.jpg&quot; title=&quot;IMG_20240802_110640&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909964bf72e5.jpg&quot; title=&quot;IMG_20240802_111119&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17229099649f9a73.jpg&quot; title=&quot;IMG_20240802_111404_1&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909964b9d116.jpg&quot; title=&quot;IMG_20240802_111940&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1722909965a890ff.jpg&quot; title=&quot;IMG_20240802_112412&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;接下来，豫工机械全体员工将继续上下齐心，发扬豫工人吃苦耐劳、敢拼敢闯的精神劲头，以昂扬的斗志和饱满的热情投入生产，保品质保交付，为公司的高质量发展全力以赴，再立新功。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(348, 2, 9, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2024年8月14日-8月18日，豫工机械2024团建第一趴，内蒙古之旅欢乐开启，草原之上 拒绝“蕉绿”，一起去吹一吹自由的风。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386112df1313.jpg&quot; title=&quot;2C9E4BEC8AE2D7A80E44ACF4A6C4C70C&quot; alt=&quot;2C9E4BEC8AE2D7A80E44ACF4A6C4C70C&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;感谢公司的贴心安排，本次团建以部门为单位，自由选择内蒙古 秦皇岛两条线路，或策马扬鞭 或帆船出海，人间皆是浪漫，奔赴一场诗与远方的美好。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386174457534.jpg&quot; title=&quot;a5c936ab4b636d8ecff8abac02fec0b4&quot; alt=&quot;a5c936ab4b636d8ecff8abac02fec0b4&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;选择内蒙古的小伙伴率先出发，开始为期5天的美好之旅，他们乘飞机到达呼和浩特，拥抱这座有温度的草原都市。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243862195eb1e7.jpg&quot; title=&quot;B1E132CBF6CB40D5287B09CDF108B9E9&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172438621958efa2.jpg&quot; title=&quot;C7423D1092BBE62DB8811BB84A8F902D&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;第一站 5A景区响沙湾，金色沙丘绵延无边，滑沙、骆驼、沙漠越野车，释放束缚，拥抱自由，骑一骑骆驼 听一听驼铃，吹吹旷野自由的风，与沙漠来一场亲密接触，烈日下的炽热，夕阳下的温柔，感受空旷深邃的岁月静好。&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243862442f7ddc.jpg&quot; title=&quot;微信图片_20240819173504&quot; alt=&quot;微信图片_20240819173504&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;等风来不如追风去，小伙伴们玩转乌兰察布火山，感受大自然的瑰丽神奇，何其有幸遇见豫工，低头有坚定，抬头有远方，我们终将遇见最好的自己。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386288ffb072.jpg&quot; title=&quot;40BE4DA2CC25A5296C690DD0FFF8253E&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386288b7053a.jpg&quot; title=&quot;33344245dd2e407c1e5817698cd7208b&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243863197567fb.jpg&quot; title=&quot;微信图片_20240819171818&quot; alt=&quot;微信图片_20240819171818&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;诈马宴豫工机械专场，穿越历史，感受皇家的奢华与风情！，欢快的节奏、激昂的歌声，感受草原的热情与活力，生活于此 快乐于此，最好的时光永远在路上。&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386345f4a8f4.jpg&quot; title=&quot;2&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386345c99346.jpg&quot; title=&quot;微信图片_20240819171845&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172438638111b39b.jpg&quot; title=&quot;c9cca0c98f052657032fbab568e1768c&quot; alt=&quot;c9cca0c98f052657032fbab568e1768c&quot;/&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;马背上的追风小姐姐 ，无拘无束 自由自在，趁年轻，和有趣的人一起嗨，工作时全力以赴 玩乐时热情放肆，可可爱爱的豫工人，心怀热爱，所遇皆美好。&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386440114b99.jpg&quot; title=&quot;33&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;最好的团队 最好的我们，有爱有快乐，有趣有热爱，回头有一路的故事，抬头有清晰的远方，一群人 一条心，一起奔跑在美好的路上。&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386491f46c3b.jpg&quot; title=&quot;4_副本&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172438649176a0b7.jpg&quot; title=&quot;微信图片_20240819171347&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172438649159e4fc.jpg&quot; title=&quot;微信图片_20240819173053&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;五天四夜内蒙之旅圆满收官，感谢豫工的厚爱，每年精心安排放松心情的机会，心怀感恩 热情热爱，未来的豫工人将更加紧密地凝聚在一起，同走一段路，共打一场仗，牵手并肩，拼搏向前！&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;'),
(349, 2, 9, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2024年8月15日,工机械2024团建第二趴欢乐启程,伙伴们乘高铁奔向美丽的海滨城市,始为期4天的秦皇岛之旅，aaaaappy的一天。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724386988ecea4b.jpg&quot; title=&quot;1_副本1&quot; alt=&quot;1_副本1&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;列车即将到达：北戴河，段悠闲的旅程，为一群可可爱爱的人儿，路是风景，一路是欢笑，好！最好的年纪，们因豫工而更加美好。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172438700951e1fe.jpg&quot; title=&quot;微信图片_20240820145509&quot; alt=&quot;微信图片_20240820145509&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;海水清爽 沙滩柔软，起来海边吹吹风，是颜值和美味在线的一天，好喝好玩好，谢豫工的无限宠爱，费旅游，简直不要太幸福。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387043b805c5.jpg&quot; title=&quot;1 (2)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243870436e9e1e.jpg&quot; title=&quot;1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387043641cf4.jpg&quot; title=&quot;2_副本4&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387043d98307.jpg&quot; title=&quot;3&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;夏天 夕阳 晚风，酒吧 音乐 好友，日落与酒，浪漫与我们，忙里偷闲的生活碎片，共度美好时光。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243871279aeb3b.jpg&quot; title=&quot;4&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243871276c76df.jpg&quot; title=&quot;d6d2bcf2d7bcfb5a4e57754595036306&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387127b71e10.jpg&quot; title=&quot;微信图片_20240819171920&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243871271efeb0.jpg&quot; title=&quot;1 (7)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;海风拂面 海浪翻卷，豫工人帆船出海 乘风破浪，扬帆的那一刻，感受到了海贼王的快乐，一起欢笑，一起共享。&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387145ab0d71.jpg&quot; title=&quot;1 (6)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387145352748.jpg&quot; title=&quot;2_副本&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;忙碌的日子，豫工人的热爱和心动从不迟到，当然要记录啊，水之间定格美好，我们好运都藏在努力里，万事都要全力以赴，包括开心。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243872061e4f48.jpg&quot; title=&quot;6&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387206bcc15b.jpg&quot; title=&quot;7_副本&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387206c81c91.jpg&quot; title=&quot;8_副本&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387206ed20ec.jpg&quot; title=&quot;9&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387206461b98.jpg&quot; title=&quot;f916a31cbfa5c1d510566fc3ff763794&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;帆船坐了 海鸥喂了，沙滩派对参加了，实景演艺秀观看了，豫工机械秦皇岛之旅完美收官，来海边采摘阳光，回人海继续发光。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387241c73cdf.jpg&quot; title=&quot;1 (5)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387241ef1a71.jpg&quot; title=&quot;1be20a97d22a1dcebfecfacd9831e167&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/17243872417e4d09.jpg&quot; title=&quot;2_副本1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/172438724123aa00.jpg&quot; title=&quot;2_副本2&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387241caea10.jpg&quot; title=&quot;2_副本4&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387241f57ba9.jpg&quot; title=&quot;3_副本3&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387241e36860.jpg&quot; title=&quot;7_副本&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202408/1724387241b93c3c.jpg&quot; title=&quot;8e63a86a45a9ceeb691433b202e56419&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;乘兴而行，满载而归，出发的过程就是此行的意，不恋过往 不惧将来，收心聚力，共迎2024金秋大战，全力以赴 闪闪发光，见证未来不一样的自己。&lt;/span&gt;&lt;/p&gt;'),
(354, 2, 9, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;征程未有尽期，行稳方能致远，金九银十 奋进正当时，豫工机械厉兵秣马 赢战金秋。2024年9月20日，金秋大战启动会在国内事业部燃情启动，营销总部200多人齐聚一堂，斗志昂扬，众志成城，正式打响金秋决胜战！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/17271486946ea9b5.jpg&quot; title=&quot;ac3a0fdab74e25e537845ab9d6147d4d&quot; alt=&quot;ac3a0fdab74e25e537845ab9d6147d4d&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;全体豫工人整装待发，带着对目标的执着，对事业的热忱，以乘风破浪的勇气，以永不消退的拼劲，赴一场星辰大海的征程。伴随着激昂振奋的音乐，豫工人整装待发，有序入场，一场对豫工人极其重要的大战，正式拉开序幕。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/172714871126bb4d.jpg&quot; title=&quot;4dbf803c07eda713e4cf617d1b61f4b3&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148711b745ed.jpg&quot; title=&quot;9FA1D5FD5370978D48CE09D14975B43E&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148711355f9b.jpg&quot; title=&quot;26A484E4D573A319BE18BD22D7EF0B39&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148711b73376.jpg&quot; title=&quot;0228E22B5E9AA51D922E136DE4E0466A&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工四总（营销总监、股东长、总教练、总政委）隆重登台，带领大家燃烧热情 郑重宣誓，凝心聚力，使命必达，坚定信念，一往无前&amp;nbsp; 。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/172714874564d645.jpg&quot; title=&quot;1FA9E1600AA0F5A8D99E9A073C758105&quot; alt=&quot;1FA9E1600AA0F5A8D99E9A073C758105&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;团队风采展示，九大业务战队依次登台，宣读目标、 高呼口号、分享心得，为金秋冲刺加油，为新征程储能蓄力。3个小时的团队风采展示，小伙伴们自信坚定 字字铿锵，，以”拼” ”闯” ”冲” ”赢”的劲头，凝心聚力，同逐梦，砥砺前行，冲目标。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148772926534.jpg&quot; title=&quot;0f6825fc41367811ddd13f4f2db1728e&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148772c2c9bd.jpg&quot; title=&quot;1E4DB481377778783828A9340FA2073D&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/172714877252cde9.jpg&quot; title=&quot;6ad9e32a0a4aad284be8b95ba5861885&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;团队代表真诚分享金秋目标，复盘过去 剖析自身，总结经验与得失 制定目标与计划，跳出局限 打开思路 重新出发，用过程来证明 用结果来绽放，每个人诚恳务实的分享，展现了自信坚韧 无惧挑战的决心，他们向内成长 向外绽放，往日不悔，未来无惧，轻装上阵，坚定前行。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148815fd7d9d.jpg&quot; title=&quot;6CC8C4A58A11DC003FC080F14FB9787C&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/172714881562f550.jpg&quot; title=&quot;AB56561FB4E06EE187676641DED91FA5&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/17271488156c6704.jpg&quot; title=&quot;c02b347dd58dba54ffdff9f9698f9098&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;不怕输 才会赢，金秋大战PK专场，小伙伴现场发起挑战，实力切磋 巅峰对决，勇于突破自己的舒适圈，共同努力 共战顶峰。世界上只有一种成功，就是找对方向之后的持之以恒，想都是问题，做才有答案，快速行动 坚决执行，这个金秋，我们定能干出一份耀眼的成绩。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148843576af1.jpg&quot; title=&quot;13EB9A8C0D591E54629E5F5B95F0AA48&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/17271488432aac1d.jpg&quot; title=&quot;510f5287a7e710ca98896a38320435ff&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148843e53207.jpg&quot; title=&quot;16053C456D2A7A61FABD4AB61E9BA35B&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;是的，人生本就无限可能，永远不要为自己设限，金秋大战激烈而精彩，拿出势在必行 我行我能的勇气，紧跟公司步伐 跟盯目标计划。简单全信，听话照做，一直走，就是巅峰。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/172714887089b6c5.jpg&quot; title=&quot;49043F2A6EDC59D818AB3A318593002F&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/17271488700d8062.jpg&quot; title=&quot;71487AC56085A04FB388F0FB03B5B8EC&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202409/1727148870a1da07.jpg&quot; title=&quot;de6d3d601544cb745d24f38b00c48e94&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;一次又一次的战役，让我们热血澎湃，一场又一场的大战，让我们斗志更坚，站在金秋的新起点，让我们继续以奋勇向上的姿态，奔赴新征程，步步为赢，马到成功，加油！&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;'),
(363, 2, 10, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;除雪滚刷的工作原理，简而言之，是通过机械旋转与物理刮擦相结合的方式，高效清除道路、停车场等区域的积雪，确保交通顺畅与公共安全。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202410/1729234767505b93.jpg&quot; title=&quot;除雪滚刷的工作原理是什么？&quot; alt=&quot;除雪滚刷的工作原理是什么？&quot; width=&quot;774&quot; height=&quot;697&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;其具体运作机制如下：除雪滚刷通常由一组或多组高强度、耐磨损的刷毛或金属刮板组成，这些部件安装在可旋转的滚筒上。当除雪机械启动后，电机或液压马达驱动滚筒快速旋转，刷毛或刮板随之高速转动，形成强大的清扫力。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202410/172923482495fb0e.png&quot; title=&quot;除雪滚刷的工作原理是什么？&quot; alt=&quot;除雪滚刷的工作原理是什么？&quot; width=&quot;750&quot; height=&quot;750&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;在行进过程中，滚刷前端的刷毛首先接触雪层，利用其柔软性和弹性，初步松动并打散积雪，尤其是那些因低温而变得紧实坚硬的雪块。随后，紧随其后的金属刮板或更坚硬的刷毛则发挥关键作用，它们像锋利的刀刃一般，将已被松动的积雪彻底刮离地面，并随着滚刷的旋转被抛向后方或侧边，从而实现积雪的快速清理。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202410/1729234837eade5d.png&quot; title=&quot;除雪滚刷的工作原理是什么？&quot; alt=&quot;除雪滚刷的工作原理是什么？&quot; width=&quot;750&quot; height=&quot;750&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;此外，部分先进的除雪滚刷还配备了可调节角度和压力的装置，以便根据雪层厚度和路面情况灵活调整工作模式，达到最佳的除雪效果。同时，滚刷表面往往采用特殊材质处理，以减少对路面的损伤，保护道路表面不受破坏。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202410/17292348573098f9.jpg&quot; title=&quot;除雪滚刷的工作原理是什么？&quot; alt=&quot;除雪滚刷的工作原理是什么？&quot; width=&quot;774&quot; height=&quot;581&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-family: 微软雅黑, &amp;quot;Microsoft YaHei&amp;quot;; font-size: 18px;&quot;&gt;综上所述，除雪滚刷以其高效、便捷的特点，在冬季除雪作业中发挥着不可或缺的作用，为人们的出行安全保驾护航。随着技术的不断进步，未来的除雪滚刷将更加智能化、环保化，为城市冬季管理带来更多便利与效益。&lt;/span&gt;&lt;/p&gt;'),
(364, 2, 10, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202410/17292357351a5efe.jpg&quot; title=&quot;A[UJ$K9ZUV3V0(U]03WCIJD&quot; alt=&quot;A[UJ$K9ZUV3V0(U]03WCIJD&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;除雪滚的除雪效率与设计构造起决定性作用。其直径、宽度、除雪滚的材质选择有关，直接影响了滚刷与雪面接触的面积和力度。直径较大、宽度适中的除雪滚，能更有效地覆盖并清除积雪，而耐磨、抗冻的材质则保证了长时间作业下的稳定性与耐久性。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202410/1729235753a5be2b.jpg&quot; title=&quot;IMG_20230105_143224348_original&quot; alt=&quot;IMG_20230105_143224348_original&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;其次，动力系统的配置也是提升作业效率的关键。强大的发动机或电机为除雪滚提供源源不断的动力，使其能在短时间内快速旋转，增强除雪效果。同时，智能化的控制系统允许操作者根据雪层厚度和路面情况灵活调整转速，达到最佳除雪效率。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;再者，环境因素同样不容忽视。秋季虽非主要降雪期，但突如其来的寒流或早雪仍需应对。气温、湿度以及雪质的不同，会影响除雪滚的作业效果。例如，湿雪较干雪更难清除，此时，适当的预热系统或调整除雪策略就显得尤为重要。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202410/17292357687082b1.jpg&quot; title=&quot;IMG_20230105_143235887_original&quot; alt=&quot;IMG_20230105_143235887_original&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;最后，操作人员的技能与经验也是不可忽视的一环。熟练掌握除雪滚的操作技巧，能够根据实际情况快速判断并调整作业方式，从而显著提升除雪效率与安全性。此外，定期的维护保养也是保持除雪滚高效作业的必要条件，确保其在关键时刻能够稳定可靠地发挥作用。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;综上所述，除雪滚的作业效率与设计构造、动力系统、环境因素以及操作人员的技能与经验等多方面因素密切相关。在秋日安利计划中，我们不仅要关注除雪设备的选购与配置，更要重视其综合性能的优化与提升，为应对即将到来的冬季挑战做好充分准备。&lt;/span&gt;&lt;/p&gt;'),
(366, 2, 9, '&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;决战收官，赢战丰年，2024年11月28日，豫工机械2024丰年大战热情启动，郑州总部国内事业部全体成员200人，齐聚一堂，发起年底总攻，50天的火热征程，即将燃情启程！&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202412/17339110085a1ca3.jpg&quot; title=&quot;IMG_20241128_155205&quot; alt=&quot;IMG_20241128_155205&quot;/&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202412/17339111322abb90.jpg&quot; title=&quot;408db102d5696c877b937e93d43d276e&quot; alt=&quot;408db102d5696c877b937e93d43d276e&quot;/&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;刚刚过去的金秋大战，豫工人以高度的热情投入工作，以品质为先，以服务为本，专业、热情、真心，赢得一个又一个客户的认可，收获了成长与荣誉。&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202412/1733911072363736.jpg&quot; title=&quot;d31749aca6e5d3f5c21e6200f690798&quot; alt=&quot;d31749aca6e5d3f5c21e6200f690798&quot;/&gt;&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;他们尽职尽责、勇于担当，他们成绩耀眼 业绩领先，他们凭借过硬的实力登顶巅峰，王冠，奖金，礼品，红花，是对他们成绩的肯定，亦是对他们付出的嘉奖，一份勋章、一份荣光，同时也是责任与使命，作为豫工的优秀代表，未来，期待他们带领豫工走向更高的山峰，不负热爱，共赴山海。&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202412/17339110960da63a.jpg&quot; title=&quot;retouch_2024113008513292&quot; alt=&quot;retouch_2024113008513292&quot;/&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;荣誉属于过去，拼搏赢得未来，2024丰年大战燃情启动。启动会上，每个人对自己的奋斗目标，思路清晰，自信满满，大家郑重签下军令状，誓言铮铮，掷地有声，军令已下，必达成，必超越，声如洪钟的发言，是决心，也是信心大家誓以最饱满的热情投入工作，夺取属于自己的荣光，向热爱致敬，为自己喝彩&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202412/1733911116e7827e.jpeg&quot; title=&quot;99db043b9f1ecd2f655038ef19605d3b&quot;/&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202412/1733911116b290e7.jpg&quot; title=&quot;9340E3D70260422C94E2461BFB1A970D&quot;/&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;2024丰年大战，新的开端，新的征程，机不可失，时不我待，每个豫工人都要珍惜它，抓住它，用好它，为2024圆满收官竭尽全力，征程即将启航。&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202412/1733911158ffb24b.jpeg&quot; title=&quot;b8a8eaf4a7c92c156f1092efb8555e58&quot; alt=&quot;b8a8eaf4a7c92c156f1092efb8555e58&quot;/&gt;&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202412/17339111984d6e86.jpg&quot; title=&quot;retouch_2024112916111915&quot; alt=&quot;retouch_2024112916111915&quot;/&gt;&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p style=&quot;line-height: 2em;&quot;&gt;\r\n    &lt;span style=&quot;font-size: 18px;&quot;&gt;红红火火的日子，优秀的豫工人一直拼搏在路上，奋勇争先，无所畏惧，与公司共同成长，与成功结伴同行，生命就是拼、闯、冲，人生最好的贵人，是永远努力向上的自己，让我们继续努力，让这个冬天见证豫工人拼搏的身影，预祝我们旗开得胜，马到成功，加油!!!&lt;/span&gt;\r\n&lt;/p&gt;\r\n&lt;p&gt;\r\n    &lt;br/&gt;\r\n&lt;/p&gt;');
INSERT INTO `dr_1_xinwenzhongxin_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(405, 2, 9, '&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2025年2月19日，豫工机械隆重举办以“‘豫’见未来，‘工’谱新章”为主题的2025供应商大会。这次大会，旨在为豫工机械2025年达成6亿产值提供高品质配件供应，为豫工规模化发展保驾护航。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/17401926496b27b6.jpg&quot; title=&quot;IMG_20250219_145914&quot; alt=&quot;IMG_20250219_145914&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192672046096.jpg&quot; title=&quot;IMG_20250219_103618&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/174019267284a747.jpg&quot; title=&quot;IMG_20250219_104751&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;100多个核心供应商厂家，豫工全体高管，相关职能部门负责人，齐聚一堂，共同探讨当前市场环境下，如何提升品质，如何以高质量产品和服务赢得市场，共建互利互信的可持续发展供应链体系，携手开创合作发展新局面。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192723a1b077.jpg&quot; title=&quot;1740109886404&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/17401927230c700e.jpg&quot; title=&quot;IMG_20250219_123139&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/174019272387c044.jpg&quot; title=&quot;IMG_20250219_141822&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192723842b8a.jpg&quot; title=&quot;IMG_20250219_142923&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/17401927230c8ca1.jpg&quot; title=&quot;IMG_20250219_144733&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械董事长李总发表了热情洋溢的讲话，分享了豫工的企业文化、发展历程、经营策略以及未来愿景，向供应商伙伴传递了公司高质量发展的信心与决心。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192766089386.jpg&quot; title=&quot;IMG_20250219_150101&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192766da0a9e.jpg&quot; title=&quot;IMG_20250219_153017&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;李总表示：豫工机械20年发展，八大产品体系，一百多款产品，供应链的品质至关重要，是豫工制造的基础。为了完成“高性价比”的服务初心，公司探索出了一条规模化发展之路，以量变换质变，用巨量订单换得供应链的价格和品质支持，特别是易损件的供应如轴承，轮胎，开关等，更求选用优质基材，国际大牌，并加大细节打磨，把品质牢记心中。为客户打造高性价比的产品矩阵，方可实现豫工品牌化可持续发展。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192794dcac1e.jpg&quot; title=&quot;IMG_20250219_151225&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192794627c07.jpg&quot; title=&quot;IMG_20250219_152234&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;李总特别提到：定制化产品是豫工的特色，也是未来发展的重中之重。面对同质化产品市场，豫工期待与供应商进行更紧密，更通心的交流，共同聚焦品质优化，服务创新，共同实现差异化竞争力。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192824579726.jpg&quot; title=&quot;IMG_20250219_150401&quot; alt=&quot;IMG_20250219_150401&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;采购总监申总发布豫工机械2025供应商分级管理制度和合作政策，向供应商分享了豫工在质量管控和供应商审核方面的要求。申总分析了豫工机械对供应链的创新需求，提出了一系列优化措施，包括建立更加严格的供应商准入机制、优化对供应商的业绩评估与考核等，严格执行淘汰机制，确保配件质量“零容忍”。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192881e29ce9.jpg&quot; title=&quot;IMG_20250219_160637&quot; alt=&quot;IMG_20250219_160637&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192856ee94d2.jpg&quot; title=&quot;IMG_20250219_162711&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;申总表示：客户就是上帝，满足客户的需求，是当下豫工与供应商的共同任务。在与豫工的合作中，携手共建廉洁高效的生态合作环境，不搞迎来送往，而要清白合作，把品质做好，把服务做细，把客户利益放在最高位，公平透明，交心通心，与供应商共建“利益共同体、事业共同体、命运共同体”，以质取胜 共赢未来。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192899cd7d47.jpg&quot; title=&quot;IMG_20250219_162314&quot; alt=&quot;IMG_20250219_162314&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;公司特别设置了颁奖环节，以表彰过去一年表现卓越的供应商，共有12家企业脱颖而出，分别荣获最佳供应商奖、最佳服务奖、最佳质量奖三个奖项。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192938695c7c.jpg&quot; title=&quot;IMG_20250219_164641&quot; alt=&quot;IMG_20250219_164641&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;最佳供应商奖&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/17401929496b8e51.jpg&quot; title=&quot;IMG_20250219_165250&quot; alt=&quot;IMG_20250219_165250&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;最佳服务奖&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/17401929602021a0.jpg&quot; title=&quot;IMG_20250219_165824&quot; alt=&quot;IMG_20250219_165824&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;最佳质量奖&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械与5家供应链企业成功举行了2025战略合作框架协议签署仪式，此次签约为豫工机械的规模化、品质化发展注入了强劲动力。是公司推进国际化高水平制造、增强产业链韧性的重要步骤。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740192990bc5e3f.jpg&quot; title=&quot;IMG_20250219_170604&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/17401929913f00b3.jpg&quot; title=&quot;IMG_20250219_170756&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/17401929917031ac.jpg&quot; title=&quot;IMG_20250219_171456&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;最后的晚宴致辞环节，豫工机械国内事业部侯总、国际事业部赵总向远道而来的供应商表示欢迎，对一直以来对豫工的信任和支持表示感谢。大家共同举杯，愿合作的路越走越宽，互信互助建立合作关系，合之以诚，作之共荣，深耕全球市场，共赢未来。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740193017948ae0.jpg&quot; title=&quot;IMG_20250219_175744&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/174019301754a1e3.jpg&quot; title=&quot;IMG_20250219_181235&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740193017a6cdaa.jpg&quot; title=&quot;IMG_20250219_182551&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;第二天，全体供应商朋友参观豫工机械总部，深入了解公司在技术团队、研发创新、产品服务及企业文化等方面的成就。参访过程中，大家与豫工各部门同事交流沟通。合作伙伴纷纷表示，未来将更加紧密地与豫工机械团结在一起，交付最高质的产品，质量至上，品质严控，共建互利共赢的“生态共赢链”。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/17401931548d6946.jpg&quot; title=&quot;4A81FEDDDFB5D40B74E1A18F9167E149&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/174019315488a10f.jpg&quot; title=&quot;4BFCE2CFF65850159548EA03B2FC5B55&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740193154aed6fa.jpg&quot; title=&quot;50ADEF5C0EA1BD3689D004FFD14916D4&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202502/1740193154f6719e.jpg&quot; title=&quot;IMG_20250220_093744&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;本次大会的成功举办，不仅为豫工与供应商伙伴们提供了一个交流与合作的平台，更为公司在新的发展阶段奠定了坚实的基础。相信在双方的共同努力下，未来一定能够实现“‘豫’见未来，‘工’谱新章”的目标，在市场竞争中脱颖而出，聚力谋远，共赢未来。&lt;/span&gt;&lt;/p&gt;'),
(411, 2, 9, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;春回大地，万象更新。2025年2月28日，豫工机械“AI赋能，智启新篇”旺春启动会隆重开启，这是一场凝聚共识、点燃斗志的盛会，国内事业部200余名精英齐聚，共启2025的辉煌征程。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/174107037670ffd8.jpg&quot; title=&quot;22&quot; alt=&quot;22&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;这场开年首战，打的不仅是业绩，更是企业的创新宣言！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;100天的征程，豫工人将借助AI数字技术，打出豫工发展加速度，将响应效率、产品优势、服务温度全面升级，向旺春大战1亿产值的目标冲锋。这一战，既要赢得漂亮，更要赢得智慧！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/17410728755d637d.jpg&quot; title=&quot;IMG_20250228_145538&quot; alt=&quot;IMG_20250228_145538&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;丰年大战荣誉表彰&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;大会开始，公司向2024年丰年大战表现优异的同事，给予荣誉表彰。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2024丰年大战，她们以“豫工英雄，舍我其谁”的魄力，带领团队勇敢冲锋，点燃自己，赋能他人，拉开了豫工迈向新台阶的大幕！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741072903b17e63.png&quot; title=&quot;4&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741072903ca23a6.jpg&quot; title=&quot;5&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/174107290397da43.jpg&quot; title=&quot;7&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;他们不是单枪匹马的孤胆英雄，而是刷新豫工发展新高度的“英雄联盟”！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;她们把&amp;quot;敢想&amp;quot;化为精密计划，把&amp;quot;敢拼&amp;quot;注入执行细节，让&amp;quot;敢干&amp;quot;扎根团队协作，珍惜每一个客户的信任，抓住每一次成功的机会，甩掉包袱，极致努力，成绩荣誉双丰收！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/17410729331ff4c7.jpg&quot; title=&quot;6&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741072933906d0b.jpg&quot; title=&quot;8&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741072933c3016e.jpg&quot; title=&quot;21&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;旺春大战启动会&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;战旗挥舞 战鼓铮铮。旺春大战启动会上，营销总部九大核心部门主管，率先列阵，开启“旺春加油接力”。200多名豫工铁军闻令而起，热情涌动。不仅点燃了大家的斗志，更显示了豫工旺春大战使命必达的决心。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/17410729626ba736.jpg&quot; title=&quot;9&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741072962d897c1.jpg&quot; title=&quot;10&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741072962c0f32c.jpg&quot; title=&quot;11&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械营销总监分享旺春大战奖励机制，为本轮冲锋再添新动力。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741072985b3b78e.jpg&quot; title=&quot;19&quot; alt=&quot;19&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;目标为先 使命必达&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;团队风采展示环节，每个豫工人铿锵有力地宣誓：“以目标为引，以标杆为镜”，冲刺旺春，再战新征程。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/174107302738b0ba.jpg&quot; title=&quot;12&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741073027fc39e6.jpg&quot; title=&quot;13&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741073027d480ca.jpg&quot; title=&quot;14&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;百万英雄挑战人热情发言，分享旺春工作目标、行动计划和预期成果，展现了豫工人的专业素养和昂扬斗志。&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741073045ad6051.jpg&quot; title=&quot;20&quot; alt=&quot;20&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;每个人热情热爱，自信满满，犹如一个个活力十足的音符，吹响了豫工人决胜2025的冲锋号角。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;AI分享环节。团队代表倾情分享AI使用案例，开阔大家对于AI赋能的全新视野，每个豫工人都已经意识到人工智能的门已经打开，所有人都要积极学习AI，运用Al，助力学习、工作和生活，重构自己的工作模式。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741073068b3e3c6.jpg&quot; title=&quot;15&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/17410730688a1ea8.jpg&quot; title=&quot;16&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/17410730681b7f78.jpeg&quot; title=&quot;17&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;很幸运在最好的年华，遇见豫工这个大舞台。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在这里，有清晰的奋斗方向，有落地的工作规划，还有丰富的学习资源。它点燃了所有人的热情，激发了每个人的斗志，带领大家与时代同频，与辉煌共舞，给我们勇敢面对未来的底气。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/17410731045c1d2b.jpg&quot; title=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/1741073104e19c38.jpg&quot; title=&quot;3&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;董事长总结致辞&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;李总在发言中表示：“一个粗糙的开始就是最好的开始，AI赋能不是口号，每一位员工都是行动的主角，要抓住AI迸发的窗口期，立即行动，扎实工作，在行动中不断调整和进化，撬动管理升级、生产创新、服务迭代三大杠杆。这是挑战，更是豫工跨越式发展的历史机遇！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202503/17410730887f9107.jpg&quot; title=&quot;18&quot; alt=&quot;18&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;旺春大战已开启，这场大会不仅是一次动员，更是一次向未来宣战的集体誓言。2025年的豫工，将以雷霆之势破局而立，借助AI的科技东风，以蓬勃之力，奔涌向前。&lt;/span&gt;&lt;/p&gt;'),
(424, 2, 9, '&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px; text-wrap: nowrap;&quot;&gt;粽情端午 感恩同行，夏风裹着粽香，又是一年端午至，今年的豫工“心意”已就位。&lt;/span&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/17485046873b6793.jpg&quot; title=&quot;6B6205DA4CB3A4F0E5554AFE9B29B615&quot; alt=&quot;6B6205DA4CB3A4F0E5554AFE9B29B615&quot; style=&quot;font-size: 16px; text-wrap: nowrap;&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;300多份节日问候，准时送达豫工总部4大办公区，由主管送到每位家人的手中，两盒甜心粽、两盒土特产，两盒甜心粽、两盒土特产，可甜可咸，诚意满满，这波福利真是太赞啦！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504712c09134.jpg&quot; title=&quot;75D3813FFC0A005DC079A7764774B99A&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/17485047125ddc32.jpg&quot; title=&quot;A2D4E855620EC3FE91109029191ADEFB&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504712d36214.jpg&quot; title=&quot;FF31B89D6EBBEC36022EDF9F90FA125C&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;福利发放现场一片欢乐，一箱箱礼品填满了每个人的办公区，大家脸上都笑开了花，又是被豫工实力宠爱的一天。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/17485047648ca8f5.jpg&quot; title=&quot;0A0AEA9B8F71A539AB9E73C6FC34DE48&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/17485047645bc86e.jpg&quot; title=&quot;c973b739faa10b9071e6d3f34f6fdad&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504764644a71.jpg&quot; title=&quot;F57E42DD0576C3706E61CCCEDDC300D2&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;这就是豫工人的专属浪漫，是豫工给“最‘粽’要人”的节日祝福。拆盒的惊喜、分享的欢乐，每一个被仪式感填满的瞬间，好似都在说：“豫工的家人，值得被认真对待。”&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504796fee33a.jpg&quot; title=&quot;3&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504796f624a5.jpg&quot; title=&quot;7AE301EE1EC89932B6F904CD4AF2F060&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504796a49b15.jpg&quot; title=&quot;64A22F9096B229191C69971F949E2EAD&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504796d66490.jpg&quot; title=&quot;576b873acd000c5cdc59f9a6389d2d2 拷贝&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;&lt;/span&gt;其实，豫工的“节日甜度”从未掉线，从春节到端午，从端午到中秋，那些藏在细节里的关怀，正化作并肩时的默契，凝成攻坚时的底气，踏实、专注、热情、拼尽全力，这是豫工人刻在骨子里的底色。&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/174850483195168b.jpg&quot; title=&quot;4888C2DB7240F432173EF595185BE7F9&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/17485048318ebdc6.jpg&quot; title=&quot;1748415924993&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504831b83e5b.jpg&quot; title=&quot;F8360591595F4E14051B8EC6FD972834&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504831bfba92.jpg&quot; title=&quot;FC7D659119530BE3FEACA1C165BDE143&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;当端午遇见618，感恩不打烊！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;为回馈新老客户长情相伴，&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;6月1日-6月25日，豫工机械开启“粽情宠粉季”：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;8大系列热销产品直降狂欢&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;爆款机型折上再减，&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;这个夏天&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;让豫工用诚意，陪您“惠”购一夏！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;最后，把所有美好都包进“粽”里&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;愿新老客户朋友：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;粽有好事发生，&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;粽遇温暖相伴，&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;粽享事业顺意，&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;粽得安康常随！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/17485049067db537.jpg&quot; title=&quot;7BBB8413D4BC4C1C07C656DA140A24C5&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202505/1748504906228cf8.jpg&quot; title=&quot;B56B56350BC43CD924CACBD5CFB9A202&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;值此端午佳节&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;豫工机械全体员工&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;与您共盼：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 4em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;夏风更盛时，我们更出“粽”！&lt;/span&gt;&lt;/p&gt;'),
(427, 2, 9, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;二十年征途 步履铿锵&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;二十年热血 初心滚烫&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2025年6月20日，在郑州总部营销中心，豫工机械“保持热爱，筑梦山海”20周年庆典燃情启动，国内&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;事业部200多名员工齐聚一堂，为豫工20周岁生日祝福。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746391f58237.jpg&quot; title=&quot;IMG_8707 拷贝&quot; alt=&quot;IMG_8707 拷贝&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;20年，是豫工与时代同频的奋斗史诗，从萌芽起航到战略出海，豫工人以品质之笔，以热爱为墨，书写了“让世界爱上河南造”的辉煌华章！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/175074641310c458.jpg&quot; title=&quot;未命名&quot; alt=&quot;未命名&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;本次庆典由三个环节组成，荣耀表彰、股东分红、盛夏誓师，环环相扣，精彩纷呈，点燃了大家的热情与斗志。&lt;/span&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746480f98d1e.jpg&quot; title=&quot;0f008c47-40ba-4d2f-830d-14c4f50cf16b 拷贝&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746480e123ed.jpg&quot; title=&quot;f520ff313dc84fcaafd51640491b5c79 拷贝&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746506ae9050.jpg&quot; title=&quot;f520ff313dc84fcaafd51640491b5c79 拷贝&quot; alt=&quot;f520ff313dc84fcaafd51640491b5c79 拷贝&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;伴随着激昂的音乐，各部门整装待发，依次入场。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746547ce115f.jpg&quot; title=&quot;C2D6CADBB298E9BF9EC180BE9077367A 拷贝&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746547819a84.jpg&quot; title=&quot;PC(E@TFC{3}BULWZM]FOZIV 拷贝&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746547d2af85.jpg&quot; title=&quot;PL~70N)Z@1A$U_[D4R%MH2S 拷贝&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507465473d03ca.jpg&quot; title=&quot;SO67G(O2U4A9P)9273TA4[K 拷贝&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;旺春大战荣誉表彰&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;大会开始，公司向2025年旺春大战表现优异的同事，给予荣誉表彰。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746587a8a6f5.jpg&quot; title=&quot;IMG_8709 拷贝&quot; alt=&quot;IMG_8709 拷贝&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;刚刚过去的旺春大战圆满结束，有人赢在巅峰，有人逆袭突围。她们用实打实的战绩，诠释了「豫工英雄」的真谛，不是昙花一现的惊艳，而是永立潮头的王者。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507466547c0a46.jpg&quot; title=&quot;6af672b89b1f8d1c3e57e28971b08bf6 拷贝&quot; alt=&quot;6af672b89b1f8d1c3e57e28971b08bf6 拷贝&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;英雄的登顶令人仰望，新生的力量同样耀眼。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;他们以初生牛犊的闯劲，打破常规；以新人无畏的冲锋，突围而出，他们让“未来可期”成为现实，成绩卓著，征途闪耀。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746693bdf76d.jpg&quot; title=&quot;IMG_8713 拷贝&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746693b367af.jpg&quot; title=&quot;IMG_8715 拷贝&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2024年度优秀表彰&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2024年的豫工，是奋进者的舞台，是成功者的沃土，豫工人简单全信 听话照做，不仅收获的喜人的成绩，更成就了一批业务英雄。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507467244267d2.jpg&quot; title=&quot;c004dc317d40e60c1f8159ede73e503&quot; alt=&quot;c004dc317d40e60c1f8159ede73e503&quot;/&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507467731dd4c7.jpg&quot; title=&quot;1&quot; alt=&quot;1&quot;/&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;个人的成功耀眼夺目，团队的雄起恢弘璀璨。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;作为战无不胜的豫工铁军，他们以超强战斗力和执行力，彼此信任 相互支持，演绎了王者之师的强大实力。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746751348df3.jpg&quot; title=&quot;1E441394A27992B2CF6F1E79F35B0796(1)&quot; alt=&quot;1E441394A27992B2CF6F1E79F35B0796(1)&quot;/&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;明日之星正在发光，未来之星也已锋芒初露。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;作为豫工的新生力量，他们以超强的爆发力，敢想敢干，敢拼敢闯，让豫工的未来之路动力十足。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746813cea6b4.jpg&quot; title=&quot;IMG_8725 拷贝&quot;/&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507468132a75ac.jpg&quot; title=&quot;IMG_8727 拷贝&quot;/&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;领奖台上王冠耀眼，领奖台下掌声不息。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;不忘初心 保持热爱，每一次平凡的坚守，都在此刻有了具体的意义，豫工的英雄们，祝贺你们！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507472166a285b.jpg&quot; title=&quot;b634798fd2bfb52b7144a5b9a057592f 拷贝&quot; alt=&quot;b634798fd2bfb52b7144a5b9a057592f 拷贝&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;股东分红&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;当豫工的航船驶过第二十年的壮阔征程，公司再次为股东们发放分红。他们既有远见、也有预见，更是对豫工的未来保持着足够的信心。他们是豫工发展的支柱，是最宝贵的财富。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746871b6a454.jpg&quot; title=&quot;999bd0c8-068b-4398-8209-9e11823fbcab 拷贝&quot;/&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/175074687175273e.jpg&quot; title=&quot;f1b23421-4d97-4054-a2f7-86c53e60194f 拷贝&quot;/&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750746871c3db89.jpg&quot; title=&quot;fb08f19f1f66bdc26e2c7927b5f0a86f 拷贝&quot;/&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/175074690356c8fe.jpg&quot; title=&quot;4&quot; alt=&quot;4&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;能量迸发：盛夏大战再出征&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;20年辉煌，精彩继续......&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;盛夏大战的战鼓已响，这是豫工扎根20年的能量迸发，是勇者争锋的广阔舞台，处处是挑战，也时时是机会，深耕当下，必能赢战未来。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507469978b1550.jpg&quot; title=&quot;1229ce638b2f91ea841bdcc822167d2 拷贝&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507469971f10f8.jpg&quot; title=&quot;A1FE0EA99DB8BAC658A980ADB3779AA5 拷贝&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507469972c4bbe.jpg&quot; title=&quot;APCYD}V4TM82KUVW3ZE09%2 拷贝&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;没有天生的王者，只有拼搏的英雄。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;盛夏誓师大会，每个人目标明确 誓言坚定。团队代表热情发言，分享干货 信心十足，吹响了豫工人冲锋的号角。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507470418e3e04.jpg&quot; title=&quot;D6`7XNHS8WBA}BRJBYLC~{O 拷贝&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750747041777b63.jpg&quot; title=&quot;eb1e2a0364a3407ad94bce70c2601c77 拷贝&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;工作的深度决定成绩的高度。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;盛夏大战，豫工人将继续以客户为中心，以奋斗者为根本，直面挑战，坚韧坚强，用实力证明，豫工人有信心、有能力，迎接新未来、新挑战。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/1750747114be2980.jpg&quot; title=&quot;3&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/17507471145b04c5.jpg&quot; title=&quot;IMG_8697 拷贝&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;《豫工战歌》歌声嘹亮，致敬每一位奋斗的豫工人！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;二十年峥嵘岁月深情回望，感恩每一位合作伙伴的信任，每一位员工的付出，每一位客户的陪伴！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;让我们携手并肩，以今日庆典为起点，共同书写豫工下一个二十年的璀璨华章！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202506/175074718386c66c.jpg&quot; title=&quot;28CC6937BBFC3702FE724BDEA410B3BE 拷贝&quot; alt=&quot;28CC6937BBFC3702FE724BDEA410B3BE 拷贝&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;没有躺赢的盛夏，只有奋进的足迹。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;盛夏大战已至，此刻，让我们同舟共济，分工合作，心往一处想，劲往一处使，让这个盛夏，留下我们拼搏的传奇！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;让豫工因我们而不同！&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;小伙伴们，加油！！！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(441, 2, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;如何选择一台合适的除雪滚，绝不是简单的“看报价、比大小”，而是一场系统性的需求匹配工程。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;img src=&quot;http://oss12.huangye88.net/live/ueditor/php/upload/4026870/image/20251218/1766022443164479.png@750w_750h_90Q&quot; alt=&quot;如何选到合适的除雪滚型号&quot; style=&quot;max-width: 710px;&quot; width=&quot;710&quot; height=&quot;563&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;如何选到合适的除雪滚型号&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;第一步：看匹配&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在查看任何具体型号前，先回答以下三个问题，它们构成了选型的“黄金三角”：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;匹配主机：您计划将除雪滚安装在什么设备上？&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;装载机：常用，需明确主机型号、吨位、液压系统流量（升/分钟）和工作压力（兆帕）。这是决定滚刷尺寸和驱动方式的核心。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;拖拉机：需注意后置三点悬挂的型号和液压输出功率。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;滑移装载机：需关注其特殊的快换接头和相对较小的流量。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;清雪车：通常为定制化接口。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;关键：“小马拉大车”会动力不足，“大马拉小车”则造成浪费和风险。 获取主机的准确技术参数。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;匹配雪情与工况：您主要应对什么类型的雪？在什么路面上作业？&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;雪质：蓬松新雪、潮湿重雪、还是已被压实的雪板？这直接决定对滚刷材质和驱动力的要求。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;路面：平坦的柏油路、有铺装砖的人行道，还是不平整的场地？这关系到是否需要“浮动避障”功能和刷丝的硬度选择。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;作业环境：是否有路边护栏、路沿石、车辆等障碍物？是否需要“雪橇式”侧滑板来保护设备和路面？&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;匹配管理目标：您追求清雪速度，还是更关注路面保护和无残留？&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;效率：倾向于选择更宽的滚刷、更高的转速，材质可能更耐磨。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;洁净度：可能需要更密的刷丝排列、更好的聚雪效果。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;多功能性：是否考虑快速更换其他属具（如铲斗）？这会影响连接架的选择。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;img src=&quot;http://oss12.huangye88.net/live/ueditor/php/upload/4026870/image/20251218/1766030899474531.jpg@750w_750h_90Q&quot; alt=&quot;如何选到合适的除雪滚型号&quot; style=&quot;max-width: 710px;&quot; width=&quot;710&quot; height=&quot;399&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;如何选到合适的除雪滚型号&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;第二步：看配置&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;完成需求匹配后，便可深入解读设备的具体参数：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;1. 滚刷尺寸 宽度：常见1.5米-3.5米以上。 宽度不得超过主机宽度的1.2倍，并考虑运输和道路宽度限制。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2. 刷丝材质&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;聚丙烯（PP）：刷丝耐磨、弹性好、不伤路面，适用于铺装路面和清除薄雪，比如市政、小区、人行道等对路面保护要求高的场景。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;钢丝/合金钢丝刷：强度高，耐磨性，可破碎压实雪，适合高速公路、压实雪、非铺装路面 等重载工况。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;混合刷丝（PP包裹钢丝）：兼顾清洁性与耐磨性。通用性选择，适合雪情复杂的地区。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;3. 驱动方式&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;机械传动：由主机动力输出轴驱动，结构简单，成本低，但对主机有要求。与特定型号拖拉机匹配时可以考虑。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;液压马达驱动：主流方式，由主机液压系统驱动，转速可调，扭矩大，布局灵活。绝大多数装载机、滑移装载机的理想选择。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;4. 功能与结构&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;定心/偏心设计：偏心设计清雪更干净，但对动力要求更高。如果你对清洁度要求高时，可以选偏心式。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;避障功能：弹簧浮动或液压浮动，使滚刷能适应路面起伏，保护刷丝和设备。不平整路面、有路沿石场景的标配。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;折腰转向：滚刷自身可左右偏转一定角度，方便推出路缘积雪。非常实用的功能，能显著提升作业灵活性。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;img src=&quot;http://oss13.huangye88.net/live/ueditor/php/upload/4026870/image/20251222/1766393335154380.jpg@750w_750h_90Q&quot; alt=&quot;如何选到合适的除雪滚型号&quot; style=&quot;max-width: 710px;&quot; width=&quot;710&quot; height=&quot;532&quot; border=&quot;0&quot; vspace=&quot;0&quot; title=&quot;如何选到合适的除雪滚型号&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;第三步：看服务&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;供应商能力评估：设备的价值一半在于产品，一半在于服务。考察供应商的服务响应速度。配件库存充足度（尤其是刷丝）。技术支持与培训能力。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;font-size: 16px; text-wrap: wrap; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;总之，选择一个合适型号的除雪滚，不能只看价格，也不能只看参数，而是与您的主机、雪情、路面和管理目标契合度高的那一台。&lt;/span&gt;&lt;/p&gt;');
INSERT INTO `dr_1_xinwenzhongxin_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(442, 2, 10, '&lt;p segoe=&quot;&quot; open=&quot;&quot; helvetica=&quot;&quot; text-wrap:=&quot;&quot; background-color:=&quot;&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; font-size: 16px; text-wrap: wrap; color: rgb(15, 17, 21);&quot;&gt;&lt;img src=&quot;http://oss13.huangye88.net/live/ueditor/php/upload/4026870/image/20251222/1766392631337721.jpg&quot; title=&quot;豫工道路破冰机多少钱一台&quot; alt=&quot;豫工道路破冰机多少钱一台&quot; width=&quot;473&quot; height=&quot;351&quot; style=&quot;width: 473px; height: 351px;&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;道路破冰机的价格由其根本类型和应用定位决定，主要分为三大价格梯队：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;1. 基础功能级（轻型/附属式）&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;价格区间：约 3万 - 15万元人民币&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;设备描述：主要为手推式小型电动或汽油机驱动设备，或可快速挂接于小型拖拉机、装载机的轻型附属装置。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;适用场景：社区人行道、广场、非主干道的薄冰处理。破冰能力有限，适用于冰层较薄、强度较低的工况。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;2. 主力作业级（中型/标准工程型）&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;价格区间：约 15万 - 50万元人民币&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;设备描述：这是市场需求集中的区间。主要为液压驱动，可匹配标准型装载机、拖拉机等主流主机。采用冲击夯或铣削滚筒等成熟工作原理，材料与工艺达到工程机械标准。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;适用场景：市政道路、普通公路、机场滑行道的常规破冰作业。具备可靠的工作效率与耐用性，是养护单位的核心装备。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;3. 级（重型/特种定制型）&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;价格区间：约 50万 - 120万元以上&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;设备描述：针对高强度、率需求设计。采用全液压高速冲击或重型铣削技术，关键部件（如液压泵、马达、轴承）采用国际，钢结构进行强化设计。通常具备智能控制、功率自适应等功能。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;适用场景：高速公路、重交通流量城市干道、严寒风区应对压实冰雪，以及机场跑道等对作业质量和时效性要求的场景。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202512/176682744180bda0.jpg&quot; title=&quot;豫工道路破冰机多少钱一台&quot; alt=&quot;豫工道路破冰机多少钱一台&quot; width=&quot;774&quot; height=&quot;581&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;二、核心配置与性能参数对价格的影响&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;在同一类型区间内，具体配置是造成价格分化的直接原因。主要成本变量包括：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;驱动与动力系统：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;机械式传动：成本较低，但效率和控制性一般。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;标准液压系统：主流选择，价格适中，性能可靠。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;闭式液压系统：效率更高，响应更快，耐久性更好，价格显著提升。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;工作机构与材质：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;破冰刀具/锤头：普通合金钢与高强度耐磨合金钢（如哈氏合金）的成本差异可达数倍，直接决定使用寿命和作业效果。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;主机架钢材：Q345B普通钢与高强度耐磨钢板的选用，影响设备整体重量、强度和抗疲劳能力。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;控制系统与技术附加值：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;基础手动操纵阀与先导液控或电液比例控制系统的价差。后者能实现冲击频率、幅度的无极调节，提升作业精度与油耗经济性。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;是否集成智能诊断、物联网接口等，也属于增值配置。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202512/1766827478072145.jpg&quot; title=&quot;豫工道路破冰机多少钱一台&quot; alt=&quot;豫工道路破冰机多少钱一台&quot; width=&quot;774&quot; height=&quot;581&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;三、品牌与供应链的价值溢价&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;一线国际品牌：价格通常高，溢价源于长期积累的品牌信誉、全球统一的制造标准、经过验证的极端工况可靠性以及全球性的服务网络。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;国内品牌：性价比优势明显，价格位于中高位。其价值在于更贴合国内工况的设计优化、更快的服务响应速度和相对完善的配件供应体系。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;中小型制造商：提供具价格竞争力的产品，价格处于区间低端。采购应放在其特定型号的成熟度、关键部件来源及售后保障能力的具体核查上。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202512/1766827509228548.jpg&quot; title=&quot;豫工道路破冰机多少钱一台&quot; alt=&quot;豫工道路破冰机多少钱一台&quot; width=&quot;774&quot; height=&quot;774&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;四、采购模式带来的价格差异&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;直接购买：需支付全款，获得设备所有权。大宗采购或年度框架协议通常可享有折扣。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;融资租赁：通过金融机构以“租代购”，降低初期投入门槛，总成本会包含利息，略直接购买，但改善了现金流。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;经营性租赁：为实际使用时间付费，无资产负担。长期看单日成本可控，但累计费用可能超过购买价。适合需求不确定或季节性的用户。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;“道路破冰机多少钱一台？”的答案，不在任何一份现成的价目表里，而在采购方自身需求与设备所能提供全生命周期价值的匹配度之中。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;行业采购的成熟路径，是完成严谨的自我工况分析，然后以此为基础，寻求在既定预算内能够提供高可靠性和低综合使用成本的设备解决方案。&lt;/span&gt;&lt;/p&gt;&lt;p segoe=&quot;&quot; open=&quot;&quot; helvetica=&quot;&quot; text-wrap:=&quot;&quot; background-color:=&quot;&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; font-size: 16px; text-wrap: wrap; color: rgb(15, 17, 21);&quot;&gt;&lt;br/&gt;&lt;/p&gt;'),
(443, 2, 10, '&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;选购&lt;a href=&quot;https://www.zzyugong.cn/show-103.html&quot; target=&quot;_self&quot;&gt;&lt;strong&gt;除雪滚&lt;/strong&gt;&lt;/a&gt;时，许多用户的反应往往是“多少钱？”——价格固然重要，但单纯对比数字容易陷入误区。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;一台真正“值”的除雪滚，不是价格低的，而是在您的使用场景下，用合理的成本实现率和长使用寿命的设备。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;看懂以下三点，您就能跳出“比价陷阱”，做出明智选择。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;除雪滚的价格差异，主要来自以下几个核心配置，它们直接决定了设备的性能和耐用度：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px; text-wrap: nowrap;&quot;&gt;第一、刷丝材质与工艺&lt;/span&gt;&lt;/strong&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px; text-wrap: nowrap;&quot;&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;基础型：普通钢丝，耐磨性一般，适合雪质较软、使用频率低的场景。价格较低。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;值型：高强度弹簧钢丝或聚丙烯（PP）+钢丝混合刷丝。耐磨、抗冲击、不易折断，能有效清除压实的冰雪&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202512/176682779072ab52.jpg&quot; title=&quot;d7b83c1a-1bdf-4adf-8e61-dcf239a97e48&quot; alt=&quot;d7b83c1a-1bdf-4adf-8e61-dcf239a97e48&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;第二、驱动方式&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;机械式：依靠装载机等主机液压系统，结构简单，价格较低，但对主机有一定要求。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;立液压式：自带液压马达和控制系统，转速可调，扭矩大，清雪效率更高，适应复杂工况。价格更高，但性能显著提升。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202512/1766827806716db4.jpg&quot; title=&quot;046efc1f-fbb7-4566-87a6-0a51572283e1&quot; alt=&quot;046efc1f-fbb7-4566-87a6-0a51572283e1&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;第三、关键部件品牌&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;液压马达、轴承、密封件等是“心脏”，关注。采用的配件，故障率低，耐用性好，价格自然上浮。这部分的投入换来的是长期作业的可靠性和更低的维修成本。你想怎么选，只能根据自己的情况来选择！如果您要长时间、多频次使用，建议您选好一点的配置！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 16px;&quot;&gt;您的判断标准：询问供应商具体的配置细节，并思考：“这个配置能否应对我当地常见的硬雪、冰板？能否承受一个冬季的高强度作业？”&lt;/span&gt;&lt;/p&gt;'),
(456, 2, 9, '&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2025年9月18日，豫工机械“金秋当燃 再启新程”启动会在郑州总部营销中心盛大举行。国内事业部200多人斗志昂扬、气势如虹，共赴一场属于拼搏者的金秋之约！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701022534a1939.jpg&quot; title=&quot;c9a10a6fa28a051fb777637f588ba930&quot; alt=&quot;c9a10a6fa28a051fb777637f588ba930&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;在激昂的乐曲中，豫工人步伐铿锵、意气风发，依次进入会场。各团队誓言如潮，接力传递，为豫工机械2025金秋攻坚拉开序幕！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770102272658b08.jpg&quot; title=&quot;其他 (4)&quot; alt=&quot;其他 (4)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;营销总监卢总监为大会作动员致辞。她强调，金秋大战不仅是业绩的角逐，更是自我超越的征程。她鼓励大家突破极限、重塑自我，在挑战中历练，在辉煌中成长！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010230107ed04.jpg&quot; title=&quot;4B0C556B222510DED1A8FCC41E8031B7&quot; alt=&quot;4B0C556B222510DED1A8FCC41E8031B7&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;八大业务战队依次登台，展示风采、亮出目标，展现“使命必达”的坚定信念。&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010234820ac67.jpg&quot; title=&quot;蚂蚁队&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701023488d2ad1.jpg&quot; title=&quot;蜜蜂队&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770102348085e43.jpg&quot; title=&quot;齐心聚力&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701023480d3492.jpg&quot; title=&quot;扬帆队&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;启动会上，团队代表科学拆解金秋目标、有序规划每日工作，稳住节奏、扎实推进，誓要突破所有关卡，撕开金秋必胜的突破口！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010236714219c.jpg&quot; title=&quot;cf7f56d8e761027824a5aa41012e5d09&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701023674445ec.jpg&quot; title=&quot;其他 (1)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701023671e8c4f.jpg&quot; title=&quot;组 1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;有人展示目标路径，有人赋能团队成长，他们将工作中积累的实战经验，毫无保留地分享出来，多传帮带，助力大家少走弯路，早日登顶！&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770102384ba2002.jpg&quot; title=&quot;其他 (6)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701023842f1c6a.jpg&quot; title=&quot;其他 (7)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;掌声与呐喊点燃了所有人的斗志。既有新兵的锐气，也有老将的担当。新老员工纷纷登台，热情分享在豫工的成长与收获：是能力的跃进、是格局的打开、是价值的提升！&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;他们感谢团队的托举，感恩公司的信任，饱满热情，自信满满，与大家相约金秋大战再续荣光，与豫工继续双向奔赴、共创辉煌。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701024185f9dbb.jpg&quot; title=&quot;扬帆队&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770102418c0748f.jpg&quot; title=&quot;勇敢者&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770102418cdf175.jpg&quot; title=&quot;追光者&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;业绩PK引爆现场气氛！大家主动突破舒适区、勇于挑战新目标，将金秋大战视为最好的磨刀石，共拼、共闯、共赢、共绽放！&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;每个人目标明确、信念坚定，以“我能我行”的魄力，紧跟公司节奏，紧盯目标进度，做团队的粘合剂、目标的推进剂、成功的压舱石——协同配合，战出辉煌！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010245038771e.jpg&quot; title=&quot;其他 (6)&quot; alt=&quot;其他 (6)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;长长的奋斗史，记录了豫工人的荣光和成绩！站在2025金秋大战的起点，全体豫工人将以更强的凝聚力、更高的战斗力，开启金秋新征程，赢战新未来！&lt;/span&gt;&lt;/p&gt;'),
(457, 2, 9, '&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;中秋未至，祝福已达。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;有一种幸运叫“豫工福利”，&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;它如春花秋月，夏蝉冬雪&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;总在恰好的时节&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;为我们增添生活的美好。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701032480fe4f3.jpg&quot; title=&quot;)K3)PG]J(6A6B(A6PSR77T0&quot; alt=&quot;)K3)PG]J(6A6B(A6PSR77T0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;9月26日&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工集团为全体员工送上中秋福利&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;礼盒双份，心意加倍&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械、富来机械、豫工严选&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;集团旗下三大业务公司&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;近千名员工&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;深切感受到豫工的祝福&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010326744d0cc.jpg&quot; title=&quot;2c974bf4313063a02cb3b8de939cc785&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010326786bf66.jpg&quot; title=&quot;3C6DC3EBA42C1C1096757EE312CBDB5D&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010326771307f.jpg&quot; title=&quot;14a8b2d058facd80921dc2f73439baed&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770103267611948.jpg&quot; title=&quot;865E862E143F7419F7A410ADD1C1E091&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;礼物甜甜，情意绵绵&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;笑容，绽放脸上&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;温暖，流淌心间&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;中秋的喜悦&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;洋溢在每一个豫工人的眼眸&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17701033007bad3b.jpg&quot; title=&quot;BF`EU_TQD8C0]WJ7B93SEDV&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770103300fa24f6.jpg&quot; title=&quot;微信图片_20250924110124_6_443&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770103300afac0f.jpg&quot; title=&quot;微信图片_20250924110125_7_443&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在豫工&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;节日的祝福从未缺席&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;每一份精心准备的礼物&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;都是豫工人踏实前行的底气&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;它让平凡的日子浸润甜蜜&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;让奋斗的岁月更有温度&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770103329e4b395.jpg&quot; title=&quot;2de4c0012dcf5476cd7e76c51308ed33&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770103329c5dbab.jpg&quot; title=&quot;5de8d41c8254227bbe360fa4c891bc3a&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;有幸相聚，不负时光&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;未来&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;愿我们继续携手并肩&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;珍惜当下，全力以赴&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;与豫工共成长，与未来同前行&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010334045bdf4.jpg&quot; title=&quot;4156cafc8090ec803d715ddb0d914e00&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/177010334020f2f1.jpg&quot; title=&quot;P74OPGT$MY2V2579IEP`]WQ&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;月满中秋，情满豫工&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;值此中秋佳节&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工集团全体员工&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;向新老客户朋友致以诚挚的祝福&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;祝大家&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;事业顺遂，家庭美满&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;身体安康，心想事成&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;中秋节快乐！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(462, 2, 10, '&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770712368449d56.jpg&quot; title=&quot;清淤机器人施工现场&quot; alt=&quot;清淤机器人施工现场&quot; width=&quot;665&quot; height=&quot;499&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;豫工机械清淤机器人操作流程&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1、开机前检查清淤机器人和液压动力系统是否有漏油，电缆连接是否有破损、虚接，机械连接部分是否有松动，观察液压油箱油位是否&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;达到指示位置。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2、主电缆进入控制电箱是否连接牢固可靠，不得有虚接或缺相。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;3、将控制箱内主空并断路器合闸，同时观测控制柜控制面板是否有电电压指示显示，确认无误后，即可进行机器人操作。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;4、手持遥控控制器，调节液压系统溢流阀手轮逆时针调至最小处，松开侧面急停按钮，按下电源按钮，拨动油泵升关，启动液压系统，等待10s钟，待液压系统完全启动，同时控制箱控制面板油泵指示灯&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;亮起。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;5、拨动遥控器水泵拨杆，将水泵启动，然后顺时针转动液压系统溢流阀手轮，直至压力达到10Mpa，观察水泵是否正常运行，拨动遥杆绞宠开关观察清淤螺旋是否正常运行，拨动遥杆绞宠升降开关，观察油缸是否正常运行，运行正常后关闭，水泵，绞龙开关，绞龙升降，拨动左前进、左后退、右前进、右后退遥杆，观察机器人行走状态是否正常，运行正常后关闭，拨动照明开关和收放绞盘，运行正常后关闭，关闭油泵开关，关闭液压系统，然后转动溢流阀手轮调至最小处（避免误操作导致下次开机压力过高，对设备造成损伤&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;或损毁）&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;6、确认所有功能正常，清淤机器人可进入清淤工作区域，将主控箱空气断路器合闸，便用遥控器打开油泵升关，等待10s钟后，液压系统启动后，开启水泵和螺旋开关，手动拨动液压系统溢流阀手轮，缓慢顺指针转动手轮，将压力调整为10Mpa，绞龙升降遥杆调整合适位置后，可进行清淤作业，根据水泵流量大小可通过控制液压系统溢流阀手轮调整（压力不得天于15Mpa）。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;7、此区域清理完毕后，关闭水泵和螺旋，通过遥杆控制左前进、左后退、若前进、若后退更换清淤位置（同时控制收放管升关，收放油管长度，达到清淤位置），待到达更换位置后，依次打开水泵和绞龙开关再此进行清淤作业。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;8、清淤任务完成后，关闭油泵开关，将液压系统溢流阀手轮逆时针调至最小处，关闭遥控器电源，同时切断控制箱空气断路器。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(463, 2, 10, '&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;清淤机器人是用于河道、水库、管道、市政窨井等场景的智能化清淤装备，目前市场上主流型号主要根据应用场景、技术特点和品牌进行区分。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770716336f2f111.jpg&quot; title=&quot;豫工机械清淤机器人调试现场&quot; alt=&quot;豫工机械清淤机器人调试现场&quot; style=&quot;font-size: 16px;&quot; width=&quot;665&quot; height=&quot;499&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;豫工机械清淤机器人根据清淤工作宽度，分为500电动型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&lt;/span&gt;、600&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;电动&lt;/span&gt;型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人、&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;700&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;电动&lt;/span&gt;型清淤机器人、&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;800&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;电动&lt;/span&gt;型清淤机器人、&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;900&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;电动&lt;/span&gt;型清淤机器人。&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: wrap; font-size: 16px;&quot;&gt;所有型号均采用履带式行走（速度2km/h）、无线遥控操控，并标配水下LED照明系统，保障在昏暗水下环境的可视性与操作便利性。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: wrap; font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770716516a4f89e.jpg&quot; title=&quot;豫工机械清淤机器人下井试机&quot; alt=&quot;豫工机械清淤机器人下井试机&quot; width=&quot;665&quot; height=&quot;499&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: wrap; font-size: 16px;&quot;&gt;从500型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&lt;/span&gt;到900型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&lt;/span&gt;，施工的时候应该如何选择？&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;500/600电动型 中小型市政管道、箱涵、狭窄河道、厂区沉淀池。 机身紧凑，转向灵活，适合在受限空间内作业；功耗相对较低。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;700/800电动型 大型排水管道、河道、景观湖、水库沿岸、港口码头。 清淤宽度与抽排效率均衡，综合性价比高，应对常规清淤任务游刃有余。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;900电动型 大型河道主干道、蓄洪区、大面积鱼塘清淤、应急抢险工程。 单次作业覆盖面最大，抽排能力最强，适用于对作业效率有严苛要求的大型工程。&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: wrap; font-size: 16px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: wrap;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;text-wrap: wrap;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(464, 2, 10, '&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770778082c7534a.jpg&quot; title=&quot;豫工机械绿篱修剪机安装现场&quot; alt=&quot;豫工机械绿篱修剪机安装现场&quot; width=&quot;665&quot; height=&quot;499&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1、开始作业之前，要认真检查机体各部，在确认没有螺丝的松动、漏油、损伤或变形等情况后方可开始作业。特别是刀片以及刀片连接部位更要仔细检查。　　&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2、确认刀片没有崩刃、裂口、弯曲之后方可使用。绝对不可以使用已出现异常的刀片。　　&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;3.在使用过程中，如果人员离开或者需要转移作业场所，必须先关闭发动机直至刀片停止。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;4.在通风良好的地方使用绿篱机，因为工作过程中会排放出一氧化碳等有毒气体，千万不要在通风不良的地方使用。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;5、每次使用绿篱机之前必须检查各零件螺钉，螺母连接是否紧固可靠，零部件有无松动、磨损、损坏等。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;6、每次使用绿篱机之前，必须检查熄火开关及熄火线是否正常，检查熄火开关旋钮扳动是否灵活，有无卡滞，检查熄火线连接是否正常，有无脱落。以确保在使用过程中发生意外时能及时熄火，以保障人身安全。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;7、初次使用需注意：修剪机初次使用前必须车辆低速工作，熟练后在高速工作。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;8.警告：严禁急加速和急停机，以免损坏发动机机，严禁在无空滤器的情况下启动发动机机会因转速过高时使气缸过热而损坏，或因杂质进入气缸导致拉缸等。严禁使用劣质油做燃料，会导致发动机过热而损坏。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;9、严禁使用劣质机油，以免损坏汽油机、气缸、活塞、活塞环、曲轴连杆、轴承、油封、化油器等。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;10.严禁烟火，并远离火源。11.绿篱机每次使用后需注意请保持绿篱机干燥、清洁&lt;/span&gt;&lt;/p&gt;'),
(465, 2, 10, '&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770779064618a4e.jpg&quot; title=&quot;避障式割草机施工现场&quot; alt=&quot;避障式割草机施工现场&quot; width=&quot;665&quot; height=&quot;499&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1.剪刀运转累计8-12小时，向转轴部位注满高温润滑脂；&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2.及时注入#92汽油，应勤检查汽油箱容量，避免油烧干后进入空气后无法启动&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;3.修剪3小时要检查水箱，散热器；适当添加冷却液&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;4.随时检查发动汽油、机油、是否充足；&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;5.长期停放应把主体放在托架上，刀头立起，缩回横臂应盖雨布或放入车库；&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;6.修剪机需专人操作、管理、保养。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;7、每次工作前要检查刀片固定部分的松动。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;8、蓄电池连续超过1个月不用，应及时给电瓶充电&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;'),
(466, 2, 10, '&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;避障式割草机是一种先进的园艺工具，它通过搭载传感器和导航系统，能够自动识别并避开障碍物，如树木、花坛、步道等，无需人工干预。这种割草机特别适合地形复杂、有多种障碍物的环境，它能够节省用户的时间和精力，提高作业效率，同时降低人工操作的安全风险。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770780255eb2b05.jpg&quot; title=&quot;避障式割草机工作原理&quot; alt=&quot;避障式割草机工作原理&quot; width=&quot;665&quot; height=&quot;499&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;避障式割草机的特点主要包括：&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;高效性：能够快速高效地进行修剪作业，提高工作效率。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;灵活性：可以上下左右进行调节，全方位修剪，适应不同的修剪要求。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;省力性：只需要配一台发电机就可以工作，不需要使用车的动力，适用于任何车型安装，只需一人就可以操作。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;安全性：能够自动躲避障碍物，减少劳动力或不安全因素，增强修剪效果。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;耐用性：机身和刀头一般都采用特殊高强度的耐磨材料制造而成，确保了设备的耐用性。&lt;/span&gt;&lt;/p&gt;'),
(467, 2, 10, '&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;汛期来临，如何选择一台“靠谱”的防汛泵是应对内涝的关键。不同类型的泵适用于不同场景，选对才能高效排水。以下为您推荐几款主流防汛泵，助您精准决策。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1. 便携式轻型潜水泵：应急抢险首选&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;代表泵型：高扬程小型潜水电泵（如口径2-4寸），永磁泵等&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;核心优势：重量轻、移动灵活、接电即用。通常采用铝合金机身，坚固耐用。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;适用场景：地下室、车库、小区低洼处等小范围短时积水抢排。单人即可操作，是家庭和物业应急的“尖兵”。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770783339e98e1d.jpg&quot; title=&quot;永磁防汛泵&quot; alt=&quot;永磁防汛泵&quot; width=&quot;665&quot; height=&quot;665&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2. 大流量轴流泵：快速降低大面积积水&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;代表泵型：固定式或浮筒式轴流泵（口径可达300mm以上）。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;核心优势：流量极大（每小时可达数千立方米），扬程适中，专为快速排除大面积浅层积水设计。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;适用场景：城市道路、立交桥下、广场、农田等开阔区域的大范围积水排放。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/1770783532ad2980.png&quot; title=&quot;潜水轴流泵&quot; alt=&quot;潜水轴流泵&quot; width=&quot;665&quot; height=&quot;571&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;3. 多功能排污泵：应对复杂积水&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;代表泵型：重型潜水排污泵（带涡流或切割叶轮）。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;核心优势：通过能力强，可处理含有泥沙、细小杂质的浑浊积水，不怕堵塞。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;适用场景：工地基坑、排水边沟、河道辅助排水等水质浑浊、杂物较多的环境。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17707836167347c2.jpg&quot; title=&quot;防汛泵&quot; alt=&quot;防汛泵&quot; width=&quot;665&quot; height=&quot;499&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;4. 自动启停一体化泵站：智慧值守&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;代表泵型：集成了水泵、控制系统和液位传感器的智能一体化泵站。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;核心优势：全自动运行。水位达到设定值自动启动，抽干后自动停止，无需人工值守。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;适用场景：地下车库、下沉隧道、市政泵站等需要长期自动监控和排水的关键部位。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202602/17707836423a19b0.jpg&quot; title=&quot;防汛机器人&quot; alt=&quot;防汛机器人&quot; width=&quot;665&quot; height=&quot;887&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;选型核心建议：&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;首先明确 “流量-扬程” 需求：需要排多远（扬程）？需要多快排完（流量）？&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;其次判断 水质情况：是较清洁的雨水，还是含杂质的污水？&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;最后考虑 使用场景：是移动应急，还是固定安装自动运行？&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;掌握以上要点，您就能根据实际汛情，选择最“合适”的防汛利器。&lt;/span&gt;&lt;/p&gt;'),
(470, 2, 9, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2026年3月5日，豫工集团国内事业部旺春大战启动会火热启幕，128名豫工人聚集一堂，以背水一战的决心，共同吹响旺春大战集结号。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731150981988ea.jpg&quot; title=&quot;066f8a54-7a3c-460c-8783-22630d224941&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731150981d38c9.jpg&quot; title=&quot;IMG_20260305_154320_1&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;国内事业部总经理侯总首先致辞，他回顾了豫工人一路走来的拼搏历程，并发出热情动员：“希望每个豫工人都能在本次旺春大战中，找回初入豫工时的状态——为荣誉全力以赴、为目标拼尽全力”！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;面对2026的市场发展，侯总勉励大家不忘初心，不惧挑战，继续发扬敢想敢干、敢打敢拼的奋斗精神，不抛弃、不放弃，全力以赴，赢战旺春。”&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115152ca3630.jpg&quot; title=&quot;90fda5d0-9d8c-4428-aa32-308947b63135&quot; alt=&quot;90fda5d0-9d8c-4428-aa32-308947b63135&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;营销总监以一场别开生面的互动游戏，诠释“敢想敢干”的豫工精神。李总监掷地有声地指出：“旺春大战，机会永远在那里，犹豫就会错过，行动才有结果！”他鼓励大家带着“敢信即能赢”的锐气，在旺春战场上，多一点耐心、多一份主动，多一次争取，破除心障，目标必达。“&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731152516a4dd0.jpg&quot; title=&quot;451333e7-0d09-4a1b-9e55-29d0161a32cb&quot; alt=&quot;451333e7-0d09-4a1b-9e55-29d0161a32cb&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;为了激发战斗潜能，高效服务客户，本次旺春大战创新战法，80名业务精英结队重组，后勤骨干下沉至业务团队，形成8支全新战队，通力配合，一起战，一起赢！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115308631524.jpg&quot; title=&quot;IMG_20260305_144748&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115308645688.jpg&quot; title=&quot;IMG_20260305_144930&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;20分钟的小组共创，再次见证了豫工人强大的执行力：8面战旗相继诞生，签在旗上的队名、写在旗上的目标，承载着每个人必胜的信念。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731153635ac65d.jpg&quot; title=&quot;IMG_20260305_150407&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115363ec3e08.jpg&quot; title=&quot;IMG_20260305_150457&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115363306250.jpg&quot; title=&quot;IMG_20260305_150506&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731153644f4121.jpg&quot; title=&quot;IMG_20260305_150527&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;战旗挥动，力量在此凝聚；呐喊震天，信念愈发坚定。当各小组竞相冲上舞台，展示自己，全场掌声雷动，128颗心、128份决心，汇成同一个声音：“豫工必胜！旺春必胜！”&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115433c3a305.jpg&quot; title=&quot;00c058b6-e8a7-446a-8aa3-0b02291a89aa&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731154338964cb.jpg&quot; title=&quot;46e18a2e-36ab-42cf-8c4e-cab82821def0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115433147b8a.jpg&quot; title=&quot;75cd18ac-b46a-4cfc-9ce3-305ab0d2e7d9&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115433d5ca01.jpg&quot; title=&quot;aa77e616-6ef5-4fe0-ada6-12054707d9aa&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115433e47c11.jpg&quot; title=&quot;ea3d94f9-f8c5-4bce-be22-3fb8d11dbd71&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731154334958b7.jpg&quot; title=&quot;f3b4dea7-f26a-42ef-8273-1c9f2ea45a25&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;小组PK，战火重燃。无论是发起挑战还是接下战书，每个小组都气势如虹、锋芒毕现。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115510125f3f.jpg&quot; title=&quot;IMG_20260305_161231&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/177311551009fb4d.jpg&quot; title=&quot;IMG_20260305_163808_1&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115510c047fb.jpg&quot; title=&quot;IMG_20260305_171223&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;每一句自信张扬的挑战宣言，每一个掷地有声的应战回应，都是豫工人对旺春必胜的信念，对自身实力的肯定。战书已下，军令状已签，冲锋号角响彻心间。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731156001f04d9.jpg&quot; title=&quot;IMG_20260305_151813&quot; alt=&quot;IMG_20260305_151813&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;分享环节，团队代表纷纷表示：面对2026年的经济压力，豫工人更要珍惜时间，抓住机会，不负每一位客户的信任；不忘初心，真正解决客户需求，继续与客户实现良性而持久的合作，携手同行，一起旺，一起赢！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/177311570910a1fa.jpg&quot; title=&quot;IMG_20260305_162533&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/177311570920562a.jpg&quot; title=&quot;IMG_20260305_163657&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731157090ce644.jpg&quot; title=&quot;IMG_20260305_170256&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773115709ea0e99.jpg&quot; title=&quot;IMG_20260305_170748&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在掌声与期待中，工厂的研发、生产、售后、发货部门代表登台分享。这些集团的幕后英雄，为旺春大战的胜利给出最有力的承诺。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;厂长表示：“2026年，工厂将继续坚持研发创新，保生产、保品质、保工期！精益求精，不让任何一台设备带问题出厂，不让任何一个承诺落空！坚持客户至上，保售后、保响应，确保24小时极速响应、72小时闭环解决，用行动兑现每一份信任！”&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/177311576875c27b.jpg&quot; title=&quot;IMG_20260305_171404&quot; alt=&quot;IMG_20260305_171404&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在全员期待的目光中，董事长登台致辞。李总表示：“豫工人的实力一直很强，旺春大战，要继续保持这种旺盛的内驱力，主动出击！抓大放小，把精力聚焦在最重要的事情上；避免内耗内卷，不做无谓的消耗，要向外求、稳扎稳打。不忘初心，顶住压力，大家一起努力，让豫工年年旺春年年旺，年年翻番年年翻！”&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17731158464b3413.jpg&quot; title=&quot;IMG_20260305_172341_1&quot; alt=&quot;IMG_20260305_172341_1&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;他特别强调：对客户，我们要更负责、更专业、更有诚意——客户把信任交给我们，我们要用品质和服务去回报他们，今年，工厂要继续加大研发投入，狠抓品质，让客户满意，与客户共赢！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/177311605139839d.jpg&quot; title=&quot;fd302fb1-ce07-4ed8-902b-207efcd4a04f&quot; alt=&quot;fd302fb1-ce07-4ed8-902b-207efcd4a04f&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;战鼓齐鸣，礼花满天，致敬每一位奋斗的豫工人！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;站在2026新的起点，豫工人将继续用最饱满的热情，向旺春目标发起总攻。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;我们坚信，在全体豫工人的共同努力下，今年的旺春战绩，将再一次镌刻在集团发展的里程碑上。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;text-wrap: nowrap; font-size: 18px;&quot;&gt;旺春必胜，豫工必胜！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(473, 2, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;随着城市内涝治理的紧迫性增加以及厂矿企业安全作业要求的提高，清淤机器人正从“新奇玩具”转变为市政管网与工业沉淀池清理的标配装备。然而，对于大多数潜在用户来说，最直接的一个问题往往是：清淤机器人多少钱一台？&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773472718c19a8b.jpg&quot; title=&quot;调试现场9&quot; alt=&quot;调试现场9&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;事实上，这个看似简单的问题并没有一个统一的答案。通过对2026年一季度市场招标数据及行业报告的梳理可以发现，清淤机器人的价格跨度极大，从几万元到上百万元不等，其背后的价值逻辑值得每一位采购者深究。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;价格三级跳：从入门级到定制化&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;根据当前市场公开的采购案例，清淤机器人的价格主要可分为三个梯队。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; color: rgb(255, 0, 0);&quot;&gt;入门级设备的价格通常在5万至15万元人民币之间&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;。这类产品多为功能相对单一的 Crawler 机器人，主要适用于小区管道或小型工厂的日常巡检及轻度淤积推扫。它们能替代人工下井探查，提升基础作业的安全性，但智能化程度相对较低。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; color: rgb(255, 0, 0);&quot;&gt;专业级设备是目前市场需求的主流，价格集中在15万至40万元&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;。这一区间的机器人具备较强的动力系统和完善的导航传感功能，能够应对市政排水管网、中型河道局部清淤等复杂工况。例如，在2026年初的一项政府采购中，广州排水公司采购8套吸污辅助爬行机器人的总限价为142.88万元，折合单价约为17.86万元/套，这为专业级市政应用提供了真实的价格。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px; color: rgb(255, 0, 0);&quot;&gt;高端定制级设备的价格则在40万元以上，甚至可达数百万元&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;。这类设备通常需要应对特殊恶劣环境，如高浓度工业沉淀、易燃易爆场所或水下极限作业。例如，广州市城市排水有限公司在2026年3月发布的一则采购公告显示，研制适用于泵站清淤作业的“水下智能清淤机器人3.0版成套设备”项目，最高限价设定为95.25万元。而在工业领域，如化工企业采购的分体式清淤机器人，由于需具备耐腐蚀等特种性能，其单台价格也往往不菲。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;价格差异的核心：技术构成与综合价值&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;为什么同样是机器人，价格差距如此之大？其成本主要源于硬件材质、核心传感器以及软件平台的差异。采用316L不锈钢等高防腐材质的工业级设备，自然比普通材质的设备成本更高。此外，集成了声呐、激光雷达和惯性导航单元的高端型号，能实现三维建模与自动避障，其技术复杂度远超仅配备基础摄像头的入门机型。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773472889393fd4.jpg&quot; title=&quot;清淤机器人装配现场(55)&quot; alt=&quot;清淤机器人装配现场(55)&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;算好“总账”：价格之外的价值投资&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;对于采购方而言，看待价格不能只看采购成本，更应关注全生命周期的投资回报。一台价值20余万元的专业级机器人，其单日作业效率往往是人工团队的3至5倍，且避免了人员下井的中毒、坍塌等致命安全风险。通过精准清淤和采集管道数据，管理者能实现从“事后维修”向“预测性维护”的转变，这种无形的数据资产价值有时甚至超越了设备本身。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;综上所述，2026年的清淤机器人市场正呈现出功能细分与价值回归的趋势。采购者在问“&lt;span style=&quot;font-size: 18px;&quot;&gt;清淤机器人&lt;/span&gt;多少钱一台”的同时，更需要厘清自身作业场景的核心需求，在价格与性能之间找到最佳的平衡点。随着行业竞争加剧和技术成熟，清淤机器人正以更透明的价值和更高效的作业模式，重塑着清淤行业的未来。&lt;/span&gt;&lt;/p&gt;');
INSERT INTO `dr_1_xinwenzhongxin_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(476, 2, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;a href=&quot;https://www.zzyugong.cn/show-146.html&quot; target=&quot;_blank&quot; title=&quot;圆盘过滤机&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;圆盘过滤机&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;的处理量没有固定数值，通常按每平方米过滤面积每小时处理0.6-0.85吨干物料估算。以一台过滤面积60平方米的设备为例，每小时可处理36-51吨干料。但具体数值需根据物料特性、矿浆浓度、粒度分布等因素综合确定。选型号的核心逻辑是：先算日处理总量，再除单位面积处理能力，反推出所需过滤面积。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-weight: 600; background-color: rgb(255, 255, 255); color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/202603/b10bcfccecbd0b5.png&quot; title=&quot;KRP1AASAXKQE2~68AN97RZJ&quot; alt=&quot;KRP1AASAXKQE2~68AN97RZJ&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在矿山选矿、化工生产、环保污泥处理等领域，圆盘过滤机因其连续作业、自动化程度高、占地面积小等优势，成为固液分离环节的主力设备。但很多用户在采购时首先面临的问题就是：到底该选多大处理量的设备？型号怎么定？今天我们就来系统解析这两个关键问题。&lt;/span&gt;&lt;/p&gt;&lt;h2 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;一、圆盘处理量到底怎么算？&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/h2&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;圆盘过滤机的处理量通常以“单位面积处理能力”为基准进行估算。根据行业通用经验，对于金属矿物（如铁精矿、铜精矿），每平方米过滤面积每小时可处理0.6-0.85吨干物料；对于煤泥或轻质物料，处理能力约为0.3-0.5吨/小时·平方米。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;举例说明&lt;/span&gt;：&lt;br/&gt;假设某选矿厂日处理铁精矿干量需求为1000吨，设备计划每天运行20小时，则每小时需处理50吨。按0.7吨/小时·平方米的中值计算，所需过滤面积为：50 ÷ 0.7 ≈ 71.4平方米。因此，可选择过滤面积70-80平方米的圆盘过滤机。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;需要注意的是，这个估算公式适用于&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;矿浆浓度在35%-65%、粒度在-200目占60%以上&lt;/span&gt;的常规工况。若物料粒度更细、粘度更高或浓度偏低，处理能力会相应下降，选型时需预留余量或选择更大规格设备。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/17748577268ad5e9.png&quot; title=&quot;2a9b8f05-09d1-42a2-a05e-cc209fa32c10.png&quot; alt=&quot;2a9b8f05-09d1-42a2-a05e-cc209fa32c10.png&quot;/&gt;&lt;/p&gt;&lt;h2 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;二、影响处理量的关键因素&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/h2&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在实际应用中，以下三个因素对处理量影响最为显著：&lt;/span&gt;&lt;/p&gt;&lt;h3 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;1. 物料特性&lt;/span&gt;&lt;/h3&gt;&lt;ul style=&quot;margin-top: 16px; margin-bottom: 16px; padding-left: 18px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot; class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;粒度分布&lt;/span&gt;：物料越细，过滤阻力越大，处理量越低。例如-400目占80%的铁精矿，其单位面积处理量可能降至0.4-0.5吨/小时·平方米&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;矿浆浓度&lt;/span&gt;：浓度过低（＜35%）时，单位时间内固体量少，处理量自然下降；浓度过高（＞65%）则流动性差，影响过滤效率&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;粘度与温度&lt;/span&gt;：高粘度物料（如化工中间体）或低温环境会显著降低过滤速度&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;h3 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2. 工艺条件&lt;/span&gt;&lt;/h3&gt;&lt;ul style=&quot;margin-top: 16px; margin-bottom: 16px; padding-left: 18px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot; class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;真空度&lt;/span&gt;：圆盘过滤机依靠真空抽吸实现固液分离，真空度通常保持在0.04-0.07MPa。真空度越高，处理量越大，但需匹配设备密封性能&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;滤布选型&lt;/span&gt;：滤布孔径、材质直接影响过滤速度。选择不当会导致堵塞严重、处理量骤降&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;h3 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;3. 设备状态&lt;/span&gt;&lt;/h3&gt;&lt;ul style=&quot;margin-top: 16px; margin-bottom: 16px; padding-left: 18px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot; class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;滤布清洁度&lt;/span&gt;：堵塞的滤布会使处理量下降30%-50%&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;设备维护情况&lt;/span&gt;：分配头磨损、真空管路泄漏等都会降低有效真空度，影响处理量&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/177485765248a2d6.png&quot; title=&quot;ZZH2ZCI@8DD%BZB5WDY`(W.png&quot; alt=&quot;ZZH2ZCI@8DD%BZB5WDY`(W.png&quot;/&gt;&lt;/p&gt;&lt;h2 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;三、选型号的“三步法”&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/h2&gt;&lt;h3 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;第一步：明确需求参数&lt;/span&gt;&lt;/h3&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;列出以下数据：&lt;/span&gt;&lt;/p&gt;&lt;ul style=&quot;margin-top: 16px; margin-bottom: 16px; padding-left: 18px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot; class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;日处理干料总量（吨/天）&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;计划运行时间（小时/天）&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;物料浓度、粒度、温度、粘度等特性&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;目标滤饼含水率（通常要求15%-20%）&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;h3 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;第二步：估算所需过滤面积&lt;/span&gt;&lt;/h3&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;计算公式：&lt;br/&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;所需面积 = 小时处理量 ÷ 单位面积处理能力&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;其中单位面积处理能力需结合物料特性选取经验值，建议向设备厂家提供物料样本进行实验室小试，获取更精准数据。&lt;/span&gt;&lt;/p&gt;&lt;h3 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;第三步：确定具体型号&lt;/span&gt;&lt;/h3&gt;&lt;p style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;根据计算出的面积，在厂家产品系列中选择接近且略有余量的型号。常见圆盘过滤机过滤面积覆盖10-120平方米，直径2-4米，圆盘数量4-16盘不等。选型时还需考虑：&lt;/span&gt;&lt;/p&gt;&lt;ul style=&quot;margin-top: 16px; margin-bottom: 16px; padding-left: 18px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot; class=&quot; list-paddingleft-2&quot;&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;安装空间&lt;/span&gt;：设备直径和长度是否符合厂房条件&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;自动化配置&lt;/span&gt;：是否配备自动排渣、故障报警等功能&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;备件通用性&lt;/span&gt;：滤布、扇形板等易损件是否标准化，便于后期更换&lt;/span&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ul&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1774857767fbeb75.png&quot; title=&quot;R@P`88$F%1JGLXN]VK(S2.png&quot; alt=&quot;R@P`88$F%1JGLXN]VK(S2.png&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); margin-bottom: 0px !important; line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;span style=&quot;font-size: 18px; font-weight: 600;&quot;&gt;总结&lt;/span&gt;：圆盘过滤机的处理量取决于物料特性、工艺条件和设备状态，选型的核心是“先算量、后定面积、再选型号”。对于新建项目，建议提前与厂家沟通，提供物料样本进行过滤试验，获取真实处理能力数据，避免因选型偏差导致产能瓶颈或投资浪费。科学选型，才能让圆盘过滤机真正成为生产线的“效率引擎”。&lt;/span&gt;&lt;/p&gt;'),
(477, 2, 10, '&lt;h2 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;传统清淤的困境&lt;/span&gt;&lt;/strong&gt;&lt;/h2&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;河道淤泥堆积是困扰城市水环境治理的长期难题。传统人工清淤方式存在诸多难以回避的弊端：作业人员需要潜入浑浊水底，面临溺水、缺氧、水下生物攻击等多重安全风险；潜水员作业深度通常被限制在20米以内，难以应对更深水域的清淤需求；效率方面，一名熟练工人每天最多清理几十立方米淤泥，面对大面积水域时力不从心。更值得关注的是，人工清淤过程中搅动的淤泥会造成水体二次污染，影响周边生态环境。这些现实困境倒逼行业寻求更安全、高效的解决方案。&lt;/p&gt;&lt;h2 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;机器人技术的核心突破&lt;/span&gt;&lt;/strong&gt;&lt;/h2&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;清淤机器人的出现，从根源上改变了传统治理模式。这类设备通常采用模块化设计，集成高精度声呐探测系统、智能机械臂和多级过滤装置，实现从探测到清理的全流程自动化作业。全电动动力系统搭配大容量电池，可持续工作8-12小时，作业深度可达50-100米，远超人工极限。清淤效率更是传统方式的10倍以上，单台设备日均作业量可达500立方米。&lt;/p&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;智能控制系统是技术核心。通过水下定位与AI算法，机器人可自主规划最优清淤路径，实时避开障碍物，并精准识别不同区域的淤积程度，实现差异化清理。操作人员只需在岸上监控数据，无需冒险下水，从根本上杜绝了安全事故。&lt;/p&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202603/1773472718c19a8b.jpg&quot; title=&quot;调试现场9.jpg&quot; alt=&quot;调试现场9.jpg&quot;/&gt;&lt;/p&gt;&lt;h2 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;实际应用成效&lt;/span&gt;&lt;/strong&gt;&lt;/h2&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;在某河道治理工程中，传统人工清淤预计需三个月完成的3公里淤积河段，机器人团队仅用两周即完成任务。在湖泊蓝藻治理项目中，机器人能够在蓝藻层下精准清理底泥，避免“一刀切”式作业对生态的破坏，环保监测数据显示作业区域水质指标明显优于人工清淤区域。&lt;/p&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;经济效益同样可观。综合考虑人力成本节约、工期缩短和后续处理费用降低，机器人方案总体成本比传统方式低30%以上，投资回报周期通常不足两年。&lt;/p&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/202603/8829ca90704a7fa.jpg&quot; title=&quot;清淤机器人装配现场(25)&quot; alt=&quot;清淤机器人装配现场(25)&quot;/&gt;&lt;/p&gt;&lt;h2 style=&quot;font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; margin: 32px 0px 16px; color: rgb(15, 17, 21); text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 24px;&quot;&gt;行业变革与展望&lt;/span&gt;&lt;/strong&gt;&lt;/h2&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; margin-bottom: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255);&quot;&gt;清淤机器人的规模化应用正在引发行业深刻变革。越来越多治理工程开始采用机器人方案，倒逼传统清淤企业转型升级。政策层面也在积极跟进，多个省市已出台文件鼓励智能清淤设备应用。&lt;/p&gt;&lt;p class=&quot;ds-markdown-paragraph&quot; style=&quot;margin-top: 16px; color: rgb(15, 17, 21); font-family: quote-cjk-patch, Inter, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Segoe UI&amp;quot;, Roboto, Oxygen, Ubuntu, Cantarell, &amp;quot;Open Sans&amp;quot;, &amp;quot;Helvetica Neue&amp;quot;, sans-serif; font-size: 16px; text-wrap: wrap; background-color: rgb(255, 255, 255); margin-bottom: 0px !important;&quot;&gt;随着5G通信、量子传感等前沿技术的集成，未来清淤机器人将实现更精准的作业控制，“机器人集群”作业模式也将为超大型清淤项目提供更优解决方案。这场由技术创新驱动的水下清淤革命，正在重新定义河道治理的边界与可能。&lt;/p&gt;'),
(479, 2, 10, '&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/177563588852902a.jpg&quot; title=&quot;清淤机器人装配现场(55)&quot; alt=&quot;清淤机器人装配现场(55)&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;基于参数表，各型号核心差异集中在清淤宽度、动力配置、处理能力三个维度，适用场景也随配置不同有所区分，具体如下：&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;一、核心区别&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;500 电动型清淤机器人&amp;nbsp; 清淤宽度 500mm（最窄）；主电机功率 22kw；水泵口径 3 寸、最大流量 100 立方；适配颗粒度 15mm&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;600 电动型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&amp;nbsp;&lt;/span&gt; 清淤宽度 600mm；主电机功率 22kw；水泵口径 3 寸、最大流量 100 立方；适配颗粒度 15mm；仅清淤宽度优于 500 型&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;700 电动型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&amp;nbsp;&lt;/span&gt; 清淤宽度 700mm；主电机功率 30kw；水泵口径 4 寸、最大流量 200 立方；适配颗粒度 38mm；动力与输送能力升级&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;800 电动型 清淤宽度 800mm；主电机功率 30kw；水泵口径 4 寸、最大流量 200 立方；适配颗粒度 38mm；尺寸略大于 700 型&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;900 电动型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&amp;nbsp;&lt;/span&gt; 清淤宽度 900mm；主电机功率 30kw；水泵口径 4 寸、最大流量 200 立方；适配颗粒度 38mm；清淤效率进一步提升&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1200 电动型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&amp;nbsp;&lt;/span&gt; 清淤宽度 1200mm（最宽）；主电机功率 37kw（最大）；水泵口径 4 寸、最大流量 200 立方；适配颗粒度 60mm；整体性能顶配&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/177563587548b946.jpg&quot; title=&quot;清淤机器人装配现场(15)&quot; alt=&quot;清淤机器人装配现场(15)&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;二、适用场景&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1.&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;500/600 电动型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&lt;/span&gt;适配小型窄空间工况，比如：农村小型农用沟渠、小区 / 园区内部狭窄排污管道、小型市政支管涵，以及淤泥中仅含细小杂物（≤15mm 颗粒）的场景。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;2.&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;700/800/900&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&lt;/span&gt;电动型适配中等规模工况，比如：城市次干道排污沟渠、中型市政管道、厂区 / 园区主干道排水渠，可处理 38mm 以内颗粒的淤泥，适配多数常规市政、厂区清淤需求。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/202604/e010a05445fd8f7.jpg&quot; title=&quot;下井&quot; alt=&quot;下井&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;3.&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;1200 电动型&lt;span style=&quot;font-size: 16px; text-wrap: wrap;&quot;&gt;清淤机器人&lt;/span&gt;适配大型宽工况、大杂物场景，比如：城市主干道大型排污渠、河道支流宽水域、大型工业园区主干排水渠，可应对 60mm 大颗粒杂物，且清淤范围、输送能力更强。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;关键共性&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;所有型号均为无线遥控操作、标配 50 米管路、水下 LED 照明，核心区别仅在于清淤范围、动力强度、杂物处理能力，可根据实际工况的宽度、淤泥颗粒大小、输送需求精准匹配型号。&lt;/span&gt;&lt;/p&gt;'),
(480, 2, 10, '&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械作为&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;清淤机器人&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;行业标杆企业，是专业研发、生产、销售&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;智能清淤机器人&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;的&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;源头工厂&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;，坚持&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;厂家直供&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;模式，凭借强大生产实力、齐全企业资质、海量客户使用案例，成为市政、水利、化工、矿山等领域首选的&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;清淤机器人生产厂家&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/202603/8829ca90704a7fa.jpg&quot; title=&quot;清淤机器人装配现场(25)&quot; alt=&quot;清淤机器人装配现场(25)&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;作为深耕工程机械领域的实力企业，豫工机械拥有现代化&lt;strong&gt;清淤机器人&lt;/strong&gt;生产基地，具备规模化、标准化生产能力，核心部件自主研发制造，配备先进生产设备与严苛品控体系，确保每一台&lt;strong&gt;市政清淤机器人&lt;/strong&gt;、&lt;strong&gt;河道清淤机器人&lt;/strong&gt;、&lt;strong&gt;管网清淤机器人&lt;/strong&gt;品质稳定、性能可靠。公司拥有专业研发团队，持续技术创新，拥有多项专利技术，可提供&lt;strong&gt;清淤机器人定制&lt;/strong&gt;服务，满足不同工况定制需求。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/17756371908c3513.jpg&quot; title=&quot;清淤机器人装配现场(7)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/177563719096224c.jpg&quot; title=&quot;清淤机器人装配现场(15)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在企业资质方面，豫工机械通过 ISO9001 国际质量管理体系认证、国家 AAA 级诚信企业认证，荣获高新技术企业称号，&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;清淤机器人&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;产品具备正规检测报告、防爆认证等齐全资质，完全符合招投标要求，是客户信赖的&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;清淤设备厂家&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/17756372276c2d43.jpg&quot; title=&quot;05325Q30292R0S- A0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;凭借过硬产品实力，豫工机械&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;清淤机器人&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户使用案例遍布全国，广泛应用于&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;市政管网清淤&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;、河道疏浚、沉淀池清淤、化工池清淤、矿井水仓清淤、箱涵清淤、暗涵清淤等全场景。无论是小型&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;水下清淤机器人&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;适配窄管作业，还是大型&lt;/span&gt;&lt;strong style=&quot;font-size: 18px;&quot;&gt;清淤机器人&lt;/strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;应对宽河道、大颗粒淤泥工况，均有大量成功案例，累计服务上千个清淤工程项目，收获客户一致好评。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/1775637290d3c1ea.jpg&quot; title=&quot;下井 (2)&quot; alt=&quot;下井 (2)&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/17756373235997a1.jpg&quot; title=&quot;下水 (2)&quot; alt=&quot;下水 (2)&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/1775637368476234.jpg&quot; title=&quot;下水试机 (4)&quot; alt=&quot;下水试机 (4)&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/17756376212de61b.jpg&quot; title=&quot;调试现场7&quot; alt=&quot;调试现场7&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;选择豫工机械，就是选择&lt;strong&gt;源头工厂&lt;/strong&gt;直供保障，无中间商差价，性价比更高；现货充足、交付快捷，全国售后网点全覆盖，提供终身维护服务。作为&lt;strong&gt;清淤机器人行业标杆&lt;/strong&gt;，豫工机械始终以高品质产品、完善服务，为客户提供安全高效的清淤解决方案，成为清淤工程首选合作伙伴。&lt;/span&gt;&lt;/p&gt;'),
(481, 2, 9, '&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;近日，豫工机械凭借规范的生产管理、严格的品质控制、完善的服务体系，&lt;strong&gt;正式通过 ISO9001:2015 质量管理体系认证与 AAA 信用体系认证&lt;/strong&gt;，标志着企业在质量管理、生产标准、品牌信誉、市场竞争力等方面再上新台阶，为清淤机器人研发、生产、销售与服务全流程提供更权威、更可靠的保障。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/1775638584b3fd6b.jpg&quot; title=&quot;557c73bd99a1b9523bd0f1782505188&quot; alt=&quot;557c73bd99a1b9523bd0f1782505188&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;ISO9001:2015 是国际公认的质量管理体系标准，代表企业在研发设计、物料采购、生产加工、成品检验、售后服务等全链条实现标准化、规范化运行。此次通过认证，意味着豫工机械从源头配件到成品出厂，每一台清淤机器人均遵循严格质量管控，产品稳定性、安全性、耐用性达到行业更高水准，让客户买得放心、用得安心。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/177563860142f48f.jpg&quot; title=&quot;05325E30185R0S- A0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/177563860197310e.jpg&quot; title=&quot;05325Q30292R0S- A0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/177563860183e12e.jpg&quot; title=&quot;05325S30168R0S- A0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;AAA 信用体系认证，则是对企业诚信经营、履约能力、品牌口碑、综合实力的高度认可。作为清淤机器人源头工厂，豫工机械始终坚持诚信为本、品质为先，多年来凭借稳定供货、透明价格、专业售后赢得全国客户信赖。获评 AAA 信用企业，进一步提升了品牌公信力，也为客户合作、项目投标、长期合作提供更强信用背书。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/17756398515740b9.jpg&quot; title=&quot;河南豫工机械制造有限公司_AAA级诚信供应商单位&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/1775639851b1cc86.jpg&quot; title=&quot;河南豫工机械制造有限公司_AAA级诚信经营示范单位&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/177563985132a08e.jpg&quot; title=&quot;河南豫工机械制造有限公司_AAA级立信单位&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202604/1775639851741f87.jpg&quot; title=&quot;河南豫工机械制造有限公司_AAA级企业信用等级&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 15px;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;两大权威认证加持，是认可更是责任。未来，豫工机械将持续以 ISO9001:2015 标准严格管理生产、提升品质，以 AAA 信用体系规范经营、服务客户，不断优化清淤机器人产品性能，为市政、河道、管网、化工、矿山等清淤工程提供更安全、更高效、更可靠的智能清淤设备，做客户值得信赖的清淤机器人实力厂家。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;'),
(486, 2, 9, '&lt;p&gt;初夏明媚，美好恰逢其时！6月17日-18日，郑州总部营销中心，豫工集团二十一周年庆典暨618女神节在集团四个事业部 接棒举行，600多人参与此次活动。&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202607/1782966104b3e9fe.jpg&quot; title=&quot;富来&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202607/1782966104bbff37.jpg&quot; title=&quot;国际事业部&quot;/&gt;&lt;/p&gt;&lt;p&gt;6月17日下午，在豫工集团-豫工机械国内事业部活动第二场 燃情启动，一场热情与温情交织的盛会，正式拉开帷幕。笑语声声，芳华灼灼。一曲《桃花朵朵开》，开启今日的盛典表彰，刚刚过去的旺春大战，全员冲锋，逆势突围，豫工英雄桂冠加冕，成功登顶业绩之巅。&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202607/1782966149f1d93a.jpg&quot; title=&quot;886a1a7ac3a1ec5c89d9944d210d15cf_720&quot; alt=&quot;886a1a7ac3a1ec5c89d9944d210d15cf_720&quot;/&gt;&lt;/p&gt;&lt;p&gt;旺春达人当仁不让，进步标兵奋勇争先，他们的成功再次证明，在豫工，成功没有预定，时间自会证明。&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202607/178296616929bea2.jpg&quot; title=&quot;7df23339b08b21535caea100b9dd8612&quot; alt=&quot;7df23339b08b21535caea100b9dd8612&quot;/&gt;&lt;/p&gt;&lt;p&gt;2025年度优秀表彰，星光闪耀，勇者为先，百万英雄勇创佳绩，优秀团队收获满满，榜样在前，力量无限，每一份亮眼的业绩，每一项沉甸甸的奖项，都是豫工人攻坚克难的底气。&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202607/17829661853088d3.jpg&quot; title=&quot;2c8bc4e96269deeae6ff1f241e67f65e_720&quot; alt=&quot;2c8bc4e96269deeae6ff1f241e67f65e_720&quot;/&gt;&lt;/p&gt;&lt;p&gt;年度股东分红，共享发展红利，不负朝夕耕耘，股东分红燃爆全场，真真切切的回报，印证豫工与家人共赢发展的初心，携手相伴，同心者，行致远。&lt;/p&gt;&lt;p&gt;董事长殷殷寄语，催人奋进，寄望全体家人，立足当下，主动迭代，提质增效、聚力攻坚，深耕业务，筑牢发展根基。&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202607/17829662011a9d5c.jpg&quot; title=&quot;7d768d64b1c7fc58f6a10a38390420a9_720&quot; alt=&quot;7d768d64b1c7fc58f6a10a38390420a9_720&quot;/&gt;&lt;/p&gt;&lt;p&gt;2026盛夏大战启动会&lt;/p&gt;&lt;p&gt;整装再出发 逆势赢盛夏，2026 盛夏大战正式启动，十支战队依次登台，定目标、抓过程、盯结果，敢想敢干，敢打敢拼，步步为营，超越自己。&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202607/17829662208ad91b.jpg&quot; title=&quot;2eb9670e2da6e2a50b16b825bae5b460_720&quot; alt=&quot;2eb9670e2da6e2a50b16b825bae5b460_720&quot;/&gt;&lt;/p&gt;&lt;p&gt;全员自信坚定，蓄势待发，誓要在盛夏冲锋中转变思维、创新方法，勤总结，多复盘，深挖掘，简单的工作重复做，重复的事情坚持做，用能力武装自己，用业绩证明自己。&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.zzyugong.cn/uploadfile/ueditor/image/202607/1782966263a96427.jpg&quot; title=&quot;352ec623-fb65-44dc-9d4b-99cb733fe3fd&quot; alt=&quot;352ec623-fb65-44dc-9d4b-99cb733fe3fd&quot;/&gt;&lt;/p&gt;&lt;p&gt;二十一年速发展，盛夏再出发，机遇与挑战并存，让我们整装出发、逆势增长，用实干书写答卷，用奋斗燃火盛夏，&lt;/p&gt;&lt;p&gt;加油，冲 冲 冲 ！&lt;/p&gt;');
