(1, '郑州豫工机械官网zzyugong.cn', 'www.zzyugong.cn', '{\"config\":{\"logo\":\"\",\"SITE_NAME\":\"郑州豫工机械官网zzyugong.cn\",\"SITE_ICP\":\"豫ICP备2023028284号\",\"SITE_TONGJI\":\"\",\"hdtp\":{\"2\":{\"1\":\"180\",\"2\":\"2024龙年大吉新春banner\",\"3\":\"#\"},\"3\":{\"1\":\"181\",\"2\":\"软管泵出口十强\",\"3\":\"#\"},\"4\":{\"1\":\"182\",\"2\":\"防汛应急设备\",\"3\":\"#\"},\"5\":{\"1\":\"183\",\"2\":\"液压劈裂机\",\"3\":\"#\"}},\"SITE_CLOSE\":\"0\",\"SITE_INDEX_HTML\":1,\"SITE_CLOSE_MSG\":\"网站升级中....\",\"SITE_LANGUAGE\":\"zh-cn\",\"SITE_TEMPLATE\":\"zhengzhoudaguanwang\",\"SITE_TIMEZONE\":\"8\",\"SITE_TIME_FORMAT\":\"\",\"SITE_THEME\":\"default\",\"SITE_DOMAIN\":\"www.zzyugong.cn\"},\"param\":{\"yqlj\":\"\",\"hdtp\":\"{\\\"2\\\":{\\\"1\\\":\\\"180\\\",\\\"2\\\":\\\"2024龙年大吉新春banner\\\",\\\"3\\\":\\\"#\\\"},\\\"3\\\":{\\\"1\\\":\\\"181\\\",\\\"2\\\":\\\"软管泵出口十强\\\",\\\"3\\\":\\\"#\\\"},\\\"4\\\":{\\\"1\\\":\\\"182\\\",\\\"2\\\":\\\"防汛应急设备\\\",\\\"3\\\":\\\"#\\\"},\\\"5\\\":{\\\"1\\\":\\\"183\\\",\\\"2\\\":\\\"液压劈裂机\\\",\\\"3\\\":\\\"#\\\"}}\"},\"seo\":{\"SITE_SEOJOIN\":\"_\",\"SITE_TITLE\":\"豫工机械_郑州豫工官网_豫工机械厂家_豫工机械设备-郑州豫工机械有限公司\",\"SITE_KEYWORDS\":\"豫工机械,豫工机械官网,郑州豫工官网,郑州豫工机械,豫工机械设备,豫工机械产品,豫工机械厂家,豫工集团,郑州豫工机械怎么样,郑州豫工机械厂家电话,郑州豫工机械厂家地址\",\"SITE_DESCRIPTION\":\"郑州豫工机械20余年致力于路面、桥梁预应力设备、防汛除雪应急设备、工程钻机设备、过滤环保设备、隧道喷浆支护设备、切割破拆设备，数控机床等研发生产，9大产品体系一站式采购。提供性能稳定的配套设备，助力国家工程建设，凭借专业的品质、合理的价格、良好的服务与口碑，得到国内外客户的一致好评！\",\"SITE_URLRULE\":\"2\",\"list_pagesize\":\"10\",\"list_mpagesize\":\"10\"},\"mobile\":{\"mode\":\"-1\",\"auto2\":\"1\",\"domain\":\"\",\"dirname\":\"\",\"auto\":\"1\",\"tohtml\":0,\"not_pad\":\"0\"}}', 0, 0);
